INSERT INTO historical_startups (year, name, logo_url, description, external_link, source_post_id) VALUES
  ('2016以前', 'Velp Velp / Velp 獸醫出任務', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/construction.png', '利用APP即時媒合平台上有執業中的獸醫師，首先進行視訊諮詢，並在有需要時前往飼主家中替毛小孩緊急處置或協助轉診。\n', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13652),
  ('2016以前', 'Freshe Run Freshe Run 空氣髮帶', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/construction.png', '為都會運動者主動提供乾淨空氣的髮帶。不須帶上厚重的口罩，用最簡單的方法，讓路邊等紅燈的汽機車或紫爆的PM2.5不再是阻止我們欣賞城市之美的夢魘。\n', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13652),
  ('2016以前', 'Blindtour 盲旅', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/construction.png', '盲旅，是一種新型態的旅行方式，讓你直到出發當天才知道要做什麼！給你說走就走的浪漫，旅行麻煩事交給旅行管家就好！', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13652),
  ('2016以前', 'Dressico', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/construction.png', 'dressico是一個分享穿搭的導購平台，收集國內外流行品牌資訊，同時提供一個讓使用者分享、交流穿搭的地方。', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13652),
  ('2016以前', 'Doughpack 學生 P2P 借貸平台', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/construction.png', '一間致力於服務學生的網路金融平台。我們透過網路科技媒合學生與學生之間的借貸。', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13652),
  ('2016以前', '學次方', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/construction.png', '透過學次方設計的學習玩具箱，我們期望能夠為孩子建立學習的自信、練習與他人的互動、找回學習知識的快樂，達到最後讓孩子能夠「自學、思辨、創造」的精神。\n', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13652),
  ('2016以前', '故事：寫給所有人的歷史', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/construction.png', '「故事|寫給所有人的歷史」（gushi.tw）是由一群喜歡故事的人成立的，目的是透過有趣的、有創意的方式，結合新媒體的運用，讓歷史走進日常生活之中，我們希望和讀者一起，帶著具有歷史縱深的眼光，重新認識這個世界。', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13652),
  ('2016以前', 'JJFlint PixelMonkey', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/construction.png', 'instagram智慧相片管理軟體，主動生成Hashtag，提升社群曝光度', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13652),
  ('2016以前', '喬睿科技 TapPay Connect 手機行動支付 SDK', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/construction.png', 'TapPay是一款提供O2O手機當面支付的交易工具，透過API界接或軟體安裝服務,提供商家、平台輕鬆串接手機收付款功能。', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13652),
  ('2016以前', '得人資源整合', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/construction.png', '創造更流動、更專精、更有彈性的勞動市場，媒合企業與工作者，引進在歐美盛行的非100%，讓專業人士有更多選項兼顧工作與生活，讓企業依其需要求得關鍵專業人才。\n', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13652),
  ('2016以前', '台灣熱像/醫院安心+', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/construction.png', '利用熱感成像與三維叠對技術，全年不中斷監控候診區，以體溫變化趨勢，彈性導入病兆量表，強化決策正確性，即時通報，採取措施，有效降低候診密閉空間中，飛沫傳染的機率，協助醫院提供安全環境', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13652),
  ('2016以前', 'PicMemory 拾時', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/construction.png', '提供一個讓照片與聲音能夠與家人、長輩互動分享的服務，並且保存珍藏著這些記憶片段。期待長輩能夠透過 PicMemory 與家人述說自己的生命故事，同時也凝聚家庭間的情感。', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13652),
  ('2016以前', 'Wattle', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/construction.png', '致力於開發模組化水壺，讓水壺有全新的使用方式。同時，創造水壺的樂趣價值。', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13652),
  ('2016以前', 'WAKEY', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/construction.png', '為一款孩子的生活陪伴物，協助3-6歲兒童逐步學習獨立，完成從起床到出門的一連串日常生活任務，成為孩子的小夥伴，也是父母的小幫手。\n', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13652),
  ('2016以前', '蝠氣球', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/construction.png', '透過1.世界冠軍品牌2.延命氣球膠囊3.AR教學技術4.標準化製成，加以實現微型創業與運用氣球分享歡樂的目標。', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13652),
  ('2017', '麒趣科技 KitchBot', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/construction.png', 'KitchBot 團隊以科技結合科學烹飪，推廣人工智能烹飪美學為目標，「Vulcan」智慧溫控插座為智能廚具的敲門磚，「Vulcan」備有專屬APP，精選60道食譜行程，能準確地控制食材的最佳烹調時間及溫度，並可建立私人的做菜行程，用科學的方法封存感動的料理滋味，找回只屬於您的味覺記憶。', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13647),
  ('2017', 'Skinny Player Group', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/construction.png', 'SkinnyPlayer是一款無線、輕量的音樂裝置，無需使用耳機線，不論是戶外慢跑、騎單車、作瑜珈皆可以貼身使用，帶來全新音樂體驗。', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13647),
  ('2017', 'PicSee', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/construction.png', '重新定義超連結的可能性，自訂分享連結縮圖標題、統計分析、再行銷追蹤。所產生之連結上線1年半共被點擊超過10億次，有30%來自台灣，70%來自全世界。里約奧運、相信音樂、周杰倫、聯合報、中國信託等官方粉絲頁都是知名使用者；台灣YouTuber訂閱者排名前10中，有7位是固定使用者，包括蔡阿嘎、這群人等。', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13647),
  ('2017', 'Deep Force', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/construction.png', 'Deep Force 的產品主要為人工智慧演算法的軟體開發，因此神經網絡的架設與演算法的訓練為公司的核心技術。\n終端裝置在技術的進步與革新下，已逐漸可勝任影像處理與分析的運算，因此Deep Force抓緊趨勢結合終端裝置與深度學習，使日常生活的裝置能更即時與隱私地處理如影像辨識的任務。\n', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13647),
  ('2017', 'BotBonnie', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/construction.png', '是專注於對話式智能機器人解決方案的新創團隊，協助企業在匯聚數億名高黏著度用戶的通訊軟體上，輕鬆運用聊天機器人提供服務接觸點。倚藉智能客服提升效率，活化社群粉絲創造營收，打造完美的顧客體驗。', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13647),
  ('2017', 'OysterX', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/construction.png', 'OysterX 是你的探險旅行紀錄工具App。探索世界並解開地圖上的迷霧，並自動記錄你的旅遊足跡！', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13647),
  ('2017', 'StoryStudio', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/construction.png', '「故事|寫給所有人的歷史」（gushi.tw）是由一群喜歡故事的人成立的，目的是透過有趣的、有創意的方式，結合新媒體的運用，讓歷史走進日常生活之中，我們希望和讀者一起，帶著具有歷史縱深的眼光，重新認識這個世界。', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13647),
  ('2017', '芮宜健康', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/construction.png', '團隊成員由陽明、臺大、成大、高醫四大醫學院校友組成，聯手利用「大腦健身房」提供線下服務，讓擔心罹患失智症者、熟齡族群、自覺記憶退化者、失智症高風險族群，能夠透過有效訓練，增進大腦健康、預防或延緩失智症，讓人擁有良好認知功能，能夠保有健康與尊嚴、享受獨立自主且豐富的人生下半場！', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13647),
  ('2017', '湛', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/construction.png', '我們正在開發一套放置在港灣用來收集海漂物的機器及一個海洋廢棄物觀測平台，這個平台不侷限只有海漂物，同時還包含有海灘及水下環境揭露(http://www.oceanai.tw/Test/viewmap.html)。湛的目標不僅是要透過機器有效的收集港灣中無人處理的海漂物，更要減少垃圾回流大海造成海洋生態二次傷害的危機；我們將對收到的海漂物進行組成分分析，公開在平台資訊系統，讓海洋環境的議題，更與社會文化緊密結合，讓海洋生態能免於廢棄物的危害，永續海洋環境。\n', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13647),
  ('2017', 'GoodPlant 綠植生活', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/construction.png', '室內植栽的領導品牌，藉由服務創新提供「訂閱制的情境植栽組合」，與產品創新「個人化植栽與智慧盆栽」，把植栽樂高化藉由民眾自己組裝，滿足個人的需求，同時使用水耕植栽技術，省去換土麻煩，並藉由智慧盆栽提供之資訊，掌握環境溫、濕、亮度，幫助都市人解決照護與選購的困擾，藉由搜集之資訊做出下一波的選購指南。', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13647),
  ('2017', '65資訊網', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/construction.png', '銀髮族專屬的福利資訊網站。透過個人化的條件，「福利、健康知識和服務據點」資源的媒合。本站之任務為「整合銀髮族相關資源，並把雜亂多元的訊息結構化，變成對每個人有用的知識」。', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13647),
  ('2017', '遠山呼喚', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/construction.png', '遠山呼喚成立於2015年，透過整合尼泊爾震央的「學習生態系統」建置經驗，我們帶領青年參與符合趨勢與需求的國際援助訓練模式。遠山呼喚致力於改善台灣青年與國際援助的落差，帶領參與者跳脫體驗式的短期服務，以專業、長期、契合需求為堅持，重新將Made in Taiwan的國際援助，打造成為國際知名品牌。', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13647),
  ('2017', 'CrossMelon', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/construction.png', '結合日本工藝、荷蘭自動化栽培科技、台灣創新，利用水耕栽培提供安全無毒、周年生產的高品質網紋洋香瓜。希望將農業企業化，吸引與培養農業人才。', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13647),
  ('2017', '寶島淨鄉團', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/construction.png', '透過環保服務、環境教育、環保商品，以「後端清理(淨灘)」及「源頭減量(教育)」著手，解決海洋污染議題。\n寶島淨鄉團在非營利組織領域已累積一定成果，未來將開發商業模式(2B)，以社會企業的方式多角化推廣環境議題。', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13647),
  ('2017', '益控通', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/construction.png', '以「自動化媒合平台」，讓製造業自動化外包資訊更透明，客戶(機械廠)與SI(系統外包商)能在最短的時間內找到合作的對象。產業顧問提供傳產客戶建議，協助其提升為自動化製造業。\n', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13647),
  ('2017', 'vrvaOrigin', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/construction.png', 'accOculus 基於眼科醫療規格開發，整合硬體(光學變焦模組)、軟體(生物資訊)，提升消費性 AR/VR 產品舒適性/安全性，解決視覺暈眩與傷害等問題。', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13647),
  ('2017', '福爾摩沙 樹芸事務所', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/construction.png', '植物健康管理 (Plant Health Management,PHM) 概念為運用多樣化的防治手段，將有害生物族群密度降至可接受之經濟危害水準之下。因此，植物健康管理的概念極具市場潛力，並可提升我國之農業整體水準，向上可以提升農民之收益，向下可以改善食品安全之現況。\n', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13647),
  ('2017', 'UVNICE 優必耐', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/construction.png', '以紫外光殺菌專利技術打造無菌生活產品，解決人們因為生活中環境衛生不足而引發的疾病問題。目前產品為「滅菌洗衣球」。', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13647),
  ('2017', '微思', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/construction.png', '微思主要研發的產品是一系列的「感官智能珠寶」，透過感官探索,利用嗅覺、觸覺、聽覺、溫覺感知來重現在親密關係中女性最重視的「前戲」氛圍，並以感測器搜集生理資訊，隨身體興奮程度來和其他模組連結、互動，藉此提升兩性之間的親密互動。\n', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13647),
  ('2017', 'College Bike', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/construction.png', '產品瞄準平價都市單車市場的缺口; 配合品牌生活美學的網路行銷; 最後，用網路行銷＋ikea自助組裝的銷售模式，提供直覺有效率的購買體驗', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13647),
  ('2017', '20snonstop 移動中的20s', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/construction.png', NULL, 'https://20snonstop.com/', 13647),
  ('2018', '憂鬱症療效預測系統 玉醫科技有限公司', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/玉醫科技有限公司_憂鬱症療效預測系統_logo-Shina-Yang.png', '台灣有200萬人受憂鬱症所苦，大大影響了工作和生活，然而每個人適合的藥物或是治療不太相同，光是要找到適合的方式就要花上半年甚至是數十年，病情在還沒有痊癒前就很有可能惡化甚至影響生命。因此玉醫研發憂鬱症療效預測系統，在診斷時就可以預測治療結果，大大降低治療的時間，讓患者可以提早恢復正常生活。\n', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13624),
  ('2018', '石灣科技有限公司 GOBOT積木小車', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/石灣科技有限公司_GOBOT積木小車_logo-Shina-Yang.png', '目前中小學生普遍反應數學難，欠缺對數學學習的興趣。GoBot 是基於在MIT波普特教授Logo機器人的基礎之上，採用實體編程積木（Tangible Programing），以及互動地圖模式(RFID Map)，將數學與編程結合，並且將學習的過程遊戲化。\n', 'http://stoneware.tech/', 13624),
  ('2018', '好好投資智能理財平台', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/好好投資科技股份有限公司-Shina-Yang.png', '好好投資運用科技，把傳統高門檻的人力財富管理服務，搬到網路上。以人工智慧「消化」複雜金融數據至一般人可輕易解讀、判斷，並協助產生「專屬」最適投資組合，線上彈指串接金融機構完成下單交易，再透過智能演算，全天候為用戶自動進行「投資後」管理服務。好好投資是聰明人隨身理財顧問，更是您的金融行車導航。', 'https://www.howinvest.com/', 13624),
  ('2018', '艾比索 EP 插圖日記', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/艾比索_艾比索-閱寫社群平台_logo-Shina-Yang.png', 'EP 美文秀秀是華文圈最美閱寫社群平台，特別吸引 15 到 35 歲的浪漫族與女生，〈插圖日記〉誘拐繪師進駐分享他們可愛的插畫作品，當你寫寫東西時，一定想找個漂亮的插圖，這才是塗鴉日記嘛！插畫師進駐可獲得 75% 的利潤還有高曝光率，〈插圖日記〉背後的技術有 AI 文本分析、圖形識別、關鍵字標籤關連引擎、圖文渲染引擎、圖片智財保護機制，感謝文化部選定本團隊全力支援，讓我們來發展台灣的插圖生態圈。', 'https://episode.cc/', 13624),
  ('2018', '沂動行銷 Soocker 搜客', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/沂動行銷_SOOCKER熟客定期購平台_logo-Shina-Yang.png', '網紅在SOOCKER搜客可以隨時把屬於自己的獎金 提領出來，無需最低金額限制以及處理時間。品牌在SOOCKER搜客可以非常容易找到合適的導 購型網紅，以最低成本獲得最大的銷售效益。', 'https://episode.cc/', 13624),
  ('2018', '良路設計 走走家具', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/良路設計_走走家具_logo-Shina-Yang.png', '走走家具是為都會族群設計的「帶著走的家」，強調美感與實用、簡易重複組裝、易搬運及環保，解決搬家時的困擾。全套九件家具符合小空間的生活需求，改善搬家問題並提升生活品質，已獲得國際設計- IF 與 Reddot雙獎肯定。', 'https://www.gogohome.tw/', 13624),
  ('2018', '食道癌近接治療置放器 貝克生醫', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/貝克生醫_食道癌近接治療置放器_logo-Shina-Yang.png', '貝克生醫開發新一代食道癌近接治療置放器，滿足精準放射治療的臨床需求，改善食道癌病患長期預後及存活率不佳的治療困境。', 'http://www.braxx.com.tw/%E8%B2%9D%E5%85%8B%E7%94%9F%E9%86%AB/', 13624),
  ('2018', '生活職人平台 居家整聊室', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/居家整聊室_生活職人平台_logo-Shina-Yang.png', '居家整聊室致力於提供大家更好的生活家居空間！ 我們相信「美好的生活選項一直都在，而且人人都可以擁有。」我們除了協助整理、局部清潔，更用心傾聽顧客的困擾，希望透過「整理」、「聊天」貼近顧客的生活，進而打造最適合的居住空間。\n', 'https://www.tidyman.tw/', 13624),
  ('2018', '智慧資產空間管家 客來喜', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/KeylessOK_LOGO.png', '我們從智慧開門技術切入，致力於提供空間使用者與周邊環境O2O商業服務整合的科技公司，幫助資產管理者實現『資產管理智慧化、資料運營視覺化』的高效協同管理服務。專注在分時管理，分區管理，人員授權，完成人、時、地三方面做智慧化管理系統，讓閒置空間的資產可以活化，給予即時且便利的運營管理與消費授權。\n', 'https://tavis888.wixsite.com/keylessok', 13624),
  ('2018', '施睿健康科技 - 智能血液透析', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/施睿股份有限公司_施睿健康科技-智能血液透析_logo-Shina-Yang.png', '施睿是一家專精以物聯網及人工智慧技術，提出完整智能健康科技解決方案的公司。其推出的智能血液透析方案，希望改善傳統醫療行為，幫助血液透析(洗腎)領域，實現醫療智能化。第㇐步是有效且大量的資料獲取，進㇐步改造並落實透析自動化系統，最終將人工智慧與專家知識結合，提供洞見及預測，達成精準醫療。\n', 'http://savy.tw/', 13624),
  ('2018', '食秘 餐飲智能採購秘書', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/食秘_食秘-餐飲智能採購秘書_logo原foodmap-02-Shina-Yang.png', '最完善的餐飲食材搜尋引擎，協助餐廳找到好食材，改善傳統電話、傳真報價及訂購的繁瑣流程，線上搜尋、採買一次到位。食材資訊透明化，就餐廳性質和需求提供食材採購建議，以集中採購的概念，協助壓低食材成本。讓中小型餐飲業者不用再每天清晨上市場買菜，讓農民有更好的銷售管道，讓外食也能是一種既安心又美味的享受。', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13624),
  ('2018', 'Travostyle 旅型', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/旅型Travostyle_旅型網站_logo-Shina-Yang.png', '旅型是一個以旅行風格為核心所設計的｢行程交流社群平台｣。平台內提供相似度分析，幫助旅人快速了解自己與他人的旅行偏好異同程度，並能因此發掘更多風格相近的行程玩法；除此之外，旅型更整合了多樣的行程工具，一站式滿足旅人規劃、記錄、分享等不同需求，讓每趟旅程的原貌得以完整的保存及呈現。', 'https://travostyle.com/', 13624),
  ('2018', '健康盟國際創新有限公司 智能衛教影音共享平台', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/健康盟國際創新有限公司_衛教影音共享平台_logo-Shina-Yang.png', '健康盟衛教影音共享平台是以「秒懂動畫」為主軸的衛教影音動畫，讓醫病關係可以透過科普角度的影片達到秒懂的效果，減少錯誤的健康迷思。透過影音媒體作為衛教傳播的管道，讓醫護人員更能即時宣導疾病，對症下藥，讓溝通更清楚秒懂。並降低教育程度與城鄉差距的落差，使得衛教溝通無障礙，更能展現衛教在醫療上的價值。\n', 'https://www.healthleaguex.com/', 13624),
  ('2018', '康立安智能醫療設備有限公司 KneeSup', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/康立安智能醫療設備有限公司_KneeSup_logo-Shina-Yang.png', '通過康立安智能穿戴設備將首次串聯起病患，手術醫生與物理治療師，形成完整的解決方案，為術後管理與復建康復的每一個環節創造價值。研發的產品包括包括四個部分：1, 智能硬件設備 2, 大數據平台 3, 病人版APP 4, 醫師版APP。', 'https://conzian.com/', 13624)
INSERT INTO historical_startups (year, name, logo_url, description, external_link, source_post_id) VALUES
  ('2018', '創新非侵入式中央靜脈血氧飽和濃度儀 Innovative and noninvasive central venous oximetry', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/康立安智能醫療設備有限公司_KneeSup_logo-Shina-Yang-1.png', '以快速且精確定量深層組織光學參數的演算法，並且藉由縝密的仿體與臨床驗證，得到⾼可信度的中央靜脈⾎氧飽和濃度。藉由近紅外線光譜技術結合擴散光學斷層掃描技術以及蒙地卡羅演算⽅法，建構正確的⾮侵⼊式中央靜脈⾎氧飽和濃度之監測解決⽅案，並以此發展⾮侵⼊性精準量測中央靜脈⾎氧飽和濃度之「重症醫材」。\n', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13624),
  ('2018', '緹蜜歐科技 Lovenuts 愛情堅果 & 創新智財開發與分析', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/提蜜歐_愛情堅果與Timeo-VR_logo-Shina-Yang.png', '緹蜜歐科技專精於：創新專利產品開發 & 開發智慧醫療 IoT 產品\n我們第一個產品""愛情堅果Lovenuts""是第一個具有手電筒偽裝功能以及藍牙解鎖的私密舒壓按摩產品，其可愛的介面與遠端遙控功能廣受歡迎。除此之外我們還開發了 AI 影像辨識結合 VR 播放平台，特殊處在於具有動作辨識功能的控制介面，以動作去遠端控制相對應的 IoT 產品。除自身產品之外，我們也協助客戶開發醫療相關偵測儀器，從專利迴避的角度去設計產品以及協助客戶專利佈局以及智財鑑價。\n', 'http://www.lovenuts.co/', 13624),
  ('2018', '黑洞科技', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/黑洞科技_雪莉單車_logo-Shina-Yang.png', '雪莉單車讓用戶省下5倍交通時間、業主提升2倍地域價值更節省10倍成本付出。除了能補足大眾運輸與生活節點的最後一哩路外，也能創造該區域的交通活化、價值提升，鬧區範圍更廣。\n雪莉直接從這些交通不便、有短程需求的區域用戶做切入，設置B2B專屬的區域單車短租服務，補足其與大眾運輸的落差及該群體的特殊移動需求', 'http://www.lovenuts.co/', 13624),
  ('2018', '賈伯利數位科技股份有限公司 Blay', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/賈伯利數位科技股份有限公司_Blay_logo-Shina-Yang.png', 'Blay 是一個機場、即時航班動態APP，是由一群熱愛旅遊，喜愛學習不同文化，和認識新朋友的年輕人所共同創辦。\n我們相信，一個完美的旅遊體驗，一定和旅途中所認識的人有莫大的關係。因此，Blay致力於打造一個方便全世界各地的旅人們互相交流的平台，讓每個旅遊行程成為充滿人和人之間的溫暖互動的美好回憶。\n', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13624),
  ('2018', '跨思科技股份有限公司', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/跨思科技股份有限公司_書窩_logo-Shina-Yang.png', '智慧生活：快速方便建立您的雲端個人圖書館，讓您有效管理、搜尋自己的藏書。共享互惠：好書借不到，老書買不到，藏書使用率低....書窩提供就近出借、轉售、贈送 … 等功能， 解決大家的問題。真實交友：透過分享，在書窩裡以書會友，a認識附近興趣相投的好友。綠色流通：幫閒置書再次流通，讓我們一起愛地球。\n', 'https://www.facebook.com/clothes.telling/', 13624),
  ('2018', 'Crescendo Lab 漸強實驗室', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/漸強實驗室-Crescendo-Lab_BotManager-_logo-Shina-Yang.png', 'BotManager is a messages analytics platform allows marketers to better track performance of adversing messages sent out through social messaging apps\n', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13624),
  ('2018', '睿濱科技', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/睿濱科技_放射治療獨立劑量驗證服務_logo-Shina-Yang.png', '醫院裡的放射治療團隊由物理師負責驗證所擬定之放射治療計畫以確保放射治療機台可以達到如同計劃預期的治療效果。然而現行物理師需與病人競爭放射治療室的使用以進行量測驗證,物理師往往只能利用下班時間或假日執行驗證計劃。 本公司致力於發展獨立劑量驗證服務以幫助物理師減少量測驗證的需求。', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13624),
  ('2018', '維諾股份有限公司', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/維諾股份有限公司_安心_logo-Shina-Yang.png', '安心+是一套結合感測設備、智能演算和雲端服務的全方位解決方案，用於民眾聚會的場所，尤其是長照中心、托兒園和醫療院所，傳統方式浪費人力資源，且用於單點體溫量測容易產生誤判，安心+運用數據科學提升判斷精準率，透過多元網絡演算邏輯，可減少40~80%的運算量，可在人群聚集空間中不間斷地掌握發燒者進而預防', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13624),
  ('2018', '髮弄資訊股份有限公司 STYLEMAP', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/髮弄資訊股份有限公司_STYLEMAP-你的時尚地圖_logo-Shina-Yang.png', 'STYLEMAP現為全台最大的美髮服務媒合平台！超過3600位設計師發表超過10萬張髮型實拍作品，幫助消費者掌握美髮流行趨勢，找到最適合的髮型和設計師！未來將致力成為台灣最大的時尚美業媒合平台-做為消費者線上尋找美業服務的重要參考管道，同時也是美業設計師經營作品口碑、拓展業務、客戶管理的有效平台。\n', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13624),
  ('2018', '謀客股份有限公司', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/謀客股份有限公司_Sligrid_logo-Shina-Yang.png', 'Aims to make all valuable thoughts more connected and reusable, Sligrid is a new way to transform information fragments into knowledge system.', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13624),
  ('2018', '轉帳幫', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/轉帳幫_P2P國際匯款代付_logo-Shina-Yang.png', '轉帳幫以結合P2P媒合的中間機制，提供民眾使用轉帳服務時能享有更優惠的手續費跟更便捷的金融服務，主要項目為：(1)國內跨行轉帳(2)P2P國際匯款代付。並開發專屬聊天機器人為數位服務平台，提供民眾線上即時的協助及快速的管理和通知。', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13624),
  ('2018', '魔幻主義有限公司', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/魔幻主義有限公司_魔法科學班_logo-Shina-Yang-scaled.jpg', '怎麼可能兼顧多元學習、成績變好、學得開心？\n「魔法科學班」利用魔術表演、音樂、聲光等感官元素結合「科學實驗」，營造不凡的學習經驗、激發孩子的學習興趣。\n', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13624),
  ('2018', 'Binflux 沛智生醫', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/Binflux-沛智生醫_Infans-生殖中心智慧管理平台_logo-Shina-Yang.png', '沛智生醫專注於使用雲端和機器學習技術，打造下一代的生殖數位醫學服務; 沛智生醫開發的Infans生殖中心智慧管理平台，可幫助生殖醫學中心解決數位化的各種複雜問題，讓繁忙的醫療人員透過直覺的操作，管理及分析複雜的療程數據、優化作業流程、擬定最佳的醫療策略，也讓身心煎熬的不孕症患者得到更好的醫療品質。\n', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13624),
  ('2018', 'Bznk', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/Bznk.com_Bznk必可票貼_logo-Shina-Yang.jpg', '"中小企業與大公司生意往來，常常會是1-6個月的應收帳款而不是馬上收現，短期且金額較小的資金缺口，不是銀行所喜歡的客群，因此中小企業資金週轉壓力會比較高，我們協助處理應收帳款的轉讓變現。\n透過p2b lending的商業模式(媒合借款人及投資人)，讓大眾投資者可以協助中小企業亦可以獲取合理報酬率。"', 'https://artzyplanet.com/', 13624),
  ('2018', 'ChaseWind', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/ChaseWind_ChaseWind-Cycling-Glasses_logo-Shina-Yang.png', 'ChaseWind智慧眼鏡為一款專為自行車騎士打造的智慧眼鏡，運用無線通訊技術並搭配擴增實境技術，以及串聯車手與自行車上所有的行動感應裝置相關資訊，不僅可記錄、提供騎士於高速移動時所需包含心跳、時速等運動資訊。再透過手機App連結後端雲端平台，提供健康管理大數據分析、自製影音上傳以及社群分享等服務。', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13624),
  ('2018', 'Commuter', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/Commuter_線上單車-IKEA_logo-Shina-Yang.png', 'Commuter 整合台灣優質的單車零件廠，把單車模組化、極簡化為 5~10 個零件，讓你輕鬆線上客製自己的單車，零件將從工廠直送到家，讓顧客像 IKEA 傢俱一樣自助組裝。售後，顧客能藉由 Bike ID 線上售後服務，自己換件、升級、維修自己的單車。', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13624),
  ('2018', '行旅科技股份有限公司 Firmso', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/Firmso-行旅科技股份有限公司_Frismo_logo-Shina-Yang.png', 'Frismo is a blockchain based service that empowers travelers to capture magical moments by providing high quality content and powerful tools.\n', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13624),
  ('2018', '數位資產仲介 FlipWeb', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/FlipWeb-數位資產仲介_數位資產仲介_logo-Shina-Yang.png', 'FlipWeb數位資產仲介為亞洲與華人世界首個公開、透明且交易最多樣化之網路數位資產交易平台，經營數位資產交易平台，透過網站、APP、Domain與粉絲專頁與帳號等網路數位資產的交易模式營利', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13624),
  ('2018', '幹得好科技股份有限公司 GJ即時上工', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/GoodJob_GoodJob找到你的好頭路-透明求職平台_logo-Shina-Yang.png', 'GJ即時上工 － 線上臨僱人力即時媒合平台\n利用行動裝置串連中小企業與臨僱人力\n藉由即時的人力支應，提升營運生產的彈性，使企業更具競爭力。\n並以透明資訊、智能推撥的服務提升媒合效率，讓廣大打工族群能更有效運用零碎時間賺取額外收入。\n期望在企業效率化成本運用的前提下，為台灣打造出更優質的臨僱就業環境。\n', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13624),
  ('2018', 'H.E.R.O.', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/H.E.R.O._H.E.R.O._logo-Shina-Yang.png', '目前世界各國的地震警報多為分鐘級，速度太慢，無法有效地在第一時間提供地震警報。H.E.R.O. 將智慧型手機轉化為地震偵測器及警報器，串連成全球地震速報網，以 IoT, Big Data, Machine Learning 等技術將地震資訊即時處理完成，將警報時間縮短為秒級，已達到地震速報的目標。', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13624),
  ('2018', 'RedString', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/RedString_RedString_logo-Shina-Yang.png', 'RedString 是一個提供使用者幫自己或朋友牽線的平台。除了採用 “共同朋友” 推薦的機制以強化使用者的信任感，RedString 也整合朋友揪團活動，讓單身的朋友們能更安全及更有效率的透過朋友來認識其他的單身朋友；非單身的朋友們也能適度扮演 “紅娘” 的角色推薦身邊的單身好友。\n', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13624),
  ('2018', '歐亞茶人國際股份有限公司 Teafolks', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/Teafolks_歐亞茶人國際股份有限公司_茶葉跨國b2b交易平台_logo-Shina-Yang.png', '小農國際化的最佳夥伴，全球茶葉生產者與商家的交易平台。我們為茶產業量身訂做，利用單一網站(採中英俄三種語言)整合買家與賣家，並結合物流、金流、資訊流等跨國與線下服務，讓全球買賣家可以一站式完成跨國交易。', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13624),
  ('2018', 'Virtual Man', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/Virtual-Man_Virtual-Man_logo-Shina-Yang.png', 'Virtual Man運用各種機器學習方法開發藥物預測模型，能計算化合物性質並預測其動物及臨床試驗結果，在真正試驗前就能優先剔除成藥可能性低的化合物，有效降低藥物開發所需花費及研發時間，減少藥廠成本，讓藥物開發邁入新的時代。', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13624),
  ('2018', 'Werold', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/Werold_Going-Down_logo-Shina-Yang.png', '從「魔怪大進擊AR」的擴增實境卡牌桌遊、「Going Down AR」的體感互動操控系統、「AR塗鴉互動競技」的AR多屏陣列整合系統，團隊現已累積多項技術模組，目前致力於結合5G通訊服務與AR科技，期望構建一個基於現實地理座標與空間位置的「虛擬AR世界」，使民眾日常使用網路、通訊與科技的習慣能夠無縫地轉移至AR世界中，達到虛實融合及展示互動的生活共享體驗。\n它是一個世界、也是一個終極的平台，其中包含了不同的風格、不同的區域，有故事的體驗、也有遊戲性的享受。所有利用這個平台的用戶，均能看到相同的虛擬內容並與之互動。除此之外，用戶也能透過我們的工具一同打造這個虛擬空間，幾近無限的向外延伸，就像一個立體並具象化的網際網路，把自身的創作分享給更多人觀看和體驗。', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13624),
  ('2018', '岩寬生醫', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/2019_台大車庫_岩寬生醫-Jin-Tang-Chen-Shina-Yang.png', '利用溫和不刺激的植粹成分調配出對幼兒、動物、地球環境皆無害的產品，致力於提升特殊醫療產品需求者(如：敏弱肌膚與無毒醫療)的守護品質，積極強化產品的專業服務，並透過醫療級產品為基礎，發展預防醫學的發展計畫，主軸包含，結合醫療數據服務與醫療諮詢研究，並改善消費者對於產品的消費體驗。\n', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13624),
  ('2018', 'OM Charge Sharing', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/OM_LOGO-Tanmoy-Kundu-Shina-Yang.png', 'We are OM: Over-the-counter, Multi-vendor Charging. Our mission is to provide a single point of swappable battery station which can be used by any EV vehicle owner bringing in a rapid shift to electric based mobility. OM charge sharing aims to tap into the growing market for green and sustainable mobility. We intend to test and perfect the idea in a mature market like Taiwan and then scale it to emerging markets like India and China.', 'https://www.weatherangel.com.tw/company/', 13624),
  ('2018', '吃貨大數據 The eater', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/吃貨大數據_The-eater_logo-Shina-Yang.png', 'The eater希望透過人性化推薦及搜尋店家的服務，成為以商圈為中心的餐飲媒體，解決固定族群對「吃」的選擇需求；透過社群媒體數據及顧客資訊的分析，成為商圈周邊店家的行銷顧問，使其能夠更有效的曝光，進而提高來客率。\n', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13624),
  ('2018', '五甫科技股份有限公司 Wolf Engine', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/五甫科技股份有限公司_Wolf-Engine_logo-Shina-Yang.png', 'Wolf Engine是一個SaaS系統，讓使用者不需要寫程式，即可自行開發出客製化的精準醫療及實驗室系統', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13624),
  ('2018', '智能掛號通', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/智能掛號通_智能掛號通_logo-Shina-Yang.png', '智能掛號通，是一個便利且智慧的跨醫療院所預約掛號整合平台，民眾可透過平台快速的進行跨醫療院所的預約掛號，平台系統搭載AI推薦引擎，可依照不同需求(如:最近距離、最短等待時間、最多人掛號…)推薦診所醫生，並完成掛號，透過此功能可達到病患分流的效果。除此之外，平台也可查詢藥品、疾病、醫師等醫療相關資訊．', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13624),
  ('2018', '樂福袋', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/樂福袋_樂福袋_logo-Shina-Yang.png', '史上第一款專為失智家庭打造，8週居家自助訓練課程，改善因疾病停滯的生活。面對三秒就有一位患者被確診的失智巨浪，樂福袋結合了專業的職能治療師與科技應用，為失智家庭設計出最適合家中狀況的自助訓練課程。讓家人用最短的時間學會如何與失智症共處，用最好的方式照顧家人。', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13624),
  ('2018', '易智寶 KidsExplorer', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/KidsExplorer_易智寶_logo-Shina-Yang.png', '為了解決父母不知道學齡前兒童學習狀況，我們的玩具利用感測器及iot 技術去紀錄幼兒遊玩益智玩具的使用數據，進而去做數據分析結果，並提供不同的教程及教具推播，來輔助家長追蹤小孩發展狀況及改善', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13624),
  ('2018', 'meowshroom', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/Meowshroom_循環貓砂_logo-Shina-Yang.png', '廢棄菇包再製貓砂，藉寵物市場讓循環經濟的概念深入人的生活。開發廢棄菇包為在地貓砂原料，解決菇包利用效率低甚至棄置污染、市面幾無功能好之環保貓砂、台灣缺乏貓砂原料需仰賴進口之三大問題。並以廢棄菇包之塑膠袋再製成產品外包裝。藉貓砂改變飼主使用習慣，並開始循環利用的思維。\n', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13624),
  ('2018', 'MIRLAB', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/MirLab_S3_-全方位音樂娛樂學習平台_logo-Shina-Yang.png', '本團隊致力於使用機器學習方法做音樂的分析與處理，並且發展各種應用。本團隊的目標在於串聯各式各樣的音樂相關應用(如音樂遊戲、卡拉OK等)並整合成一個雲端平台，以推向B2B與B2C端的商業模式。', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13624),
  ('2018', 'PAMO', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/PAMO_3分鐘線上和解服務_logo-Shina-Yang.png', '我們目前提供的服務是「3分鐘線上和解」，讓您不用再從「報警才有法律保障」與「私下和解比較省事」間，做任何抉擇。「3分鐘線上和解」，讓你輕鬆Pass And Move On！', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13624),
  ('2018', 't-條碼客 t-Tumor Marker', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/t-Tumor-Marker-t-條碼客-Steven-Wang-Shina-Yang.jpg', '甲狀腺癌是全世界成長最快速的癌症，病患在接受治療後，需要非侵襲性之腫瘤追蹤指標。本產項產品，使用非侵襲性尿液中之外泌體甲狀腺球蛋白，作為比血液甲狀腺球蛋白更精確及節省成本之生物指標，病患亦免受停藥4周檢查之痛苦。開創全新的腫瘤追蹤標記。', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13624),
  ('2019', 'Aemass台灣分部 3D影像製作及分析', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/Aemass.png', 'Aemass 是在矽谷舊金山的 XR/AI 新創公司。\n以可攜式單一鏡頭 3D 立體錄影系統 (Absolute 3D Volumetric capturing) 為 XR(VR/AR) 提供真實內容。\n(非 360 panorama, CGI Avatar, 3D 靜態掃描)\n利用Aemass全球專利的3D錄影技術，以及與好萊塢(Hollywood, LA)娛樂圈的深度連結以及成功經驗。\n我們成功的在台灣的教育、體育、影視娛樂、醫療、智慧城市等領域做了市場測試。\n拓展亞洲市場的同時，我們也增進了手機3D掃描、環境建物3D紀錄、遠端3D會議、3D資料分析等技術，而以3D影像服務了更廣的客戶群。', 'https://www.aemass.com/', 13606),
  ('2019', '萌醫寵物科技 VELP寵物遠距醫療平台', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/萌醫寵物科技_LOGO.png', 'VELP™ 為萌醫團隊開發之遠距寵物行動醫療平台APP，去除時間、地點限制，以寵物健康為中心，環繞生活場景提供最即時便利的專業照護', '#', 13606),
  ('2019', '自遊智載股份有限公司 tournii途你機車租賃平台', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/tournii途你logo-Sean-Hsieh-Shina-Yang.png', '機車是多數台灣人的主要代步工具，台灣共有 1,367 萬輛的機車在路上跑，機車可以說相當程度代表了台灣 的在地交通文化。\n因此租機車在觀光景點旅遊，既方便又省旅費，但租機車消費爭議案件也多，消費者往往必須面臨沒有保險、價格不透明、提前預約到場沒車，有時候還要簽立本票擔保等問題，我們認為若是能提供比較公開的管道，就可降低出遊掃興、個資外洩、事故傷害的風險。\n現在我們推出tournii途你機車租賃平台，為了用戶、業者共同提供更為專業、便捷、信賴可靠的服務！', 'https://www.tournii.asia/', 13606),
  ('2019', 'LeadBest Consulting Group (原LeadBest)', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/2019_玉山銀行_LeadBest-logo-Sophy-Yeh-Shina-Yang.png', 'LeadBest Consulting Group 是一個跨國執行顧問集團，我們從「數位賦能」出發，透過數位化、區塊鏈、敏捷思維、資訊安全等成熟的軟體技術，幫助客戶精準切入市場，解決營運難題，打造高獲利的商業模式。\n', 'https://www.leadbest.io/', 13606),
  ('2019', '雲飛傳媒有限公司 BayPay灣支付 (原Bytepay)', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/baypay-logo.png', '我們的使命是要讓區塊鏈上的資產很容易被存取並可以在現實生活中像現金一樣容易使用，要達到這個目的，我們開發了BayPay ，一個基於區塊鏈分散式帳本的支付閘道，就如同PayPal協助我們在區塊鏈上做現金轉帳，BayPay協助您在區塊鏈上做現金轉帳。', 'https://www.baypayforum.com/', 13606),
  ('2019', '云醫智能股份有限公司 / CloudMed iCARE 八合一健康管理器', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/2019_友達_CLOUDMED_單色LOGO-Hung-Chih-Lin-Shina-Yang.png', '云醫智能成立於2018年，是率先提供專業整體行動醫療服務解決方案的企業，並一直是台灣最領先的專業行動醫療電子製造與行動健康管理服務公司。云醫智能以業界最先進的生物醫學演算法技術及設計製造解決方案，支援正蓬勃發展的行動醫療與行動健康管理產業，讓終端使用者輕鬆掌握健康自主權。\n', 'https://www.cloudmed-ai.com/', 13606),
  ('2019', '芝麻開門有限公司 客來喜 飯店智能客服', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/KeylessOK_LOGO.png', '提供展覽方接待貴賓的智能解決方案，如：住宿、交通、餐飲等。展覽方僅需提供需求，即可完成一切禮賓服務。參展者可在行動端提前完成入住確認、行動票卷換餐、線上回饋表單等服務，創造全新的數位參展體驗。', '#', 13606),
  ('2019', '選優科技有限公司 SHOWHUE', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/2019_友達光電_台大創創logo-Hannie-Liu-Shina-Yang.png', '選優專注於 AI 人工智慧創新服務應用，透過深度學習與電腦視覺技術，將影像內容化為精準數據，提升零售業的轉換率及體驗。', 'http://keylessok.com/', 13606),
  ('2019', '老虎網路科技股份有限公司 17FIT', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/17fit.png', '17FIT是專注於運動健身、美容沙龍、SPA按摩的軟硬體解決方案(SaaS + IoT)。不論你是經營工作室、運動場、俱樂部、教室、診療所、健康中心、沙龍、SPA，這裡有一切你需要的智慧功能，讓你的生意不斷成長。', 'https://17fit.com/', 13606),
  ('2019', 'VOISS', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/2019_東方線上_台大創創logo-VOISS-inc-Shina-Yang.png', '為跨境電商的消費者，提供全渠道無縫的購物體驗：藉由多樣化的訊息交流與互動體驗方式，包括：諮詢、玩遊戲、猜謎、播客...等，最直接有溫度地親口關心消費者；從網站、APP、社群通訊軟體，以及回到家、在車上、到實體店內的物聯網裝置，都能清晰認電商消費者的個人化品牌助理-Vicky，帶領電家擁抱新通路的紅利。', 'https://www.voiss.co/', 13606),
  ('2019', '深智科技股份有限公司 NexRetail', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/2019_東方線上_James-Wu-Shina-Yang.png', 'NexRetail 是專注於零售業AI影像辨識的 B2B 軟硬體數據服務平台，致力於提供實體體店面和網路，數據分析結合性的產品和技術，成為實體店面和網路的橋樑。利用AI人工智慧影像辨識技術即時檢測到店顧客的客流量、年齡、性別、購物區域熱力圖進行統計與分析，從而計算人群數量和密度，檢測異常現象；實現促銷區、重要區域的人流統計與控制以及銷售狀況。', 'https://www.nexretail.com/', 13606),
  ('2019', '量身訂做頭皮管理長照服務 頭皮醫生', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/頭皮醫生_LOGO.png', '我們相信每個人都是獨一無二的個體，每天的頭皮問題也都不同，不會有一個產品能滿足所有人的需求。而造成頭皮問題的原因，也往往不是單一因素所引起的。「頭皮醫生」結合頭皮管理師以及專業團隊，運用大數據與量身訂做方式打造創新的頭皮管理長照服務，從『根本』解決消費者的頭皮問題!\n', 'https://drscalp.com.tw/', 13606),
  ('2019', '有戲數位股份有限公司 有戲數位 AI Copywriting Platform', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/2019_東方線上_有戲數位logo-Ariel-Lin-Shina-Yang.png', '有戲數位為客戶有效控制預算，整合實體與網路行銷，創造商品行銷利益。不論是客戶的需求是商品定位、網站規劃、行銷設計、線上線下行銷，或有年度預算徵求代理商，我們提供優質一站式的服務。', 'http://www.youuxi.com/', 13606),
  ('2019', '擴思科技股份有限公司 YoMuscle', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/Logo橫式方底-e1579247832829.png', 'YoMuscle是由一群愛好運動的科技人所創立，致力於以運動科學增進運動的經濟性，降低運動過度而造成傷害。從2017年起，我們更專注在跨領域的整合，結合科技與運動科學、研究中高齡族群的體適能、運動處方及慢性疾病的預防與改善。\n「YoMuscle 運動健康管理平台」提供健身者一條龍服務的完整解決方案: 成為健身者、醫師、運動指導員三方之間的溝通橋梁，讓醫師及指導員可以更容易的藉由運動數據判斷健身者真實狀況，做更貼切的診斷、建議及指導，達到運動增進健康的目的。「YoMuscle 運動健康管理平台」內所提供之訓練課程，會依照個人狀況智能化調整訓練強度，使運動更加安全而有效。完成訓練後，透過清楚易懂的圖像化運動報告，讓訓練成果一目瞭然！\n讓YoMuscle陪伴您一起動起來，讓您安心運動有Muscle！', 'https://yomuscle.blogspot.com/', 13606),
  ('2019', '酷鳩科技有限公司 Muro Box 智慧音樂盒', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/2019_添翼音樂_Muro-Box-logo-Shiao-Chen-Tsai.png', '酷鳩科技的理念是用科技串聯人與人，本公司第一項產品是全球首創的智慧音樂盒(Muro Box)，它解決了音樂盒產業200年來的瓶頸，讓機械式音樂盒能演奏無限多曲，還可以保留每個人的專屬回憶。使用者透過Muro Box的手機App編輯可自由編曲和上傳曲目，還可在雲端曲庫選歌下載編輯成播放清單，並且預設演奏時間演奏專屬回憶曲目給對方驚喜與祝福。\n截至今日(2020/07/14)，我們的首次國際群募在Indiegogo已經募得台幣809萬元。我們目前的835位贊助者來自全球44個國家/地區。其中最多贊助者來自美國(40%)台灣(16%)與日本(8%)。 歡迎造訪我們的群募專頁看目前成果: https://igg.me/at/murobox', 'https://murobox.com/', 13606)
INSERT INTO historical_startups (year, name, logo_url, description, external_link, source_post_id) VALUES
  ('2019', 'DeepWave迪威智能', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/2019_添翼音樂_dwavelogo-Henry-Lin林智源-Shina-Yang.png', '透過音樂分析與檢索的技術，創造出全方位音樂娛樂與學習平台。\n藉由一套分析音樂並自動轉換成節奏遊戲內容的機制，讓使用者能盡情與隨選音樂做互動。\nMake Touching Music Touchable !!', 'https://dwave.cc/', 13606),
  ('2019', '駭音科技有限公司 SLiMTAB', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/2019_添翼音樂_slimtab-林季伯-Shina-Yang.png', '駭音是一群致力於改變音樂教育模式的團隊。我們團隊透過整合IoT以及AI技術來改變數百年未曾過音樂教育型態。\n"駭音是一群致力於改變音樂教育模式的團隊。我們團隊透過整合IoT以及AI技術來改變數百年未曾過音樂教育型態。\n近年來遠距離教學市場正逐漸發展中，然而目前的遠距離教學方式難以進行樂器彈奏的教學，包含樂器指法、節拍、彈奏技巧等都難以透過現有的方式讓老師能有效指導學生學習。我們研發的SLiMTAB是一個遠距離弦樂器教學的IOT裝置，來讓學生在學習及練習時獲得彈奏上的回饋。', 'http://mislab.csie.ncku.edu.tw/project-pages/slimtab.html', 13606),
  ('2019', 'Pikabu 皮卡布', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/2019_台大車庫_pikabu_logo-Olivia-Su-Shina-Yang.png', 'Pikabu 是款內在優先的交友軟體，不僅止於配對，核心特色是每個用戶都有一隻專屬的柴柴戀愛教練協助你脫魯：內在優先－專門設計給以內在優先、真誠交友者使用的交友APP。', 'https://pikabu.cc/', 13606),
  ('2019', '線上共享衣櫃 衣服圖書館', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/2019_台大車庫_衣服圖書館-洪于捷-Shina-Yang.png', '衣服圖書館透過衣服交換的共享模式，讓使用者把自己穿不到但品質還很好的衣服換出，換到自己想要的衣物。我們透過檢舉、黑名單、互評制維持商品素質，同時透過引導式拍照、極為詳細的分類、針對瑕疵色系等，讓被換出的衣物資訊更加透明。\n', 'https://www.facebook.com/clothes.telling/', 13606),
  ('2019', '透識科技 BumBum', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/BumBum.png', 'BumBum 是短距離社交 App，讓用戶拓展線下生活圈。在10月中改版後，用戶數自然成長了七萬人，曾佔法國和蒙古等地區，Appstore社交排行榜前十名。\nBumBum 主打短距離、24小時的限時動態、匿名功能，以及和附近互動的戀愛鈴功能，用戶可以探索 500 公尺內其他用戶限時動態，相較其他社交軟體，搖一搖或是配對，其距離至少是五公里、十公里甚至更遠，而 BumBum 強調的是 500 公尺，500公尺是學校的校園，工作的那棟大樓，或是你住的社區。讓你和周遭時常擦身而過的那些最熟悉陌生人，從此有了連結。', 'https://www.bumbumapp.com/', 13606),
  ('2019', '溫和抗敏修護及私密處專利保養抑菌醫療級產品 岩寬生醫', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/2019_台大車庫_岩寬生醫-Jin-Tang-Chen-Shina-Yang.png', '利用溫和不刺激的植粹成分調配出對幼兒、動物、地球環境皆無害的產品，致力於提升特殊醫療產品需求者(如：敏弱肌膚與無毒醫療)的守護品質，積極強化產品的專業服務，並透過醫療級產品為基礎，發展預防醫學的發展計畫，主軸包含，結合醫療數據服務與醫療諮詢研究，並改善消費者對於產品的消費體驗。\n', 'https://acheloy.wixsite.com/website', 13606),
  ('2019', '區塊識集 blockore', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/2019_台大車庫_區塊識集Blockore-Shina-Yang.png', '「Blockore 區塊識集」是以區塊鏈為核心的資訊整合暨教育平台，企圖解決市面上區塊鏈相關知識與資訊碎片化及教育資源不足的問題。Blockore 結合了Dapps 去中心應用程式，並整合目前繁雜零碎的區塊鏈知識與資訊，不論是初學者或是想進階認識區塊鏈的使用者，皆能在此找到合適的知識。\n', 'https://www.blockore.io/', 13606),
  ('2019', 'Hikingbook 登山書股份有限公司', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/2019_車庫_Hikingbook_logo-柯政祥-Shina-Yang.png', 'Hikingbook 提供整合登山歷程且易用的登山安全服務，為山林愛好者提供創新解決方案，打造完整生態系；登山者可使用該服務於登山前規劃，登山時精準定位、記錄行程，登山後分享、備份與分析紀錄，透過創新科技，讓每個人都能安全、自在地享受山林之美。\n', 'https://hikingbook.net/', 13606),
  ('2019', '維諾股份有限公司 安心+ 全天候主動式體溫監測預警系', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/維諾股份有限公司_安心_logo-Shina-Yang.png', '人群群聚處往往是流感交互感染的盛行區域，長者照護單位、嬰幼兒園、醫院等地區在有限的人力編制下，管理單位無法提供全時全方位的體溫監控，維諾團隊開發「安心+_全天候主動式體溫監測預警系統」，應用雲端服務，降低持有成本提供自動化體溫監控，建立發燒者主動偵測預警機制，並整合即時通報程序，提供民眾安心的環境。', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13606),
  ('2019', '樂齡智遊戲 復能樂齡遊戲', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/樂齡智-logo-PS-yeh-sanyeh.png', '樂齡智專注於提供65歲以上銀髮族所使用的樂齡遊戲，我們透過專業遊戲設計+職能治療+數據收集應用/分析，使樂齡遊戲達到有趣耐玩，並具備復能的效果，且可透過數據應用長期追蹤訓練效果。', 'https://www.facebook.com/Learningsgame/', 13606),
  ('2019', '智能影像辨識系統 Memorence AI', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/01/memorenceAI_logo-e1610694855990.png', 'Memorence AI 是人工智慧公司，我們致力於提升日常與專業檢驗流程的品質與效率，以守護消費者使用安全與高品質的產品與服務。我們提供智能視覺學習與辨識系統。用戶包含如智慧工廠，健康醫療產業，並持續拓展不同領域應用。\n', 'https://www.memorence.com/', 13606),
  ('2019', '智慧洗衣 到府收送 SparKlean Laundry', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/SparKlean_logo-戴文.png', 'SparKlean Laundry是一家革新性的洗衣新創，藉由科技、服務、數據、品牌四大元素結合，打造全新的洗衣版圖。主要提供網路預約洗衣，專人到府收送。並透過自行研發耐洗耐熱洗標，全程追蹤衣物動向。下一階段我們將整合實體門市，創造一個以社交、生活為主軸的洗衣門市，讓洗衣不再是現代人的煩惱。', 'http://www.sparklean.com.tw/', 13606),
  ('2019', 'ArtzyPlanet 玩藝星球', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/2019_添翼音樂_富盈數據_玩藝星球logo-Ryan-Huang.png', 'ArtzyPlanet 玩藝星球，專為設計、音樂、影視人才建立的「共創媒合」社群平台，以「交流」與「共創」啟發創作者間的無限可能，並透過需求媒合提升企業的競爭力，目標成為亞洲最大的創意社群品牌。', 'https://artzyplanet.com/', 13606),
  ('2019', '荔枝智慧股份有限公司 荔枝好推', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/construction.png', '荔枝好推為LINE官方帳號2.0時代不可或缺的推播工具，協助企業做好精準行銷，進而降低行銷上的花費。荔枝好推藉由行為數據的收集來提供顧客分群、分群推播，與成效管理等模組，用戶可以依據顧客的屬性進行分群，接著透過分群推播達到精準行銷以及節省大量推播費用的效益。', 'https://lychee.tw/', 13606),
  ('2019', '良路設計有限公司 走走家具', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/良路設計_走走家具_logo-Shina-Yang.png', '走走家具是為都會族群設計的「帶著走的家」，強調美感與實用、簡易重複組裝、易搬運及環保，解決搬家時的困擾。全套九件家具符合小空間的生活需求，改善搬家問題並提升生活品質，榮獲2017年國際設計- IF 與 Reddot 雙獎肯定。\n', 'https://www.gogohome.tw/', 13606),
  ('2019', '邦妮科技 BotBonnie 對話互動式行銷解決方案', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/BotBonnie.png', '邦妮科技專注於對話式人工智慧商務機器人之研發與市場化，協助跨國品牌與電商客戶搶先佈局未來商務體驗。除了開放行銷與客服人員簡易上手的聊天機器人建置平台，也提供使用情境創意發想與諮詢顧問服務。\n我們協助企業在匯聚數億名高黏著度用戶的多渠道通訊軟體上，運用聊天機器人提供優質、個人化並成效卓越的顧客體驗。', 'https://botbonnie.com/', 13606),
  ('2019', 'airabbi 瑞比智慧科技 CodingBar', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/2019_雜學青_CodingBar團隊logo-李宗毓.png', '我們想同時解決「教程式」和「學程式」的相關問題：幫助老師降低教學負擔和門檻，讓更多人可以教程式；同時可以因材施教，讓學生學習更客製化、更有效率，於是我們從老師和學生的需求切入，開發出雲端系統 CodingBar 線上智慧學習平台，鎖定 11~18 歲青少年程式學習市場，提供多元的程式學習模式。', 'http://www.codingbar.ai/', 13606),
  ('2019', '籿苗創學文化股份有限公司 / 小人小學 扣扣老師 - 學齡前家庭陪伴IP', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/小人小學_LOGO.png', '「家是人類的第一個學校，父母與孩子一起學習長大。」\n小人小學由扣扣老師成立。從家庭諮詢、關係恢復的服務，以最有效率的方式讓父母更加認識自己的孩子，增進親子關係。用數據，透過線上課程、線下課程與親子策展。教大人，蹲下來學習與重新認識孩子的獨特；教小孩，成為一個超級小孩，培養未來創造世界的能力。', 'https://www.skidsedu.com/', 13606),
  ('2019', '艾貝比科技股份有限公司 課外通', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/6.課外通.png', '課外通是個集結兒童的課外活動、冬夏令營隊、才藝班課程及課外學習的資訊平台。\n我們聚集優質、具理念、有特色的教育工作者和他們的課程，並協助家長了解孩子的特質及潛力，推薦適合的課程給孩子們。我們期望串連各方教育專家及運用科技力量，來幫助孩子們健康、適性及多元的發展，進而讓每個孩子們的未來超乎想像。', 'https://www.exlearn.tw/', 13606),
  ('2019', 'Ludo 人工智能助教', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/LUDO_LOGO.png', 'LUDO也是目前少數專注於利用AI回饋學生課堂中問題，以及課堂練習評量的技能型線上教育工具。 此外，LUDO更提供一站式服務，使老師的內容得已發行到其他國家，於技術、服務流程，皆為業界領先的佼佼者。', 'https://www.intro.ludonow.com/', 13606),
  ('2019', '樂飛科技股份有限公司 發票特務 INVOICEMAN', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/06/發票特務logo_標誌去背-1-e1591084228264.png', '透過遊戲化機制吸引消費者使用電子發票載具服務，並利用其中的發票資料描繪出顧客輪廓，為品牌建立精準CRM以掌握消費者需求，成為最懂顧客的O2O生活行銷平台！', 'https://www.lifi.com.tw/', 13606),
  ('2019', 'MoBagel Inc. Decanter AI', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/MoBagel-Logo_BlueYellow.png', 'Decanter AI 是一套專業系統，提供快速、容易使用、準確、高解釋力的自動化機器學習引擎來建立您的資料模型。Decanter AI 讓資料科學家與商業分析師能夠直接使用世界頂尖的機器學習技術。透過直覺性的視覺操作介面，企業能夠迅速建立準確的預測模型來解決各種商業挑戰。', 'https://mobagel.com/tw/', 13606),
  ('2019', '我方策略股份有限公司 Hunger夯客', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/Hunger_LOGO.png', '服務業開店神器「夯客」提供完整的網站、會員、預約與行銷系統工具，協助商家們創造感動服務，輕鬆管理好每一位好客人。', 'https://biz.hunger.tw/', 13606),
  ('2019', '智慧型農務管理系統 天氣探長', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/天氣探長logo-Shina-Yang.png', '台灣特殊四季氣候，將直接控制茶樹光合、呼吸作用的比例，如何在茶樹不同生長階段且不同天氣條件下，精準決策，甚至製茶階段，便能減少每個作業環節的失誤，發揮出最大產能與維持最高品質山區，若能解決這項問題，我們將成為台灣首家客製化茶農農業資訊公司，未來能把這樣的商業模式套用在不同的經濟作物上。\n', 'https://www.weatherangel.com.tw/company/', 13606),
  ('2019', 'WORD UP', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/2019_遠傳_wordup_logo-Shina-Yang.png', 'WORD UP致力於提供優良的數位學習環境，打造AI雲端數位教材系統。主要提供AI分析學習歷程、數位化教材服務、智慧出題系統，串連學校、補教業者與學生，更有效運用考題、作業與學生練習狀況做AI數據分析，有效地提升教學效率。\n', 'https://www.wordup.com.tw/about', 13606),
  ('2019', '車聯網行動定位數據平台 3drens', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/2019_遠傳_3drens_Logo_black_white-Shina-Yang.png', '3drens的車聯網行動定位數據平台，針對物流車隊、租賃車或共享乘車，提供智慧出行軟體服務。平台並具備IoT資產管理、預測性維護、駕駛行為評分、行程優化等功能，可根據客戶的需求彈性客製化設計，提高營運效率、節省業務成本並增加盈收，智慧化每一趟出行旅程。\n', 'http://www.3drens.com/', 13606),
  ('2019', 'Project Aurora DOMI Earth', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/2019_遠傳_domi-logo2019-Shina-Yang.png', 'Applying the freemium model to energy-saving upgrades for small businesses', 'http://domiearth.com/', 13606),
  ('2019', 'Dapp Pocket', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/2019_車庫_DappPocketlogo-Anderson-Chen1-Shina-Yang.png', 'Dapp Pocket 讓你方便又安全地管理區塊鏈資產。有了 Dapp Pocket，你可以在手機上使用各式各樣的區塊鏈應用，還可以比價不同平台並即時兌換各種區塊鏈代幣。', 'https://www.dapppocket.io/', 13606),
  ('2019', 'Smart pipetting system 維德智慧科技', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/construction.png', '我們希望將最新的自動化系統與機器學習技術導入生醫產業的研發與檢測流程中，來優化執行過程中需要大量研究人員操作的繁瑣試驗流程，以及需要專家耗時判讀的數據結果等。透過結合電機、資訊、醫療等不同領域成員的專業觀點，我們能從不同角度來切入，優化整體醫療服務品質。\n', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13606),
  ('2019', 'SIFA / 視遠科技 SIFA-洗髮精選擇的智慧幫手', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/SIFA_LOGO.png', 'SIFA要解決消費者找不到合適洗髮精，所以造型無法維持，進而影響自信的困擾，SIFA用簡單五步驟，問券-拍照-AI運算-寄送-7天試用，找到最適合當下狀態的洗髮精。', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13606),
  ('2019', 'Meteo團隊 Meteo遊戲式教學電子琴', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/2019_車庫_Meteo團隊logo-蔡佳昱-Shina-Yang.png', '在台灣，每十位成年人有四位想學鋼琴卻因為時間、金錢等原因沒有去學。Meteo為這些人設計了一種結合音樂遊戲的實體電子琴產品，讓彈鋼琴變得輕鬆容易沒有負擔。同時Meteo也提供線上樂譜分享平台，讓使用者能輕鬆的找到自己想彈奏的樂曲來學習。', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13606),
  ('2019', '源典智慧醫療服務平台 源典大數據', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/2019_車庫_Meteo團隊logo-蔡佳昱-Shina-Yang-1.png', '社會的老齡化使長照與醫療保健的服務需求快速增加，少子化則擴大了醫護、保健人力的短缺，如何運用人工智慧與模型演算法的預測能力，透過智慧醫療的服務平台，滿足樂齡者、家屬、醫師、醫療院所、藥局、藥廠、設備廠商的需求，達成精準醫療、人性服務的目標，進而提升樂齡民眾的生活與醫療品質，是源典大數據團隊的願景。', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13606),
  ('2020', 'Screea', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/02/WechatIMG757-William-Chiang.png', '全球通用O2O返現暨行動支付APP。', 'http://www.screea.com/', 13580),
  ('2020', 'OH!Bot Line@一站式電商服務', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/02/LOGO-反白8cm-拷貝-張智凱.png', 'Line@一站式開店服務，企業只要有Line@就能串接我們服務，快速完成虛實整合．舉凡像是Line@行動電商，Line@即時預約功能，更重要的是能夠發揮Line社群的特性，創造社群結合虛實整合的新潮流！', 'https://www.ohbottech.com/', 13580),
  ('2020', 'KryptoGO GoTrace區塊鏈與加密貨幣分析平台', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/02/kryptogologo.png', 'KryptoGO 致力於成為最先進的區塊鏈資料分析平台與搜尋引擎，分析鏈上資料結合鏈下情報，鏈接虛實身份，協助區塊鏈公司與金融機構以有效率的方式符合虛擬貨幣的監管規範。KryptoGO 為各行各業提供一站式 KYC/AML 監管服務，協助政府、執法單位打擊金融犯罪。', 'http://kryptogo.com/', 13580),
  ('2020', 'ALPHA Camp', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/02/alphalogo.png', 'ALPHA Camp 提供亞洲最完整的科技人才培育課程。自 2014 年以來，我們以新加坡和台灣為教學據點，培訓超過 5000 名學員。校友遍及台灣、新加坡、中國、以及全球的科技新創，包括 Facebook、騰訊、Grab 等。', 'http://tw.alphacamp.co/', 13580),
  ('2020', 'Surreal Education', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/02/surreal-edu-logo-徐凡Joanna.png', 'Surreal Education(超現實教育)不單只是單方面AR/VR教程設計的提供，而是透過整合式的XR線上教學資源平台，以身歷其境的互動體驗詮釋學科知識內容，提供即時性雙向學習的互惠協助，來提升國民基礎教育學習成效，以期達到翻轉教育的目的。', 'https://www.surrealedu.com/SurrealEducation/News', 13580),
  ('2020', 'SAT. Knowledge SAT. Knowledge Platform', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/02/2019_雜學校_SAT-logo-衛星知識.png', '我們希望透過優質內容產製或代理，改變過去獲取知識的方法及品質，重建領域知識學習脈絡，並同時協助講師育成，讓知識供給者能建立個人品牌。我們希望透過多元的知識傳播形式，包含「文字」、「聲音」、「影像」、「線上面對面」等，持續供給知識內容，給所有需要的學習者！SAT. 衛星知識，將知識輻射到每個角落 。', 'https://www.surrealedu.com/SurrealEducation/News', 13580),
  ('2020', '圖靈鏈 圖靈證書 TuringCerts', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/02/Turing-Certs-Logo-Big-胡耀傑.png', '圖靈證書服務之目標市場初期囊括所有大學與教育機構、考試單位、政府部會、公司企業、申請工作之用戶、與學生。其中提供發證者由任何具有發證書與證照需求之學校、企業、考試單位與政府擔任，能15秒內完成大批鏈上證書之發送與驗證。', 'https://certs.turingchain.tech/', 13580),
  ('2020', '方格子 方格子 vocus', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/02/logo-1024-翁子騏.png', '方格子vocus是新型態的分享與交流平台，在這裡，作者可以輕鬆發表自己的專業觀點，分享生活體驗，創作絕妙好故事。', 'http://vocus.cc/', 13580),
  ('2020', 'Avalanche Computing Hyper-Scale Computing', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/02/2019_友達_Avalanche-Computing_logo-Jay-chen.png', 'Avalanche Computing is a hyper-scale computing company which provides the AI end-to-end computing framework for intelligence application providers.', 'https://www.avalanc.com/', 13580),
  ('2020', 'Datax', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/02/2019_友達光電＆添翼音樂_Dataxlogo-Aric-Fung.png', '從數據標註，AI 模型客製，到業務流程自動化，Datax 為企業，開發及研究人員提供完善的平台服務。當中包括受企業歡迎的數據 自動標註系統。\n透過結合⼈體動作及物件辨識的 AI 標註模型，只需少量訓練資料及人手標註，就能配合遷移和持續學習機制，達成⾼準確度的客製化辦識⼯具。此工具適⽤於眾多不同的⾃動化流程（質量監控、瑕疵辨識、製造流程管理、安全檢測等）。軟件⽀援部署在客戶本地伺服器，甚至離線系統運⾏，確保數據不外流。', 'https://datax.io/', 13580),
  ('2020', '萊司珥得股份有限公司 光盾技術 - 新世代科技淨化整合產品 ( LED/玻璃/光學膜 )', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/02/萊司珥得logo-蔡小孟.png', '萊司珥得獨創專利以光盾技術利用光來淨化生活環境，讓細菌、霧霾、臭味遠離生活，多元化產品可應用在燈源、玻璃製品、大樓設計、甚至3C產品中，在汙染源不段增加的現代社會，從生活周遭的物品提升生活品質。同樣可應用在生鮮（防霉抑菌）、種植養殖場域（抑菌除臭）、醫療周邊輔助等，讓光豐富且淨化您的生活。', 'http://www.lightshield.com.tw/', 13580),
  ('2020', '台大機械Pulxion新創團隊 快速評估腦中風及心血管疾病之影像技術', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/02/pulxionlogo.png', '本產品透過影像處理與特徵量化方法，揭開人體體表所蘊藏的豐富資訊，並擷取其中特徵差異進行分析，從中歸納出與特定疾病之關係，此為本產品創新之處。首先拍攝目標為人體頭頸部，受測者需按照指示進行約20秒的影像錄製，再透過網路將影片上傳至雲端伺服器計算，透過頸部脈搏起伏，以評估受測者頸部血管阻塞狀況。', NULL, 13580),
  ('2020', '深義分析 Retail Insight +', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/02/PT-LOGO_1024-02-Jarron-蛙哥-Cho-scaled.jpg', '點通科技專精於物聯網(IOT)與人工智慧技術(AI)，熟悉軟硬體整合與開發，與各種通訊技術。\n因應銀髮時代，點通科技致力於發展更簡單的更智慧的照顧系統，沒有學習門檻。長輩只需透過一個簡單的按鈕–伊鍵通，串起所需要的各種服務，包含各種健康指數監控與完整的摔跌偵測，隨時掌握長輩狀況。', 'http://www.ptcom.com.tw/', 13580),
  ('2020', '環球睿視 Ubestream AIchatin', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/02/streamlogo.png', '環球睿視AIchatin智慧對話引擎提供各領域AI人工智慧對話通用型與客製化應用方案，AI可中英多語即時全時同時自動答詢推播與轉接真人。環球睿視主力發展AI人工智慧與影音互動串流，提供真人智慧與人工智慧一體化協同服務科技及AICT資通訊大數據服務。環球睿視為全球智慧城市聯盟會員，現櫃買創櫃板輔導中。', 'https://www.ubestream.com/', 13580),
  ('2020', 'Numbers 分散式數據溯源分析系統(Traceable Data Framework: Transparent and Decentralized Analysis System)', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/02/numberslogo.png', '分散式數據溯源分析系統包括資料與輔助資訊擷取註冊軟體app、區塊鍊數據溯源系統(API/SDK)、資料搜尋與認證平台，使用區塊鏈讓數據可被追蹤及溯源，可視為數據的「生產履歷」。每筆數據在產生同時即加上數位簽章(數據指紋)，以區塊鏈去中心化、不易竄改的特性，讓後續各項與這筆數據相關的活動都被紀錄下來。', 'http://numbersprotocol.io/', 13580),
  ('2020', 'DT42 DLBox & DL Edge Platform', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/02/jjlogo.png', '灼灼科技提供了深度學習邊緣裝置軟體服務平台 DL Edge Platform，透過使用者介面讓客戶可以隨時修改影像辨識的目標，快速地將原本只有影像儲存功能的監視系統，升級為具有客製化影像識別能力的人工智慧檢測系統。', 'https://www.dt42.io/', 13580),
  ('2020', 'PackAge+ 配客嘉股份有限公司 網購包裝循環系統', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/01/PackAge-配客嘉股份有限公司-logo.png', '我們是PackAge+ ，致力於用愛與永續改變世界的社會企業！我們希望創造一個無塑網購的生活，解決網購包裝一次性浪費的問題，並透過串連線上電商與線下歸還點，打造友善社會與地球的網購包裝循環系統！除了上述使命與願景，更有環保愛心衛生紙及環保公益紙箱─兩樣產品，希望可以帶給大眾一個更加有愛及永續的生活！', 'https://www.packageplus-tw.com/', 13580),
  ('2020', '未來三次方 未來思考課程', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/construction.png', '「未來思考課程」聚焦於「未來思考六根支柱」架構，輔以獨家創發的感知未來工具，以參與式工作坊形式，透過講師的授課與引導，協助客戶藉由系統性的方法，擴大自身的思考範疇，以全新視角看待時代的改變，並找到自己的因應策略與態度，進而創造其真正的、有效的可欲未來。', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13580)
INSERT INTO historical_startups (year, name, logo_url, description, external_link, source_post_id) VALUES
  ('2020', 'S&S 運動女孩', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/01/SS運動女孩-logo.jpg', '我們是一群愛運動的女孩，分享、討論我們所愛的事物，因為喜好，因此無論是健身姿勢是否正確、哪邊的健身房器材比較好？運動後要吃什麼才不會胖？到運動時的穿著打扮、球鞋、音樂選擇……等等，都想跟妳們一起活得時尚又健康！或許是為了減肥、雕塑體態、保持健康……我們曾為了不同的原因、透過不一樣的管道，走進了這個汗水淋漓的世界，初衷總有很多原因，但現在，我們只是喜歡運動，喜歡這個 #全新的我 !', 'https://www.sweatandsweet.com/', 13580),
  ('2020', 'YouLink', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/01/2019_台大車庫_團隊YouLink-logo-Henry-Fan-e1610693494876.png', '透過100%安全的社群網絡去拓展人們現實的生活圈, 認證/匿名 模式一鍵切換到合適應用場景,採用人臉辨識搭載機器學習技術進行多元身分證件照片與資料識別,並且使用安全去中心化區塊鏈技術儲存使用者資料。\n特有數位廣告分潤機制,解決90%財富集中在1%人手裡的社會問題,使用者最多一個月可獲得上萬元收入。', 'https://youlink.tw/', 13580),
  ('2020', '透識科技 BumBum', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/BumBum.png', 'BumBum是幫助拓展線下生活圈的短距離社交App，主打短距離限時動態和附近互動的戀愛鈴功能。讓用戶探索500公尺內其他用戶，相較其他社交軟體，搖一搖或配對，其距離至少是五、十公里之外，而BumBum專注 500 公尺，500公尺是學校的校園，工作的那棟大樓，讓你連結那些時常擦身而過，最熟悉陌生人。', 'https://bumbumapp.com/', 13580),
  ('2020', '智能耳聰 Aurismart AIoT智慧安全輔具', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/01/aurismart智能耳聰.png', '身邊親友的聽力問題，引發我們深入了解「聽」的世界。\n聽障人士與聲音隔絕，造成生活與工作上許多不便，因為聽不到環境的警示聲音，如:門鈴聲、住警器、汽車喇叭聲、呼叫聲，無法察覺環境聲音變化，而感到不安，減少獨立自主生活的可能性。\n本團隊研發在助聽器、輔聽器以外的聽障生活輔具。\n運用AI辨識生活裡的環境聲音，用文字或圖案，透過穿戴型裝置，讓聽障人士知道環境聲音變化，可以用手機上傳雲端，進一步知道是什麼聲音。\n從服務與聲音被動隔絕的聽障人士開始，再擴及服務主動與聲音隔絕的情境。展現服務社會的企業精神，提供聽障人士邁向生活獨立的輔具，而且是使用方便，價格可負擔的輔助系統。', 'https://bumbumapp.com/', 13580),
  ('2020', '創創顏值最高戰隊 EsScent EsScent 訂閱制香水', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/01/2020_台大車庫_創創顏值最高-e1610694347341.png', '#Essence 象徵著本質\n#Scent 是香氣\n我們是EsScent\n一個相信能用香氣改變世界的品牌。\n#品牌願景\nEsScent將提供您多樣且客製化的小香訂閱服務\n我們希望讓所有的消費者都有探索適合香氣的機會\n讓您能在眾多香水之中發現真命。', 'https://www.facebook.com/EsScentSubscribe/', 13580),
  ('2020', 'AmazingTalker', 'https://tec.ntu.edu.tw/wp-content/uploads/2022/06/AmazingTalker（企業page）.png', 'AmazingTalker 是為想學語言的人所打造的線上外語教師媒合平台，透過透明的資訊與大數據的排列與媒合，讓最適合彼此的師生可以透過最短的時間相聚在一起，學習外語並互相交流不同的文化，串聯世界各個角落。', 'https://tw.amazingtalker.com/', 13580),
  ('2020', 'VoiceTube 看影片學英語', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/08/79968b1b-logo_type4_b.png', 'VoiceTube 致力於打造練習聽力跟口說環境，讓每一位學習者都能夠自信開口說英文。我們相信語言是溝通的工具，讓我們與全世界接軌。過去台灣人的英語學習方式都跳脫不出填鴨、死背的框架。我們透過影片學習讓「學英文」這件事情變得輕鬆有趣，同時讓使用者學習到最實用的英文用法。\nVoiceTube 網站上有多達三萬部的影片，透過影片真實的對話、多元的情境、時事的討論，短短幾分鐘就能融入國外情境，輕鬆自然地學習，有趣的題材更可以幫助學生持之以恆地學習。也因此，短短2年VoiceTube 已成為台灣最大的英語學習平台。\n\nVoiceTube 立志營造一個美好的英文學習環境，在這裡，你所學習到的不只是語言，而是用語言獲取全世界的知識！', 'https://tw.voicetube.com/', 13580),
  ('2020', 'Snapask時課問', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/08/Snapask-logo-color-transparent.png.png', '"有感於學習課業帶來的壓迫感與問題沒有得到解決的困擾，創立於2015年的Snapask，初衷為期盼運用科技延伸課堂教育，推動自主學習。透過即時演算技術媒合學習供需，Snapask 為學生提供專業的家教解題，即時在線上為學生解決急迫的課業問題，並藉此養成學生主動發問的習慣，培養對學習的興趣。\nSnapask 目前在港、台、星、馬、印、泰、日、韓等亞洲主要國家與地區提供服務，用戶包含300萬名學生與35萬名家教。過去三年，Snapask 已成功在香港、台灣及新加坡建立穩定的市場地位，10到17歲的學生族群中已有二至六成註冊並體驗過Snapask 提供的服務。\nSnapask時課問—即時媒合專屬家教解題：透過在App中上傳題目的照片，10秒內即可即時媒合學習供需，配對到最合適的家教一對一線上解題，更為學生分析學習曲線，培養自主學習的習慣與動力。\nSofasoda—建構未來力：提供線上職場軟實力課程，以「啜飲式」學習方法，讓大學以上到職場輕熟齡的用戶均能隨時隨地自在學習、透過平台提供的生涯工具確定人生方向、自信地迎接未來。\nLab樂本知室—自主學習的基地：提供國小、國中、高中中英數理課程，成人英文簡報、IELTS證照課程。6人以下精緻班，班內生並享有免費使用自習空間與專科老師現場輔導等服務，盼能引導同學們共同學習、樂在學習。\nWizmo－透過AI實現適性學習：協助學生與教育組織導入Snapask時課問的即時解題和學習曲線分析服務，串接學生在Snapask時課問上的提問內容與在校學習的數據提供分析，讓老師能夠彈性調整教學步調與觀念，實踐因材施教的願景。"', 'https://snapask.com/', 13580),
  ('2020', 'Qbi益智磁吸軌道玩具 塊樂方程式 Qbi Globe', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/08/49671210_229384961318806_1671608766321131520_n.png', '我們是專注於開發可以高度互動共玩的益智玩具品牌，Qbi。\n我們所提供的設計，不僅可以培養小朋友的多元智能，也要能增進他們的生活能力與學習能力。\n第一款產品「Qbi益智磁吸軌道玩具」，是一款可以增進親子互動、同儕合作的玩具，共歷時2年多的開發，上百位小朋友及家長的參與。它不只小孩喜歡，連大人也愛，沒有年齡限制，是一款可以大人小孩一起共創共玩，創造歡樂體驗的益智玩具。', 'https://www.qbitoy.com/', 13580),
  ('2020', 'MEandMine Body/MEandMine Emotion/MEandMine Theraplay MEandMine', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/08/66932081_497007667725206_3295956386826944512_n.png', 'MEandMine成立於矽谷，由一群小兒科醫生、教育者、科學家、心理學家和玩具迷組成的團隊。MEandMin首創『意義型遊戲』延伸STEAM精神至全人教育，在孩子最喜歡的遊戲概念上，無縫整合最抽象的人體科學、自我發展和社交情商學習。啟發孩子們愛自己，培養健康思維，發展出強韌的學習型人格。', 'http://www.meandmine.com/', 13580),
  ('2020', 'Glossika', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/08/logo-1.png', 'Glossika 利用 AI 為語言學習者量身打造個人化的學習體驗！我們利用語言學的科學化研究來分析語言的架構及難易度，提供精準且個人化的學習內容，並進一步推測學習者的記憶強度並提供複習建議，幫助學習者將短期記憶轉化為長期記憶，用更有效率的方式將一門語言學好。', 'https://ai.glossika.com/home', 13580),
  ('2020', 'Coding Ocean 海霸 程式老爹', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/08/1_-5j6988_EttYIBnsdaH2xg.png', '《Coding Ocean 海霸》用遊戲化將繁雜的程式概念重新包裝，變成輕鬆有趣的桌遊機制，讓使用者能從玩樂中學習，例如程式中的順序性、集合、條件判斷和迴圈等。而為了提升娛樂性和耐玩性，也加入互動中的核心要素：對戰，和國外的程式教育教材走出差異。對程式老爹而言，程式教育不只是教寫程式，除了培養程式思維和邏輯思考，還能帶領孩子探索和創造，培養解決問題的思考能力！', 'http://www.papacode.com.tw/', 13580),
  ('2020', '兒童程式教育完整解決方案 橘子蘋果兒童程式學苑', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/08/logo-mini-4cb1638c1e88eec3b7b90140fd3fa6573937b92bbf864ca849c62c53f2e085bb.png', '橘子蘋果兒童程式學苑提供面向 6-18 歲的程式設計教育資源，包含遍佈全台的教學據點、線上教學平台、程式設計入門工具以及學習輔助工具，致力於提高未來主人翁的科技素養，是台灣目前最具規模的兒童程式教育團隊。服務及產品已獲得市場驗證，從 2013 年的一個教學據點增加為現在的 43 個。', 'https://orangeapple.co/', 13580),
  ('2020', '綿羊犬百寶箱 綿羊犬', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/08/1415543673-707946928.jpg', '過去五年來，綿羊犬以教育設計原理，成為臺灣第一的教育類「桌上遊戲」品牌，產品銷售至國內超過 1200 間學校、並累積發行至全球 20 多國。在 2019 年，綿羊犬獲得全球最大的【德國埃森桌遊展】官方論壇邀請登台講座；2020 年也成為亞洲第一個登上【大英博物館】的教育遊戲品牌。目前綿羊犬正在籌畫全新的產品線：STEAM 科技教育主題玩具產品線，並有大量募資需求。', 'http://www.shepherdkit.com.tw/', 13580),
  ('2020', '語文和程式編輯教育的全功能型機器人 - Kebbi Air 女媧創造', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/08/otojazdqeipi7m5w2ggq.png', '市場上唯一滿足語文和程式編輯教育的全功能型機器人 - Kebbi Air\n2019 年上線半小時預購數量即超過千台，累計至三月銷量超過 6,000 台，有約 500 所學校採已規劃導入課程中。\n女媧創造相信 AI 機器人所帶來的互動形式，能帶給使用者有情感、有溫度的陪伴體驗。\n因此 Kebbi Air 不只是一台多功能的科技產品，團隊用設計思維，探索挖掘人的需求， 更結合教育的理論及趨勢，作為機器人硬體、軟體及內容應用的設計方向， 讓數位內容跳出螢幕進入到真實世界，更讓孩子的身心發展更加自然且全面。', 'https://www.nuwarobotics.com/', 13580),
  ('2020', 'STEAM 教育型無人機 Arklab 飛行學院', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/08/下載.png', '市場上唯一滿足語文和程式編輯教育的全功能型機器人 - Kebbi Air\n2019 年上線半小時預購數量即超過千台，累計至三月銷量超過 6,000 台，有約 500 所學校採已規劃導入課程中。\n女媧創造相信 AI 機器人所帶來的互動形式，能帶給使用者有情感、有溫度的陪伴體驗。\n因此 Kebbi Air 不只是一台多功能的科技產品，團隊用設計思維，探索挖掘人的需求， 更結合教育的理論及趨勢，作為機器人硬體、軟體及內容應用的設計方向， 讓數位內容跳出螢幕進入到真實世界，更讓孩子的身心發展更加自然且全面。', 'https://www.arklab.tw/', 13580),
  ('2020', '程式設計教育 猿創力程式設計學校', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/02/2021_親子天下_猿創力程式設計學校Logo-Kennan-Chen-1-1.png', '猿創力程式設計學校創立於2014年，為台灣最早投入程式教育的領航者之一，累積10,000小時以上的教學經驗，8,000名以上學生，培育100位以上專業程式教師；專為5～18歲兒童青少年所研發的完整程式人工智慧課程系統，採用線上真人互動以及線下實體方式進行教學，並收集教學過程的學生學習數據；目前學生遍及台灣、上海、美國，市場目標為全球華人市場.\n【團隊榮耀】\n2014年－入選台北市創新實驗室育成團隊\n2015年－入選新北市新北創力坊育成團隊\n2016年－入選AppWorks之初創投加速器育成團隊\n2017年－入選國家發展基金創業天使計劃\n2019年－榮獲「親子天下教育創新100」', 'https://www.codingapeschool.com/', 13580),
  ('2020', 'Surreal Education SHADOWORKS', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/08/fb4cdae3e87487948b22d58b8d0bcdda.png', '闇橡科技股份有限公司為一專業AR/VR整合設計研發團隊，致力於透過AR/VR來替教育改革，並創建Surreal Education品牌，以身歷其境的互動體驗詮釋抽象學科知識內容，建構出老師與學生對未來學習的想像藍圖。', 'https://www.surrealedu.com/SurrealEducation/News.aspx', 13580),
  ('2020', '「MAKAR」AR/VR開放式平台 Mind & Idea Fly Co., Ltd.', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/08/vt8atds0aoejajkga7n3.png', '米菲多媒體股份有限公司為台灣領先的AR/VR行動應用軟體開發商，也是全球少數的AR/VR底層引擎技術開發商，獲得多項國內外獎項的殊榮，以圖像識別、追蹤技術為核心，結合雲端技術、機器學習、大數據分析、多媒體互動，發展出十數種創新AR/VR行動應用服務模組，並擁有國內最大 AR/VR開放式平台「MAKAR」，任何人都可以自由開發AR/VR，對於產業發展具有相當的影響力。\n「MAKAR」AR/VR開放式平台，解決高成本、高技術及長時間的開發方式，使用者只要透過圖像式的拖拉，即可快速在10分鐘內建立AR/VR專案，不需學習任何的程式語言。MAKAR以圖像識別、追蹤技術為核心，結合雲端技術、AI、機器學習、大數據分析、多媒體互動，已發展數十種創新AR/VR應用務模組， 可在行動裝置、EPSON AR眼鏡 BT-300/ BT-35Ｅ及HTC Vive Focus Plus 觀看。', 'https://www.makerar.com/', 13580),
  ('2020', 'FlipRobot STEAM Education Solution Actura翻轉機器人團隊', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/08/1453d5e6c8c56df37d231542a9fa901e-330x330-1.jpg', '翻轉機器人為最適合教育單位導入的機器人STEAM教育解決方案，由課程設計出發，提供包含：硬體、軟體、課程內容、教育平台以及專業師資培訓，輔導教育單位能順利導入翻轉機器人產品。目前已開發機器人學用(STEAM Ability)三年完整產品，包括：輪軸與機構、關節與仿生以及AI, IoT雲互動等系列產品。', 'https://www.actura.com.tw/', 13580),
  ('2020', '玩轉教學推廣計畫 玩轉學校', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/08/大頭照.png', '玩轉學校相信愛玩是人類的天性，好奇是學習的起源。遊戲式教學是我們專注的核心，以議題式遊戲作為模板，點燃學習熱情、勇於挑戰複雜的社會議題，最後透過引導反思，將學習帶回現實生活，啟發開創未來的關鍵能力。 目前主要活動分成四類： 教師研習、學生課程，寒暑假營隊，以及企業CSR合作，2016年以來在臺灣舉辦了45場的自辦營隊、五百場以上的學生課程與教師研習，影響學生與老師逾1.5萬人次，目前合作對象包含國際機構樂施會、遠傳電信、國泰人壽、中信反毒基金會、台大D-School、美國World Peace Game基金會等，以及全台各級學校等。', 'https://www.pleyschool.org/', 13580),
  ('2020', 'STEAM魔法科學課程 菁英魔法學院', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/08/logo_whitebg_small.07d146dc.fill-640x640-c100.jpg', '菁英魔法學院成立於2017年，由國際魔術冠軍周代祥領軍，是全球首創魔術結合科學的教育品牌，內容涵蓋STEAM、科學素養及數理思維。提供B端一站式科學素養課程解決方案，包含課程導入、師資培訓、教材教具。用戶年齡4-12歲', 'https://www.pleyschool.org/', 13580),
  ('2020', '必揚VR學院 VOLLEGE 虛擬實境理化實驗室 必揚實境科技 VEYOND Reality', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/08/veyond-1.png', '必揚實境科技專長在教育與訓練領域的VR、AR、MR（XR）實境模擬內容開發上，VR理化實驗室產品在2018年同時獲得兩項數位內容大獎的肯定。該VR實驗室擁有極佳的沈浸體驗感，已獲得數十所教育機構採用，可以有效地提高學生的學習興趣與效果，是台灣普及度最高的VR科理化實驗室。\n備註：""必揚實境科技致力開發嶄新的教育解決方案。創辦人長期服務於網路軟體產業，從事過教育及遊戲融合的專案，對於創新解決方案具備豐富的經驗。\n\n本公司產品已獲台灣150餘個教育單位的採用，是台灣應用普及率最高的虛擬實境理化實驗室。\n\n*獲獎記錄：\n2018年底連續獲得資訊月創新金質獎及數位內容獎年度最佳產品兩項大獎。\n2019獲得高雄體感園區主題型計畫補助。\n2020入圍國發會XR創星金賞教育應用決選。\n2020獲選國發會親子天下教育新創20+鏈接國際加速計畫。', 'https://sites.google.com/veyond.tw/vollege', 13580),
  ('2020', '一站式醫療到宅服務平台 牙驛通—牙醫到府居家醫療服務（益康生醫股份有限公司）', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/04/logo-4.jpg', '益康生醫股東成員為牙醫師、藥師、送藥到府經營管理人才，成員們都希望以社會企業的經營方式來促進台灣到宅醫療的產業發展，並逐步導入更多相關醫療專業人員的投入，藉此創建到宅醫療服務生態系，不僅是讓現行居家的病患及照護者，更為我們超高齡化社會的未來提前做好準備。', 'https://www.findcompany.com.tw/%E7%9B%8A%E5%BA%B7%E7%94%9F%E9%86%AB%E8%82%A1%E4%BB%BD%E6%9C%89%E9%99%90%E5%85%AC%E5%8F%B8', 13580),
  ('2020', '虛擬健檢、復健系統 龍骨王股份有限公司', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/08/Logo_橫_中英彩-zoe-liang.png', '龍骨王的雲端遠距健檢、復建系統，運用體感偵測技術，打破空間、時間的限制，提供醫療院所與居家民眾一個有效追蹤體能健康與復健狀態的智慧工具。讓每個人在家就能享有專業的復健照護。\nLonggood’s cloud-based tele-rehabilitation system provides a smart tool using motion-sensing technology that effectively assess physical fitness and administer rehabilitation training for everyone anytime, anywhere. The system not only saves time and money for the patients as well as for the health care sector at large but also enables rehabilitation exercises in non-clinical settings such as home environments without compromising the quality of patients care', 'https://www.longgood.com.tw/', 13580),
  ('2020', '內容提供/服務整合 愛長照', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/08/LOGO2.jpg', '愛長照，最多人使用的長照平台，分成三個主營服務項目：\n一）找資訊，健康樂活＆長照相關內容服務平台。\n二）找看護，或者看護找工作，人力媒合平台。\n三）找東西，線上線下長照電商分潤平台。\n這三個主營服務項目，我們透過網路科技應用，不僅在我們官網（關鍵字：愛長照），也在各大社群平台經營圈粉（臉書粉絲27萬人，LINE粉絲6萬人）。同時，因高齡人口社會議題，流量紅利還在不斷走升(至少20年)。這不僅是時代的議題也是我們的機遇，督促我們不斷改善精實，也不斷嘗試推陳出新，後續將有更多年輕新血投入，創造更多創新服務到我們的親愛用戶。', 'https://www.longgood.com.tw/', 13580),
  ('2020', 'Applato - intelligent healthy dietary solution Applato', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/02/2021_台大創創加速器_ApplatoLogo-Yen-Chen.png', 'Applato連結食物和營養需求，透過機器學習和食物影像辨識的技術，將生活中飲食問題轉換成健康餐點推薦，協助個人打造更完整的照護，並提供企業加值服務，提升食品相關產品的精準行銷，讓每一個人在享用美食的同時也享有健康！ Applato links food and nutritional needs together. We transform difficult dietary problems into smart healthy food recommendations with machine learning and food image recognition technology to help people stay healthy and to provide value-added service to corporates for precision marketing of food products and increased sales.', 'http://yen285.wixsite.com/myapplato', 13580),
  ('2020', 'AI線上運動助教 LUDO 如荼科技股份有限公司', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/08/part_1342_994320_05178.png', '忙碌的生活使許多人不能維持規律的鍛鍊，LUDO 嘗試打破運動的時間與空間限制，讓人們無論是下班回家、出差回飯店，都能透過一支手機自我訓練。 LUDO 正在建立一個全新的運動生態系，利用人體動作分析系統，快速回饋姿勢校正的互動機制，打開運動學習新場景的體驗。\nLUDO 於 2018 年開始著手開發能夠即時回饋的人體動作分析系統，期望透過快速回饋給使用者的互動機制，打開運動學習新場景的想像。 線上運動學習必須要能解決每個學習者練習時遇到的問題，LUDO Sport AI 為了解決學習者獨自練習無法察覺姿勢正確性的問題，讓每個人透過「自拍」結合即時影像辨識，得到校正回饋。', 'http://yen285.wixsite.com/myapplato', 13580),
  ('2020', '拍片自造所', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/08/20200531拍片自造所logo去背-影音創客-領客創意.png', '"「拍片自造所(Video Pai.com)專注於協助新手從0到1學會拍片;提供TTT三大服務：Traning線上課程、Tutor線上教練、Tool線上工具，讓你聽得懂、學得會、跟著拍、立可用。 理念：你的拍片教練，手把手陪你學拍片。 目標：人才影音力賦能，產業影音力運用加速數位轉型。 願景：透過共創與合作，走出台灣，行銷到世界五大洲。\n""VideoPai.com assists beginners learning how to make a video from zero to one. We provide the “TTT” services: Training online with relevant courses, Tutoring online with experienced instructors, Tools online for making videos. By these well-designed services, everyone can easily absorb knowledge, quickly get started, instantly film after our demonstration, and publish the effective video for web marking right away.\nCore Value: Your video-making instructor teach you how to make a video step by step.\n\nGoal: Empower people to obtain the ability of making video. Empower the industries to use video for digital transformation.\n\nVision: By the co-creation and cooperation, our marketing starts from Taiwan, then one day to the five continents, the whole world.\n"""', 'http://yen285.wixsite.com/myapplato', 13580),
  ('2020', 'DL BOX & DL Platform 灼灼科技', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/02/jjlogo.png', '灼灼科技研發之 DLBox ，搭載了深度學習邊緣裝置軟體服務平台 DL Edge Platform，在不需要連接外網的情況下，內建下列功能：\n*執行深度學習技術以預設模型完成影像識別功能\n*讓使用者透過圖形化介面之標註工具，完成新資料標註\n*執行模型訓練功能，客製化深度學習模型\n*更新模型後，執行深度學習技術以客製化模型完成影像識別功能\nDT42 develops DLBox and DL Edge Platform which a deep learning edge device software service platform. Without connecting to an external network, the following functions are built in:Perform deep learning technology to complete image recognition function with preset models Allow users to complete new data annotation through the graphical interface annotation toolPerform model training function to customize deep learning model After updating the model, execute deep learning technology to customize the model to complete the image recognition function', 'https://dt42.io/', 13580),
  ('2020', '衛教影音共享平台 健康盟', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/09/健康盟_LOGO標準字中英-王文利-1-1.png', '健康盟衛教影音共享平台是以「秒懂動畫」為主軸的衛教影音動畫，讓醫病關係可以透過科普角度的影片達到秒懂的效果，減少錯誤的健康迷思。透過影音媒體作為衛教傳播的管道，讓醫護人員更能即時宣導疾病，對症下藥，讓溝通更清楚秒懂。並降低教育程度與城鄉差距的落差，使得衛教溝通無障礙，更能展現衛教在醫療上的價值。', 'https://www.healthleaguex.com/', 13580),
  ('2020', 'Encore 專屬熟女的興趣社交平台', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/08/logo-2.png', 'Encore 為中熟年女性打造純女性興趣社交平台，提供安全的同在空間，目標成為全球最大的熟年社群基地。女性在青中年時期為家庭、工作付出，面臨離巢期挑戰時，Encore 將協助女性找回嗜好、培養興趣、尋求同好、自信有我。\nEncore is a platform for 35+ females to make friends, organise activities and develop interests in a social setting. Women represent a unifying familial influence by their 20s, but friendship are often compromised as the demands of motherhood take precedence. Encore is devoted to creating an environment that enables women to feel confident and socially supported.', 'https://encoredays.com/', 13580),
  ('2020', 'LTPA智慧認知訓練方案 樂齡智造科技股份有限公司', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/08/271156_B.jpg', '許多研究證實，在中年期間規律的進行認知與肌力訓練可以預防失智症的發生。科學家們認為，每周至少進行兩次的休閒時間體力活動（LTPA-Leisure Time Physical Activity）對年齡、性別和不同年齡的人產生了很大的影響。\n「LTPA智慧認知訓練方案」是一系列APP和設備，結合AI與IOT技術，協助長者進行長期的失智訓練與肌力提升，幫忙長者建立身體活動例程，以維持或改善生活質量。 由職業治療師（OT）共同開發，並用來記錄，追踪和分析老年人的訓練進度和與效率。', 'https://www.ltpasolution.com/home-tw.html', 13580),
  ('2020', 'WaCare遠距健康', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/08/2020_UDN聯合報_WaCare遠距健康logo-Terry-Hsieh.png', '創新健康社群網路應用服務「WaCare 遠距健康」- 連結健康專家與親友的關懷網路，透過AI推論引擎、機器學習演算法與自然語言分析，串連政府開放資料、穿戴式裝置、個人醫療數據，實現個人行為塑模與健康風險預測，透過個人化的衛教建議、視訊聯繫等提升社群親友的健康意識，並以主動式風險警示誘發線上諮詢與關懷行動及早抑制風險發生。 ""Established in 2017, La Vida Tec. developed WaCare App, a health community software, to collect and integrate the data of the community to build an interactive care network. We utilized a great quantity of individual health information and machine learning techniques to build active individual health management and risk assessment.\nWe made preventive healthcare come true and release the pressure of the Government and medical institutions from aging society. We also made people get early warnings before disease occurrence to achieve the ultimate goal of health promotion, disability prevention, and active aging.', 'https://www.wacare.live/', 13580),
  ('2020', '自動化產品服務 gadgetHi', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/08/2020_車庫_gadgethi_台大創創logo-ck1031052王重程.png', '"gadgetHi為日常常見的服務提供自動化的技術，朝著減少服務業50％勞動力需求發展，應用層面如餐廳營運，停車場管理與文書處理等。\n正如我們的座右銘「機器上手，人性觸動」，人人都可以輕鬆上手，簡單駕馭，且精準呈現真人能提供的技術。我們以三個核心價值：簡單、可靠、可行來解決問題，促進自動化的發展。\nGadgetHi find solutions to provide automation for some of the most common services in our everyday lives. Our goal is to develop technologies to aid humans on repetitive tasks and reduce the need of labor by at least 50% for services like restaurant operation, parking lot management, and company word processing etc. Just as our motto, “Robot Hand, Human Touch” said, we want our technology to be accessible and friendly, mimicking help from another human. Therefore, we approach any problem with the three core values in our mind: simple, reliable, and safe."', 'https://gadget-hitech.com.tw/website_home_chn.html', 13580),
  ('2020', '影響貿易 恩沛國際投資', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/08/impct-logo.png', 'IMPCT為全臺灣第一也是唯一榮獲社企界諾貝爾獎-霍特獎全球冠軍的團 隊，以改善偏遠地區孩童教育的初衷，推出獨特的「影響貿易」商業模式，將 同時解決傳統「公平貿易咖啡」無法追蹤成效與實質影響力的痛點，在採購端 和消費端做出改變，把經濟弱勢地區生產的咖啡，轉換成推動社區發展與教育 培力的力量，並以自建的「影響貿易平台」將所有回饋效益公開透明。成立迄 今不到五年的時間，已在中美洲如薩爾瓦多、瓜地馬拉、宏都拉斯以及南非， 興建九所玩安幼兒園，讓超過300位孩童的教育品質得以提升。未來，團隊將結 合區塊鍊技術推出「影響貿易平台2.0」，讓資金流向完全透明化、全球化以及去 中心化並且經得起檢驗。', 'https://impct.tw/', 13580),
  ('2020', '水滴發票 水滴', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/08/2020_車庫_水滴logo-Cheng-Jason.png', '水滴是一間 AI 金融科技公司，專注於將 AI 技術導入到日常金融應用之中，打造聰明的理財服務。在堅持保護使用者隱私的大原則下，我們從底層設計保護使用者的資料，讓產品不只是好用，更要讓使用者用的安心。團隊由資訊處理專長的連續創業家所創立。結合數據分析與國外金融科技的經驗，水滴讓使用者的點點滴滴都累積。\nCredidi, founded by serial entrepreneur with data science background, is a FinTech AI startup focused on implementing cutting-edge AI technology to create powerful financial tools. With user privacy at our core, we are designing our entire database from the ground up to ensure that our service is as safe as it is smart. Join Credidi now and start making smart financial decisions.', 'https://github.com/vincentno1/credidi', 13580),
  ('2020', 'Contal 素養科學班 Contal 教育', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/08/cropped-a-2.png', '水滴是一間 AI 金融科技公司，專注於將 AI 技術導入到日常金融應用之中，打造聰明的理財服務。在堅持保護使用者隱私的大原則下，我們從底層設計保護使用者的資料，讓產品不只是好用，更要讓使用者用的安心。團隊由資訊處理專長的連續創業家所創立。結合數據分析與國外金融科技的經驗，水滴讓使用者的點點滴滴都累積。\nCredidi, founded by serial entrepreneur with data science background, is a FinTech AI startup focused on implementing cutting-edge AI technology to create powerful financial tools. With user privacy at our core, we are designing our entire database from the ground up to ensure that our service is as safe as it is smart. Join Credidi now and start making smart financial decisions.', 'https://contalacademy.com/%20https://www.facebook.com/Contal-109143503885491/?modal=admin_todo_tour', 13580),
  ('2020', '客製化年節禮盒、囍餅彌月、點心伴手禮、義大利麵、手搖飲料、義大利麵調理包 Tribake樂芽', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/08/original.png', '捐錢、做志工、購買愛心餅乾等方式，大家一定不陌生，但是單憑愛心為賣點的消費並不長久，因此樂芽團隊研發優質產品，推出用心服務，將餐飲技術轉移給身心障礙者以及庇護工場，同時讓大家多認識一些優質小農，創造三贏，讓大家是真心認同，覺得好吃，同時做了公益，創造長期且正向的循環。\n營業內容：\n手作教室-清新樂芽：客製化年節禮盒、囍餅彌月、餐會餐盒、點心伴手禮\n複合式餐廳-囍歡樂芽：義大利麵、手搖飲料、義大利麵調理包\n\nTriBake hopes that everyone can be better off. We insist on building up the reputation of individual farmers and providing disabled people with stable income sources while allowing customers to enjoy products of high quality.\n\nDonating, volunteering, and buying cookies sold by disabled people on the street are all common ways to do charity. However, marketing pity is not a sustainable way to sell products. TriBake develops products and services of high quality and provides professional assistance to disabled people so that customers can enjoy good snacks while doing good deeds at the same time, creating a virtuous cycle for charity.', 'https://tribake.shoplineapp.com/', 13580),
  ('2020', 'PlasmaFluo BioMetaSpec', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/08/2019_台大車庫_BioMetaSpec-logo-W-M.png', '暴增的血中一氧化氮，是重症的主要病理特徵，我們團隊所研發之重症用血液監測儀據高敏感度特色為:\n1. 能夠在敗血症發生後第一小時偵測到一氧化氮這個前兆因子。\n2. 免試劑、高靈敏度且可頻繁篩查的檢測平臺。\n3. 於急診或門診收住院時協助臨床醫師早期偵測，POA 敗血症有利醫院申請較高額度之 DRG。\n4. ICU 急重症病房治療時，做為 point-of-care 床邊照護的簡易操作設計，即時瞭解病患對藥物治療反應與器官損傷情形，進而降低敗血症死亡率和住院天數，改善病患預後與有益醫院獲利。\n5.保守預估在本團隊於 2023年底取得 510(k)後五年內能將營收達到 6 千萬美元。\nThe sudden increase of inducible Nitric Oxide Synthase (iNOS) is the pathological hall mark of sepsis and organ failure.\nThe features of plasma fluorometer are described as follows:\n1.Detect the sepsis within one hour via the cofactor fluorescence of iNOS.\n2.Agent-free sensor can constantly monitor and sensitively detect the emerging iNOS at the early stage of sepsis.\n3.This medical device can help doctors in emergency department (ED) and ICU to judge the sepsis is present on admission (POA) or not, which is beneficial for hospital to claim higher reimbursement from diagnostic related group (DRG).\n4.When patients are admitted to ICU, this device can serve as bedside point-of-care and routinely check the treatment response and the risk of organ damage. Early detection before organ damage could reduce the mortality and days of hospitalization.\n5.Our team plan to obtain 510(k) approval from FDA and the company revenue could reach 60 million USD within 5 years.', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/', 13580),
  ('2020', '優時間銀行雲', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/08/2019_車庫_優時間銀行雲logo-CJ-Lin.png', '暴增的血中一氧化氮，是重症的主要病理特徵，我們團隊所研發之重症用血液監測儀據高敏感度特色為:\n1. 能夠在敗血症發生後第一小時偵測到一氧化氮這個前兆因子。\n2. 免試劑、高靈敏度且可頻繁篩查的檢測平臺。\n3. 於急診或門診收住院時協助臨床醫師早期偵測，POA 敗血症有利醫院申請較高額度之 DRG。\n4. ICU 急重症病房治療時，做為 point-of-care 床邊照護的簡易操作設計，即時瞭解病患對藥物治療反應與器官損傷情形，進而降低敗血症死亡率和住院天數，改善病患預後與有益醫院獲利。\n5.保守預估在本團隊於 2023年底取得 510(k)後五年內能將營收達到 6 千萬美元。\nThe sudden increase of inducible Nitric Oxide Synthase (iNOS) is the pathological hall mark of sepsis and organ failure.\nThe features of plasma fluorometer are described as follows:\n1.Detect the sepsis within one hour via the cofactor fluorescence of iNOS.\n2.Agent-free sensor can constantly monitor and sensitively detect the emerging iNOS at the early stage of sepsis.\n3.This medical device can help doctors in emergency department (ED) and ICU to judge the sepsis is present on admission (POA) or not, which is beneficial for hospital to claim higher reimbursement from diagnostic related group (DRG).\n4.When patients are admitted to ICU, this device can serve as bedside point-of-care and routinely check the treatment response and the risk of organ damage. Early detection before organ damage could reduce the mortality and days of hospitalization.\n5.Our team plan to obtain 510(k) approval from FDA and the company revenue could reach 60 million USD within 5 years.', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/', 13580),
  ('2020', 'TEFCORD排齦線 棗子科技', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/08/2020_車庫_棗子科技logo-張復龍.png', NULL, 'https://wordpressmu-651819-3104022.cloudwaysapps.com/', 13580),
  ('2020', '推倒學術付費高牆 Researchain', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/08/output-onlinepngtools-4-廖佑銘.png', '貪婪的學術出版商壟斷了知識傳播，囚禁了學術自由，面對出版寡頭設下的層層枷鎖，我們決心奮力抵抗，我們將帶領學術工作者重新奪回知識的火種，我們將為全球3000萬學術工作者，\n打造世界第一個學術區塊鏈社群平台 ── Researchain。\n""The greedy academic publishers have monopolized the spread of knowledge and imprisoned academic freedom. I determine to resist against the yoke locked by the publishing oligarchs. I will lead researchers to regain the tinder of knowledge. I will construct the world''s first academic blockchain community ─ Researchain | Decentralize Knowledge', 'https://lukadvisor.tech/', 13580),
  ('2020', 'Rogy 360度全景攝錄影直播相機 達標智源科技股份有限公司', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/08/0.jpeg', '達標智源以全景360產品出發，本著台灣研發設計製造的定位，並以dp品牌行銷全球，推出首項產品── Rogy 360 6鏡頭全景攝錄影直播相機。\n此核心關鍵技術提供機內即時拼接處理，達到無需後製的高效能結果，一秒鐘即能拍製全景360度內容，另一優勢單鍵直播，可即時直播到Facebook 及Youtube無需連接行動裝置或電腦，達到簡單使用的目的。\n""dp smart launched the first product, Rogy 360 6-lens Panoramic Live Streaming Camera.\nThis core key technology provides real-time in-camera stitching processing, enabling efficient results without the need for a post-processing, capturing 360-degree views in one second, and one advantage of one-click broadcast, live streaming to Facebook and Youtube without connecting to mobile devices or computers for simple use.', 'http://www.dpsmart.com.tw/', 13580),
  ('2020', 'KOLpass', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/08/2568414_original.jpg', '"KOLpass是一個意見領袖(KOL)平台致力在提升商家轉換率進而破除無效流量和提升KOL與商家合作效率進而帶動再次合作機會。以KOL體驗為出發點的即時合作功能，結合聯盟行銷的成效分潤，讓口碑行銷市場更真實、有效且簡單。\nKOLpass is an Key-Opinion-Leader (KOL) platform dedicated to improving the conversion rate of merchants/brands to eliminate invalid traffic and increase the efficiency of cooperation between KOL and merchants, thereby driving opportunities for cooperation again. The instant cooperation/redemption function based on the KOL experience combined with the effectiveness of affiliate marketing makes the word-of-mouth marketing market more authentic, effective and simple."', 'https://lin.ee/o9tT3td', 13580),
  ('2020', 'FOLLOW 數位音訊導覽服務 ＆ Ctrl A 現場-現場營運POS與人流分析系統 揚揚創新科技有限公司', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/08/9cf7bfe2819254a6117163564537ba434d6c50daf3855e4a7c57129cd22022beae1f7c49a25568f893e5ebfd7ccde3cf180d0fb66964401a8248ab12029be959.jpg', '"FOLLOW數位音訊導覽服務：讓內容體驗數據化，消費者的每一步體驗軌跡都能看得到。CtrlA現場控：整合現場票證與出入流程，完整掌握現場人流數據與熱時軌跡。\nFollow, the Digital Audio Guiding Service: Know every interactions of the consumers in their visiting experience via visualized experience datas.\nCtrlA, the Onsite Control System: Given a full pictures of flow of people and the hot track of the site by Integrating the information from ticketing and entry/exit control."""\n', 'https://www.y2services.com/index.html', 13580),
  ('2020', 'Count++ Luk Advisor', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/08/2020_台商資源國際_台大創創logo-luk-wingsan.png', '"銷售量及營業額一向是實體門店重要的績效指標。但與電子商務相比，面對營業績效不佳，實體門店卻無法透過網站分析等方法，以更進一層的數據分析來應對瞬息萬變的客戶需求。「Count++客流分析」 解決方案以電腦視覺，結合3D影像技術,CCTV 與人工智能演算法為門店進行客流追蹤。Count++不單能根據日、周、月、年等作週期分析、跨門店、跨渠道分析，還能結合POS系統等銷售數據作整合分析， 進而準確預測下一周期的營運績效。商戶更可得到精確的顧客細分，協助零售業者制定相應策略，提升經營效益。\nBrick-and-mortar retailers are always looking for insights other than sales and revenue to make better decisions. Our solution “Count ++” helps retailers collect rich insights about not only how many people enter their store, but also about their behaviors or preferences while there and how long they stay at each point in the shop. Powered by computer vision, 3D imaging technology and AI algorithms, Count++ would be able to compatible with CCTV and provide periodic, cross location and cross channel analytics and predictions. Retailers could make informed decisions, which enables them to power-up their operational process, revenue strategy and business model."', 'https://www.slamindoorar.com/', 13580),
  ('2020', 'SLAM GO', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/08/1594894913201-YUCHI-CHI.png', '"擴增實境(Augmented Reality)室內導航需求：戶外定位服務(Location-Based Service；INDOOR)已日趨成熟。然而，由於衛星訊號無法穿透建材，使得「室內定位」一直是衛星訊號的盲區。室內定位的應用不僅有需求性，且具備高度商業價值，諸如機場車站(路徑指引)、遊樂園(AR互動)、百貨商場(室內導購)都是AR需求的應用場域。也因此，室內定位日漸成為熱門探討的議題。藉由將真實世界資訊與虛擬地圖服務整合，甚至可以結合眾多資訊讓使用者以AR方式確認在百貨商場(室內導購)前方是否右轉或左轉，同時也能透過AR方式顯示所在位置的餐飲店家，或是遊樂園(AR互動)特殊景點，甚至可清楚標示遊樂園園區名稱，而不用像以前即便透過地圖導航卻還是無法分辨正確前進方向。 INDOOR AR O2O零售4.0服務模式試煉：2015年阿里巴巴馬雲便提出以物聯網(互聯網)+、O2O(online to offline)及O2M(online to mobile)逐步發展朝向零售4.0趨勢。本團隊著眼於這兩年行動支付逐漸普及INDOOR遊戲風行全球，讓智慧手機服務應用充滿更多想像。而本服務將透過在ARKit/ARCore技術開發INDOOR AR室內導覽與導購服務應用，將行動商務O2O、虛實整合發展與應用建置在統一夢時代大型場域，透過FunTech(INDOOR AR)讓消費者在遊戲化導覽尋路中，買得開心、玩得有深度。此外，因APP與雲端平台將會有消費者玩樂與消費習慣大數據，以及透過社群網絡串聯，後續的遊戲化導覽尋路設計安排，將可逐步發展出C2B經營模式，實現零售4.0。\nINDOOR AR O2O零售4.0服務模式試煉：2015年阿里巴巴馬雲便提出以物聯網(互聯網)+、O2O(online to offline)及O2M(online to mobile)逐步發展朝向零售4.0趨勢。本團隊著眼於這兩年行動支付逐漸普及INDOOR遊戲風行全球，讓智慧手機服務應用充滿更多想像。而本服務將透過在ARKit/ARCore技術開發INDOOR AR室內導覽與導購服務應用，將行動商務O2O、虛實整合發展與應用建置在統一夢時代大型場域，透過FunTech(INDOOR AR)讓消費者在遊戲化導覽尋路中，買得開心、玩得有深度。此外，因APP與雲端平台將會有消費者玩樂與消費習慣大數據，以及透過社群網絡串聯，後續的遊戲化導覽尋路設計安排，將可逐步發展出C2B經營模式，實現零售4.0。"', 'https://www.slamindoorar.com/', 13580),
  ('2020', '新零售方案 邁摩科技', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/08/2020台大創創_台商國際_邁摩科技-removebg-Sam-Yen.png', '"“新零售”是在多年行業經驗基礎上，以門店運營為基礎，結合移動互聯網、大數據，針對零售企業，重點打造的集“商品、會員、行銷、庫存、訂單、採購、資金、資料”於一體的線上線下全管道解決方案，具備多埠、跨螢幕、移動化等特性，可以支援隨時隨地滿足客戶的購物需求及零售企業運營需要。\n"New retail" is based on many years of industry experience, based on store operations, combined with mobile Internet and big data, for retail enterprises, focusing on creating a collection of "commodities, members, marketing, inventory, orders, purchases, funds, information" All-in-one online and offline full-pipe solutions, with multi-port, cross-screen, and mobile features can support customers'' shopping needs and retail business operations needs anytime, anywhere.', 'http://www.mimotech.com.tw/', 13580),
  ('2020', 'Zero CKOY', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/08/2020_春池加速器_CKOY_logo-Jerry-Hsu.png', '"零負擔旅行沐浴體驗，採用循環設計和環境友善材料的一次性潔膚塊。\nZero is a shower kit for your journey and made of eco-friendly materials. It''s single-use but zero waste. The concept follows the sustainable principle and aims to reduce plastic containers."', 'https://ckoy.co/zero', 13580)
INSERT INTO historical_startups (year, name, logo_url, description, external_link, source_post_id) VALUES
  ('2020', '無耗材過濾技術 點點塑', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/08/淺色底使用藍logo-Alice.png', '"點點塑致力於用科技協助海洋環境、過濾產業，自主研發顆粒捕捉技術清除水域中危險物質例：塑膠微粒、工廠過濾殘渣，提供污染防治設備與服務，透過發掘社會問題實施水域清潔，期望用青創科技之力協助傳產和環境，成為為海洋生物發生的企業，Save Ocean Save Children\nMicroPC is focusing on using Non-consumable Filtration technology to assist the marine environment and the planet industry. MicroPC developed particle capture technology to remove dangerous substances in waters such as plastic particles, factory filtration residues. Micro PC capture technology already apply in environment providing pollution prevention equipment and services for government. In the future, we will assist semiconductor planet for saving the consumable cost. We hope we could become an enterprise that occurs for marine life, Save Ocean Save Children"', 'https://www.micropctw.com/', 13580),
  ('2020', 'OPO Stack AI智慧電管家', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/08/下載-3.png', '"OPO STACK 智慧電管家是結合AIoT技術並整合行動電源,不斷電系統,及家用儲能功能運用於室內及室外的節能減碳的新發明專利產品.\n本產品之「隨插即用，安全輕鬆」特色，就安裝上更具優勢，無需專家到府，節省人工與時間成本安裝，藉此反映於銷售價格。本產品因儲能容量較小，在掌握相同技術之基礎下，形成成本較低，而間接造就銷售價格低之市場優勢。\nOPO Stack is an innovation product combined with the functions of power bank, ups & ess and also can be easily to control by App. The product is for indoor/outdoor household/small office."', 'http://www.interxie.com/', 13580),
  ('2020', 'One more 再一杯工作室', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/08/noemore_logo-li-Weil.png', '"「再來一杯」是關於永續旅遊的循環經濟計畫。我們以獨特設計的玻璃瓶裝水取代飯店提供的一次性塑膠瓶裝水，同時作為旅客在這趟旅行時的外出杯，享受台灣的手搖杯文化！旅客在退房後飯店會將空瓶回收，經過高溫殺菌後重新填裝，提供給未來更多的旅客使用，打造完整的循環系統! 我們透過與旅館業者合作B2B的產品服務化租賃模式，以一個瓶裝水的小改變，落實永續到更大的生活圈！\n""One more cup"" is a circular economy project about sustainable tourism. We replace the disposable bottled water provided by the hotel with our design - glass bottled water. Tourists can enjoy a high quilty water in hotel and use it as their personal bottle during this trip to enjoy Taiwanese hand-shake drinks culture. At the time of check-out, the hotel will collect the empty glass bottles, through the high-temperature sterilization and cleaning, those bottles will be refilled into new bottled water, which will be provided to the next passengers. By our unique product design, recycling and reusing process, B2B product-as-a-service model, we look forward to implementing sustainability to a larger scope with a small change of bottled water!"', 'https://chungweitwd.wixsite.com/taiwonfood', 13580),
  ('2020', '好盒器', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/08/好盒器LOGO_1024-宋宜臻.png', '"好盒器建置便利的外帶容器借還機制，串聯店舖提供可重複使用的飲料杯與餐盒，讓民眾在購買餐飲時可借走容器、用畢後再歸還到任一歸還站點，即可完成一次容器循環、減少一次性垃圾，降低我們對拋棄式容器的依賴，讓環保與便利不再是兩難的選擇。\nGoodToGo is a reusable cup rental service that aims to replace single-use cups. GoodToGo members get a cup when ordering a drink to-go from a partnered shop. After consumption, they return the used cup to any drop-off location. People can effortlessly enjoy to-go services without producing waste."', 'https://goodtogo.tw/', 13580),
  ('2020', '智慧看護媒合平台 Home心', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/08/2020_玉山銀行_台大創創logo-蕭存佑.png', '"在未來10年內台灣將邁入「超高齡化社會」，照顧服務成了迫在眉睫的問題。\nHome心目前主力放在住院的照顧人力媒合，用數據分析為住院者篩選出最適合的照護服務員，成為住院家庭最堅強的後盾。\n由LINE做為全民入口，未來計劃開發更多長期照護、智能照護的服務，打造出台灣長照的新生態，並落實「在傳產中看見創新」的願景。\nTaiwan will enter a new era of """"Super-aging society"""" in the coming decade. Due to that, elder caring will be the top priority question for Taiwan.\nFortunetely, Homexin has the answer for that. Homexin focus on hospital healthcare market. We use data and edge cutting technology to find the right caregiver for each particular patient.\nIn the future, Homexin plan to build a whole new ecosystem of healthcaring on LINE. Expanding our services to homecaring, AI caring center. Visioning a hospitality enviroment for the elders with the use of technology and software."', 'https://homexin.com.tw/', 13580),
  ('2020', '即時非侵入性人臉辨識偵測心跳與呼吸技術 傑精靈', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/08/2020_商之器_傑精靈logo-Steven-Su.png', '"本產品利用電腦視覺與人工智慧的方式動態追蹤人臉並即時計算出人的生理參數---心跳率與呼吸率，屬於非接觸式的量測方式。可透過心跳率與呼吸率估算運動中最重要的乳酸值，有助於應用於健身房的健身訓練、老人安養的心血管疾病監控，或是運動疲勞等情境。亦可更可以應用於門禁系統，辨識人臉的真偽。\nThis technique of the product using computer vision and artificial intelligence to calculate the person''s physiological parameters-heart rate and respiration rate in real time based on the dynamic information of the face which is a non-invasive method. The most important lactate value in sports can be estimated by heart rate and breathing rate, which can be used in fitness training in the gym, cardiovascular disease monitoring for the elderly, or sports fatigue. It can also be applied to access control systems to identify the authenticity of human faces."', 'https://www.sg-aitek.com/', 13580),
  ('2020', '光學骨質密度儀(OBD) 智慧生醫光電', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/construction.png', '"我們所提出的光學骨質密度儀經過實際測試，可以提供中高度準確之骨質密度評估，且預測準確度與\nDXA 量測結果僅 5% 誤差。該技術目前正在申請國際發明專利。簡單來說，光學骨質密度儀就是把 X 光換成多波長近紅外光作為光源，因此原理上與 DXA 相當雷同，故準確度才會如此之高。透過照射多波長的\n近紅外光於手部遠端橈骨處並收取穿透光影像進行分析，加入手部基本物理量測所獲得的參數（手腕寬度、\n厚度、周徑）通過多變數線性迴歸模型，便可以準確預測該受測處骨質密度。量測全程為非侵入式檢測且無\n輻射性、容易操作並量測快速。', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13580),
  ('2020', 'MUSK system MUSK Technology', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/08/2020_康寧_MUSK-logo-Ching-Wen-Huang.png', '"MUSK創新應用Micro LED技術來達成無光罩的曝光製程，突破一張光罩只能定義一種線路設計的先天限制，是一個相對於傳統光罩的破壞式創新。一個MUSK系統可以任意設計並執行無數個曝光圖形，藉此大幅降低製程成本、縮短開發時間、同時保有內部使用者的設計機密性。\nMUSK system is a disruptive innovation relative to traditional photo-MASK. As a creative application to achieve a so-called maskless exposure, it breaks through the limitation of mask which is always considered that one mask only defines one pattern. You can design and execute the exposure process for a variety of patterns on the MUSK system to have a dramatic reduction of process cost, to shorten development time, and to preserve internal confidentiality', 'http://www.musk-tech.com/', 13580),
  ('2020', '音樂語音相關AI技術 DeepWave', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/09/logo-dwave-depng-Henry-Lin.png', NULL, 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13580),
  ('2020', '卡伯', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/09/Cardbo_MaterialDesign_Pure2D-Ryan-Hu-1-1.png', '卡伯專注處理信用卡優惠的分析與比較。2C 端，我們幫助持有信用卡的小資族在特定的消費情景，能夠利用卡伯的 LINE bot 快速查詢優惠，以便獲得最多回饋。2B 端，我們利用卡伯開發的優惠搜尋引擎協助數位通路業者，優化他們平台消費流程的使用者體驗，進而增加下單轉換率。\nCardbo specializes in credit card offers’ data analysis.\nOur LINE bot, the 2C product, focuses on helping credit card holders get the best discounts by offering them instant searching service with which they can easily search for credit card information on the spot.\nIn our 2B division, we adopt the search engine developed by cardbo to assist digital sales channels sellers optimizing user experience on their platforms, increasing their shopping carts’ conversion rate.', 'https://www.cardbo.info/', 13580),
  ('2020', 'SAT. Knowledge', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/10/SAT_Logo_776_386-2-Yu-Stephen-e1603360425770.png', 'SAT. Knowledge 衛星知識，希望能透過網路科技，將知識傳播到每一個有需要的角落。 在知識日新月異的現代，傳統的教育方式已經無法滿足新型態工作者的學習需求；SAT. Knowledge 要改變過去人才培育的方式，改變台灣的教育； 希望透過 SAT. Knowledge 的努力，讓每一個在這塊土地的年輕人都可以被「賦能」，在世界的任何一個角落都發光發熱。 各產業的專業知識內容，經過 SAT. 的把關篩選後，可以用多元的傳播形式，如「文字」、「聲音」、「影像」、「線上面對面」等形式，傳播給任何有需要的學習者。', 'https://sat.cool/home', 13580),
  ('2020', 'Goodie APP', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/10/2020_聯經_GoodieLogo-Ramos-Chang-e1603360296695.png', 'Goodie- 好友間的推薦社群APP。 用戶可以更快速直覺的建立自己最喜歡的 影集/餐廳/音樂/書本 口袋名單，更可以瀏覽/收藏/推薦 好朋友的口袋名單。 在Goodie, 不只能透過好朋友，找到生活中的好推薦， 也建立更多好友間的共鳴。\nSTOP relying on reviews from strangers online! Let your friends help you out to find out what fits your taste. Goodie is a seamless, and personal way of finding great series, books, musics, restaurants. Simply by recommendations from your best friends.', 'https://www.imgoodie.com/', 13580),
  ('2020', 'AR虛擬世界平台 維爾歐德', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/02/2021_台商資源國際_維爾歐德logo-werold-studio.png', 'AR世界是一個基於真實世界地理座標及空間位置與現實融合的虛擬世界，我們期望透過「AR虛擬世界平台」使民眾日常使用網路通訊與科技的習慣如社群和商業行為能夠無縫地轉移至AR世界中，達到虛實融合及展示互動的生活共享體驗。它是一個世界、也是個終極的平台，包含不同的風格、區域，有故事的體驗、也有遊戲性的享受。\nThe AR World is a virtual world that is based on real geolocation and spatial 3D transformation, parallel to the real world.\nWe hope that through the “AR World Platform” to create, play and share augmented reality, people can seamlessly transfer their social and commerce behaviors to the AR World to extend and share the experience.', 'https://www.facebook.com/weroldgames', 13580),
  ('2020', 'Memorence AI 智能影像辨識系統', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/01/memorenceAI_logo-e1610694855990.png', '智能影像辨識系統/對企業用戶, 解決其作業或生產過程中影像辨識議題,以多元應用場域之AI模型, 助攻企業發展智能化應用系統, 並達到多元效益 1) 提升生產品質與效率 2) 集中式管理數據 3) 降低成本 4) 提高客戶滿意度。', 'https://www.memorence.com/', 13580),
  ('2021', '開吧餐飲顧問股份有限公司 開吧', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/09/開吧_logo.jpg', '渡渡(開吧)是整合台灣餐飲業食材供應的服務，過往一間餐飲店每日叫貨的廠商繁瑣，不只到貨時間不一定，還會浪費許多時間做訂單處理;對於廠商來說也需要在同一地點送多處不同的店家，不只浪費時間和油錢，也需要處理法雜的配送順序。我們希望透過大數據來整理店家和店家之間的叫貨品項與數量，來共同找尋最理想的價錢，在整合供應商的路線來達到雙贏的局面。', NULL, 13575),
  ('2021', 'Coherence Bio Coherence Bio', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/09/coherence1-Cole-S.-Wu.png', '擴核生醫生產基於卡夾式試劑盒的實驗室自動化平台，可實現真正的樣品輸入到結果導出，應用於現場的分子診斷和樣品製備，無需昂貴的大型檢測設備或專業的操作人員。\n', 'http://www.coherencebio.com/', 13575),
  ('2021', '灼灼科技 DLBox', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/09/漸層灼灼中字-縱去背-Jocelyn-Chen.png', '灼灼科技研發之 DLBox ，搭載了深度學習邊緣裝置軟體服務平台 DL Edge Platform，在不需要連接外網的情況下，內建下列功能：\n*執行深度學習技術以預設模型完成影像識別功能\n*讓使用者透過圖形化介面之標註工具，完成新資料標註\n*執行模型訓練功能，客製化深度學習模型\n*更新模型後，執行深度學習技術以客製化模型完成影像識別功能', 'https://www.dt42ai.com/', 13575),
  ('2021', 'InTOL: Intelligent Test Oracle Lab 穎鞱資訊股份有限公司', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/09/螢幕快照-2021-09-22-下午4.06.30.png', '應用程式之跨平台GUI測試解決方案的高效能測試、開發平台、與交流市集', NULL, 13575),
  ('2021', 'fish-ER 魚健康尾環ER與行為監測系統', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/09/螢幕快照-2021-09-22-下午4.11.28.png', 'fish-ER致力於打造全世界第一個「魚」的健康尾環「ER」幫助人們更容易養魚。\n過往，人類僅能間接地監控養殖池的外在環境(如水溫、水質)，無法直接監控魚隻的生理數據，造成養殖存活率低之問題，且需投入大量人力照顧名貴魚種。藉由魚類健康尾環fish-ER，對每隻魚進行客製化即時照顧與活動監測，將能改變全球大型水族館及高經濟價值養殖漁業 (例如黑鮪魚、錦鯉…等)養護技術，省下龐大人力成本與損失。', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13575),
  ('2021', '醫光生技團隊 FINE scope', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/09/螢幕快照-2021-09-22-下午4.06.20.png', '小神經檢測儀', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13575),
  ('2021', 'Takeawayla Takeawayla', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/09/takeawayla_logo-luk-wingsan.png', 'Takeawayla (https://takeawayla.com/)宅食是一個外賣和生活百貨超級搜尋引擎。在平台上用戶可以比較不同餐廳在不同外賣平台的餐單和價錢優惠，也可以比較不同生活食品百貨在不同網購平台的價錢。餐廳可以透過訂閱Takeawayla 的Data Studio 獲取同類型競爭對手在同區域類似餐單的售賣價錢優惠和規律，而做出相應對策。\n', 'https://takeawayla.com/', 13575),
  ('2021', '男孩團隊 會員數位行銷數據分析', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/09/螢幕擷取畫面-2021-09-15-164548.png', '會員數位行銷數據分析，透過銷售系統整合會員做數據分析，經過分眾貼標進行會員精準行銷，透過數據理解會員行為並接下來行銷作為參考依據。', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13575),
  ('2021', '天公伯手路菜團隊 天公伯手路菜平台', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/09/天公伯logo-Chris-Chen.jpg', '天公伯手路菜平台致力於傳統美食的傳承與食譜大數據的收集和變現，結合傳統菜市場與師傅直播拿手在地料理，提供線上預訂熟食外送、常溫調理包和生鮮食材包，服務那些沒時間去市場採購，且買不到適量食材與配方的家庭和個人，甚至是不懂料理的新手，即使在遠端也可以吃到家鄉真正的美味。\n', 'https://tgobay.com/', 13575),
  ('2021', 'Keedle籽樂教育 智能化精準教育系統', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/09/螢幕擷取畫面-2021-09-15-163624.png', '身為老師，我們看到許多的不安，常被問：到底怎麼做對孩子最好？雖然現在人人用手機就能搜尋資訊，但反而更難判斷什麼方法適合自己的孩子。其實孩子的行為都是在訴說著他們需要的協助，家長或老師透過籽樂的「日常精準教育平台」填寫簡單的孩子「情緒行為」、「學習能力」、「學習問題」及「特殊需求」等檢測，智能化模型即會精準分析孩子的特質與需求，配對有效正向教育教養策略，讓城鄉家庭皆能不受時間地點限制，獲得個別化的即時專業陪伴，達到真正由孩子角度出發的「適性教育」理想。', 'https://keedle.org/', 13575),
  ('2021', 'FANSEE 童畫童話', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/09/fansee-logo-鄭富源.png', 'FANSEE 推出的「童畫童話」AR 劇場盒，是一款以提升「閱讀素養」為目標的教學教具，主要將繪本故事轉譯為數位型式，並透過 AR 技術將數位動畫內容擴增在劇場盒上。「童畫童話」透過動手做、聽故事、繪製角色、故事配音等環節，讓學童遍歷聽、說、讀、寫等學習體驗，並進而激發學童的創造力，讓科技不單單只是扮演著補助教育的角色，更是破除物理限制讓學童盡情發揮想像力與創造力的近用載體。', 'https://fansee.studio/', 13575),
  ('2021', 'DakoData Dako', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/09/Dakodata_logo-Ching-Tien.png', '我們正在打造一個新世代的商業分析工具，這個分析平台能弭平數據跟決策之間的鴻溝。人類將能更輕易的整合資料、分析資料，並且從數據中看出洞見。\n我們的團隊使命是賦能從組織到個人，都能夠用數據做出更好的決策！\n', 'https://www.dakodata.com/', 13575),
  ('2021', '智慧價值股份有限公司 AI投資戰情室', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/09/螢幕擷取畫面-2021-09-15-161635.png', '跨域進行AI與數據應用的一站式平台整合開發，包含其相關所需的系統與平台經營專業諮詢，與企業客戶一同打造創新數位管理與會員新經濟生態系。以數據與AI，圍繞會員經營核心，完整旅程的全程監控與參與。\n', 'https://www.aiv.com.tw/', 13575),
  ('2021', '揚揚創新科技 Ctrl A現場控-最佳OMO應用服務', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/09/logo_bg1-YENCHEN-CHU.png', '揚揚創新科技透過創意整合科技及應用流程，讓展演活動「現場」的各個環節需求，都能透過平台所開發的各項服務輔助解決，快速掌握現場狀態並累積應用數據。目前提供策劃活動中「前」、「中」、「後」三階段的應用服務，透過數據掌握消費者喜好，從活動前到活動結束離場，全程抓住現場實況，用數據帶你看見參加者每一步的現場足跡，為品牌、企劃、策展人打通場域體驗與掌握參與者喜好的最後一哩路。\n', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13575),
  ('2021', 'TeaClass查課 TeaClass查課', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/09/logo-炸蝦軟軟.png', 'TeaClass以開發行動應用程式並與各類型開課單位成為合作夥伴，來連接參與課程的消費者，提供線上到線下不同成長階段所適合的課程搜尋服務，打造更優質的教育現場體驗。', 'https://www.teaclass.com.tw/', 13575),
  ('2021', '翻篇Funnpen 翻篇智能導購', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/09/youuxi1024-Ariel-Lin.png', '有戲為一專攻華文演算法智能生成平台的新創公司。三大專利圍繞在智能化內容生成工具的開發，為泛文化和娛樂的內容產業提供內容即服務（CaaS, Content as a Service）的工具平台，提供日漸壯大的UGC（User Generated Content）平台用戶更快速產生具影響力的圖文影音內容。', 'http://www.youuxi.com/', 13575),
  ('2021', '居家整聊室 生活職人媒合平台', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/01/居家整聊室_生活職人平台_logo-Shina-Yang.png', '我們相信 「美好生活選項一直都在，而且人人都可以擁有」\n走進上百個家庭後我們發現，「生存以上，生活以下」是許多台灣家庭所面臨的問題，辛苦工作原本是為了更美好的生活，卻在汲汲營營之中，忘記了怎麼好好的生活！\n居家整聊室，致力於打造台灣的生活職人媒合平台，提供大家更好的生活家居空間！\n\n平台上的「居家整聊師」在台灣是一個全新的職業，是生活的實踐家，是一群對生活有想法有夢想的人！ 我們除了協助整理、局部清潔，更用心傾聽顧客的困擾，希望透過「整理」、「聊天」貼近顧客的生活，進而打造最適合的居住空間。', 'https://www.tidyman.com.tw/', 13575),
  ('2021', 'AIdea AIdea 人工智慧共創平台', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/09/螢幕擷取畫面-2021-09-15-161139.png', 'AIdea是一個人工智慧解題平台，首先評估企業需求確認AI的有效性，經過資料整備、議題設計將需求轉換成AI可以解的題目，公開上架到平台，應用群眾解題的方式，協助企業快速找到最佳AI方案。AIdea平台目前已累積12000位的AI人才，超過50件產業案例透過此平台公開解題，成功累積台灣產業的AI議題庫、資料庫、人才庫。\n官網：https://aidea-web.tw/', 'https://aidea-web.tw/', 13575),
  ('2021', '爾科 ERRK 爾科智能健康助理', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/09/爾科-LOGO-去背檔案-Ching-Chen.png', '爾科智能健康助理的雲端健康服務，聚焦於數據驅動的客製化慢性疾病預防管理，與健康服務工作流程的數位自動化基礎建設，藉由提供客戶數位勞動力與新型態互動模式、改善健康服務提供與接收雙方的體驗，提升健康體系效能、為醫病雙方創造永續的價值。', 'https://www.errkhealth.com/', 13575),
  ('2021', '思惟睡眠科技股份有限公司 數據可驅動可複製睡眠中心(Data-Driven Scalable Sleep Labs, DSL®)', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/09/螢幕擷取畫面-2021-09-15-155757.png', '我們團隊將致力於打造全球睡眠醫學界的 Uber 平台。建立數據可驅動可複製睡眠中心(Data-Driven Scalable Sleep Labs, DSL®)，能解決廣大睡眠障礙者無法接受適當治療的問題，並改善睡眠障礙者長期濫用安眠藥物問題。病患在家即可進行居家睡眠檢測，並透過線上看診進行後續治療，搭配個人虛擬護士VPN長期追蹤慢性病管理的照護。', 'https://www.sleepwell2.com/book-online', 13575),
  ('2021', 'KOLABLE KOLABLE', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/02/2021_x_KOLABLElogo-徐愷.png', '我們是一群內容創作者，從2012年開始經營內容，試過了各式各樣的平台，像是Facebook、YouTube、Twitch、Accupass到Hahow等，每個平台都只能完成特定的功能，發現都沒有一個能夠整合各種功能的平台，而對於內容創作者來說，能夠彈性的組合適合粉絲的方案是非常重要得！於是我們著手開發了KOLABLE，希望透過這個系統幫助KOL更加抓緊粉絲，不但可以提供給粉絲更多服務，還能放大內容價值。\n', 'https://www.kolable.com/', 13575),
  ('2021', 'GOROX 3D全彩與多材質列印混鍊機', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/09/螢幕擷取畫面-2021-09-15-153600.png', '我們的產品能讓所有的 FDM 3D列印機都能用一個噴頭做到全彩與多材質3D列印，不需改裝機台或用特殊昂貴的耗材。', NULL, 13575),
  ('2021', '健康盟 DigiMed', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/09/健康盟_LOGO標準字中英-王文利.png', '健康盟主打秒懂健康影音內容，透過秒懂的內容讓病人從進入候診間TV到看診離開醫療院所所發送的內容，都可以隨時清楚知道自己看診所需的醫療資訊，並透過DigiMed平台可以隨時醫病溝通，解決醫療人員沒有太多時間溝通等問題，讓病人清楚自己所需要的資訊，以利下次回診跟醫師溝通，並減少醫療糾紛問題。\n', 'https://www.healthleaguex.com/', 13575),
  ('2021', '醫淬思股份有限公司 醫療社群顧問與商轉平台', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/09/螢幕擷取畫面-2021-09-15-154801.png', '醫淬思股份有限公司由嫻熟社群經營的醫師、醫學專家們創立，初心是希望用大眾易懂的方式，傳達正確的醫學觀念以及知識。資訊不對等是醫療人員、民眾、機構的三方溝通硬傷。若大眾沒有良好的觀念基礎，就無法有效進行醫病溝通，也容易誤信偏方和不實廣告的產品。\n醫淬思匯聚醫療KOL切入市場，目前已是台灣最大醫療社群聯盟，超過60位醫療社群意見領袖加入，總計粉絲超過150萬，包含醫師、牙醫、中醫、藥師、營養師、護理師、治療師和諮商師等。藉由社群衛教、期刊科普促進民眾健康識能，與值得信賴的品牌和醫療機構合作，提供民眾值得信賴的健康資訊與轉介平台。\n\n成立以來醫淬思已成功與國內外優質品牌、機構與醫學資訊提供者合作，與全球最大的期刊出版社Elsevier合作podcast論文期刊導讀、台灣最大的健康媒體康健策略合作文章投稿刊登。與國內外知名品牌跨界合作，例如：統一企業、呂RYO、Kielh’s、橘子工坊、台新Richart等。\n\n醫淬思獲得多項新創獎項殊榮，包含：台積電青年築夢計畫、U-start 創新創業計畫、台大創創加速器，獲得台灣大學的投資入股。醫淬思希望能在未來建構出三方（醫療人員、民眾、機構）共創多贏的醫療社群，啟動醫療資訊效率，消弭醫療資訊不對等，實踐醫療普惠無遠弗屆。', 'https://www.facebook.com/Mediterest', 13575),
  ('2021', 'HolyBug 遊戲卡牌鑑定與交易平台', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/09/Holy-Bug_Logo-With-IP-蔡曜隆.png', '寶可夢遊戲卡牌於全球風行20多年，2019年開始在台灣成為小朋友與大人共同比賽、交換、交易的話題，並且呈現指數型的成長，本計劃在成立一個包括教育學習、競賽、卡牌交易與鑑定平台，讓台灣的卡牌遊戲環境更安全與健康。', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13575),
  ('2021', 'Slash studio C.C.S. 計畫', 'https://tec.ntu.edu.tw/wp-content/uploads/2022/03/Logo_1024-studio-slash.png', 'C.C.S.計畫（Circular, Container, System）目的是打造一個循環容器系統，以循環設計為核心的產品開發策略，確保容器的設計有利於回收。讓被淘汰的產品透過循環供應鏈再重新回到市場，建立起材料的循環模式。', 'https://www.facebook.com/slashstudio2020', 13575),
  ('2021', '杯特 uCup永續杯平台與AIoT感測創新清洗系統', 'https://tec.ntu.edu.tw/wp-content/uploads/2022/03/杯特.png', '小小的台灣島慣於免洗用具，一年製造出超過15億的免洗杯垃圾！製造這些一年就排放超過450萬公斤的二氧化碳！但自備環保容器，對於大部分的人來講又是極為困難的事情，因此杯特團隊希望提供一個輕鬆做環保的新選擇！不用帶杯子出門也能隨時租借環保杯，不用自己清洗""也能在使用後能隨時歸還！\n不是免洗杯，卻跟免洗杯一樣方便！', 'https://www.facebook.com/Cup.Rental.System', 13575),
  ('2021', '安彼企業 中小企業成長平台', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/09/螢幕擷取畫面-2021-09-15-121235.png', 'IMB種小企業成長平台\n互聯網技術與APP\n讓中小企業主完成自己的\n商業企畫書，再進行演算法提高訊息效率，\n給出企業主最適合之資訊\n讓原有的企業社交數位轉型、遠距離、低接觸\n是配合疫情期間最適合的企業主社交模式\n', 'https://imb-business.com/website_publicV', 13575),
  ('2021', 'RemoteNC RemoteNC 雲端加工專家系統', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/09/20200503-remoteNC-logo-vert-01-1-Beatrice-HU.png', 'RemoteNC 雲端加工專家系統，是針對少量多樣 CNC 加工廠打造的製程運算服務，透過雲計算大幅降低工廠製程管理的負擔，並搭配 (1) 稼動率監測功能、(2) 可在行動裝置檢視的作業流程可視化軟體，能有效找出工廠運行的瓶頸，優化 CNC 銑床的稼動率。', 'https://www.remotenc.com/', 13575),
  ('2021', '聚星聯網 聚星聯網方案', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/09/1629184964003-Aryan-Hong.jpg', '整合分散節點網路、端對端直連加密傳輸技術，和自有研發成果，搭配雲端系統進行商務管理、設備管理和文檔管理等事宜，成為聚星聯網方案，提供企業能遠距執行互動式商務的影音通訊能力，現主要面向金融業者;其功能核心打包為軟體開發套件(SDK)，可讓智慧型終端業者置入產品中，提供使用者遠距影音通訊功能。', 'https://www.ihh.tw/', 13575),
  ('2021', '精拓生技 EVA Select', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/09/螢幕擷取畫面-2021-09-15-113817.png', '精拓生技致力於循環腫瘤細胞（CTCs）的應用，開發更具競爭力與個人化的抗癌藥物檢測服務(EVA Select)。目前的癌症治療是基於標準治療和醫生的經驗，但個體差異使治療方法對每個病人的效果不同。透過我們的服務，醫生將了解藥物對患者癌細胞的實際效果，並根據患者的情況進行治療，減少患者以身試藥的風險，降低潛在無效用藥的風險和成本。', 'https://www.cancerfree.io/', 13575),
  ('2021', 'NanoParma SeraParma COVID-19 IgM 快篩檢測試劑、AirParma 新冠奈米盾', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/09/螢幕擷取畫面-2021-09-15-114321.png', '臺灣納諾帕瑪公司以奈米創新科技，發展出針對新冠病毒的「SeraParma™ COVID-19 IgM 快篩檢測試劑（專案製造取證中）」，具有安全、準確、便利的特性，簡單三步驟，僅需一滴血、20分鐘即可得知檢測結果。可以同時解決PCR核酸檢測的檢驗人力不足，以及目前市面上快篩高偽陽高偽陰的雙重困境。\n【241例檢體：敏感度：100%，專一度：100%】\nSeraParma™ COVID-19 IgM 快篩檢測試劑較市面上快篩敏感 1,000 倍，與PCR核酸檢測比對的 241 筆臨床檢體，結果一致性達百分之百，臨床檢體驗證結果為零偽陽、零偽陰。\n奈米分子放大訊號的創新技術，讓檢測極限表現更好、敏感度更高，可測得無症狀感染者或感染早期者（症狀出現後 1-7 天內），有效的達到「早期篩檢」，以協助評估患者是否遭受新冠病毒感染。改善目前市面上快篩無法早期篩檢的新冠感染篩檢困境。\n同時也開發出「AirParma™ 新冠奈米盾」，為全球首創可以處理新冠病毒空氣傳播的防疫品，霧化後可與空氣中的新冠病毒用於感染生物體的棘蛋白結合，並使病毒沉降。\nAirParma™新冠奈米盾不受新冠病毒變異影響，AirParma™是模擬生物體的 ACE2 受器，和新冠病毒感染用的棘蛋白結合，而病毒的變種是為了ACE2結合得更好、更有機會感染生物體，因此變種病毒反而會和 AirParma™ 結合更緊密。\n\n秉持著加速世界重返安全生活的初衷，NanoParma™團隊期盼能為降低疫情擴散盡一份力，專注在發展強化每個人防禦病毒能力的產品，並且所有抗疫產品堅持 MIT 臺灣研發、臺灣製造，將臺灣研發的產品推向國際舞台，讓世界看見臺灣。', 'https://nanoparma.com/', 13575),
  ('2021', '配客嘉股份有限公司 循環包裝服務體系', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/01/PackAge-配客嘉股份有限公司-logo.png', '配客嘉期望提供通路與消費者更環保友善的消費選擇，台灣每年因為數位的購物方式產生數億件的一次性包裝垃圾造成環境嚴重的傷害，期望未來透過我們的包裝循環模式，能夠讓包裝以共享租賃的方式在電商、消費者與歸還通路之間可以不斷重複循環使用，來減少紙箱破壞袋等包裝垃圾的浪費。\n', 'https://www.packageplus-tw.com/', 13575),
  ('2021', 'AITM Molecular Pocket Doctor (Mo-Po-Doc)', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/09/螢幕擷取畫面-2021-09-15-111742.png', '我們將發展移動醫學（精準免疫荷爾蒙定量快篩試劑，結合AI與物聯網的生醫儀器系統）來分析女性體質個體差異及解決現代人亞健康問題，提供個人數位醫療處方籤。', NULL, 13575),
  ('2021', '孚創雲端股份有限公司 Patent Search, Patent Vault, Design Search, Due Diligence, Quality Insights, SEP OmniLytics', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/09/螢幕擷取畫面-2021-09-15-112814.png', '孚創（InQuartik）是一家致力於發展人工智慧技術，並專注於專利情報的軟體即服務（SaaS）供應商。過去專利無形資產的價值難以衡量，我們應用大數據及人工智慧，讓每件專利可透過一統一的標準來衡量其品質（可專利性）及價值（貨幣化潛力）。除此之外，我們設計簡易上手但功能強大的專利資料檢索平台、線上協作平台、適用於專利訴訟的前案檢索解決方案、專利盡職調查解決方案及標準必要專利現況儀表板。', 'http://www.inquartik.com/', 13575),
  ('2021', 'AIPLUX LOFA', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/09/1629681395509-Alfred-Wu.png', 'AIPLUX是一個透過智慧財產權(專利商標)為核心，並運用創新的IT/AI技術，提供全球唯一跨國、跨語言、節省傳統申請的多國商標線上申請平台，而我們的產品透過結合申請評估系統和 AI 推薦，讓跨境商標申請變得輕而易舉。\n用戶可以直接在5分鐘內提交多個國家的申請，並節省70%的服務費。', 'http://aiplux.com/', 13575)
INSERT INTO historical_startups (year, name, logo_url, description, external_link, source_post_id) VALUES
  ('2021', 'Crypto-Arsenal Automated SaaS Crypto-Trading Platform', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/09/2021_車庫_Crypto-Arsenal_logo-Li-Richard-1.png', '奇策智能雲端致力於建構加密貨幣量化程式交易平台，打造新一代智能交易機器人開發、媒合與自動執行跟投的雲端服務，對接各大加密貨幣交易所，支援雲端或本地端策略開發環境、即時回測、實時模擬、實盤交易、計算績效指標與視覺化圖表等功能。容器化架構與管理，動態分配算力給每支獨立交易機器人，有效降地交易延遲。透過策略競賽排名有效媒合策略與交易者，利用 Split-As-You-Profit 模型和 Smart Contract 達到「先儲值執行策略，後獲利再分潤」的創新商模，將策略開發者與交易者權益最大化;代幣回饋與交易競賽挖礦機制將利潤與平台上客戶共享，可有效獲客與留客並創造互利共生的加密貨幣量化交易社區。', 'https://crypto-arsenal.io/', 13575),
  ('2021', 'thingnario Photon', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/09/螢幕擷取畫面-2021-09-15-105154.png', '以IOT與AI為核心（AIoT)，用SaaS的模式，提供各行業所需的軟體服務，目前先致力於再生能源行業。我們的智能軟體服務，將大量不同地點的再生能源資料整合處理（如太陽能或風力發電站），提供不同角色所需的資訊能見度，並透過ＡＩ降低假警報並提供有效建議，以確保發電效率，降低維運成本，提高整體維修效率。\n', 'http://www.thingnario.com/', 13575),
  ('2021', 'FooSpace 自由食間', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/09/freezone-logo-combination-01-Jason-Wang.png', '「自由食間」致力於發展OMO智慧新零售，用創新科技為零售市場帶來下一個顛覆 。', 'http://www.freezone.com.tw/', 13575),
  ('2021', 'LAPSEE萊剖析 媒體素養教育教材、相關影片', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/09/LAPSEE去背-許晴棻-Beverly.png', '「思考是起點，自由是終點，一起找出媒體中的魔鬼。」現今，網路為假訊息最大的溫床，媒體識讀成為不可忽視的教育課題。LAPSEE致力於推廣兒少媒體素養教育，藉由產製媒體素養教材，及舉辦營隊課程，增進孩童的媒體識讀能力，使身處於資訊爆炸時代的孩童，擁有一雙看見世界真實樣貌的眼睛，具備查證資訊的能力，成為主動的媒體公民。', 'http://lapsee.org/', 13575),
  ('2021', 'BioFlow 可移動式氣流阻隔手術裝置', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/09/螢幕擷取畫面-2021-09-15-103500.png', '新型冠狀病毒肆虐全球，目前緊急手術的執行在病毒檢測結果未知下，手術人員根據指引皆需穿著全套PPE裝備、且僅能於負壓手術室中執行。我們欲製作一能建立空氣阻隔層之可移動式手術裝置來補足負壓手術房的不足，透過氣流的設計將手術台內病患空氣與外界隔絕，不僅能降低手術人員及病患感染的風險，更能大幅增加手術的可及性，創造雙贏的局面。', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13575),
  ('2021', 'PICK （a cross-functional team from Blue Planet Inc.） PICK', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/09/pick-logo-吳佩軒.png', 'PICK是運用語意分析技術整合各大社群論壇商品評價資訊，並串連用戶完整消費行為歷程的評價導購工具；一方面協助消費者解決多平台間跳轉查詢評價的不便，另一方面透過C端數據的搜集分析，協助企業掌握消費者購物前的關鍵決策行為，進而精準定義用戶畫像及判斷廣告通路特徵，期能彌平數據斷層、成為未來數據運用的新解方。\n', 'https://www.blueplanet.com.tw/', 13575),
  ('2021', '鳴天設計 E-YES兒童弱視訓練器', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/09/鳴天設計logo-Zeal-Design.png', '鳴天設計致力於改善兒童弱視的遊戲型輔具，透過組合各式AR情境模塊來創造具探索與訓練價值的遊戲，以進行眼部肌力與辨色訓練，並以視力檢測遊戲模塊來追蹤兒童視力變化。', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13575),
  ('2021', '二拾衫 二拾衫', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/09/TwentythreeLogo-T-Oscar.png', '如果你敢使用五星級飯店經過清洗的「二手毛巾」，那你就也一定敢穿著乾淨的二手衣物。以中心化的二手衣物販售平台取代原本買賣家直接交易，我們將二手衣物統一消毒上架，當二手衣物市場中的「五星級飯店」。', 'https://www.twentythree.com.tw/', 13575),
  ('2021', 'CyHorus CyHorus', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/09/螢幕擷取畫面-2021-09-14-172134.png', 'CyHorus 是一個提供資安服務的 SaaS 平台。在不影響企業服務下，進行 24/7 持續式攻擊模擬。我們是台灣第一個專為混合雲與 Kubernetes 環境的攻擊模擬平台，提供嶄新操作體驗與專業修復建議，無需專業資安背景，即可模擬駭客入侵，讓企業隨時驗證破口、評估風險、強化資安。', 'https://www.cyhorus.com/', 13575),
  ('2021', 'Petit小劇場 暑期戲劇營隊', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/09/Petit-logo-陳希涵.png', 'Petit 小劇場致力於解決臺灣教育下孩子「缺乏學習動機」的普遍困境，協助每個孩子在自我理解的過程中，尋找自我的人生價值及熱忱。我們的工作坊主要提供給正值人格發展期的國三生，希望在人生最重要的轉變期放入反思的種子，改變未來的探索藍圖。\n劇場工作坊融合創作性戲劇與未來思考的架構，設計出寒暑假、假日、線上等沈浸式課程，藉由納入創作性戲劇「即興」的元素，在開放的環境中體驗活在當下、展演內在情感，並在營隊最後以成果展「十年後的自我」，進一步探索自我的人生使命。\n\n從 2021 年開始，Petit 已累計辦理4場實體活動、1場線上活動，影響超過50名青少年和大學生，未來規劃建立可規模化的活動模式，從台北拓展到全台灣。', 'http://petit-dramaturgy.com/', 13575),
  ('2021', 'Circle by Circle Circle by Circle', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/09/Circle-by-Circle-Logo_1024x1024-Erin-Yang.png', '我們相信每一位父母與孩子都值得擁有正向且有趣的的親子關係與體驗。Circle by Circle 是一個教育創新團隊，以蒙特梭利啟發（Montessori-inspired）與孩童發展為核心，提供0-3歲分段年齡的訂閱制教育意義型教具體驗盒（educational play kits）以及給家長的會員制內容與講座。並以數據與AI技術應用，旨在提供更為客製化的推薦內容與產品體驗。', 'http://www.circlebycircle.com/', 13575),
  ('2021', 'Spersor', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/09/logo-b101105035-TMU.png', '這是一項能讓男性更加了解自身健康狀況，並進一步進行自主管理的產品。透過醫學專業與智能的結合，讓男性進行飲食生活作息等調整時，能藉此來觀察身體健康的變化。這項產品以改善現有檢測流程為出發點來進行設計，我們期待能為男性帶來更多元的健康管理方式。', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13575),
  ('2021', 'EZ學習歷程 申請大學備審一站式製作平台', 'https://tec.ntu.edu.tw/wp-content/uploads/2022/01/高中生資訊網新logo-e1643006973432.png', '提供一站式學習歷程（升大學備審）製作平台，協助高中生有系統性地打造獨一無二的學習歷程，並成功錄取頂尖大學、理想校系。\n', 'https://ezcv.tw/', 13575),
  ('2021', 'Workfe工作咖啡 咖啡廳即時資訊應用軟體', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/09/螢幕快照-2021-09-22-下午1.14.07.png', '近年遠距工作蔚為潮流，因此工作場所的品質格外重要。但目前的咖啡廳時常客滿或環境不符合顧客需求。Workfe應運而生，幫助顧客尋找有空位且環境符合需求的咖啡廳。Workfe提供店家的即時空位率;獨創的#Freetag系統，可讓使用者認同或新增特色標籤;社群機制讓使用者看見他人或店家的貼文分享。Workfe讓使用者找到適合的咖啡廳，也增加店家曝光率。', 'https://www.workfe.app/', 13575),
  ('2021', 'PISTA Osprey', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/09/螢幕擷取畫面-2021-09-14-155308-2.png', '以核心技術的數據驅動之異常檢測和預測,應用在跨產業之 AIOps與企業之AIoT，與商業或製造流程中決策輔助', 'http://www.pista-tech.com/', 13575),
  ('2021', '賽神仙 Prediction in cancer patient by using big data approach', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/02/2021_車庫_台大創創logo-Bryan-Lee.png', '利用檢體分析並進行數據整理，以提供醫師能更精準對於病人在攝護腺癌的治療、監測的策略採用，以達到降地醫療成本支出與精準化醫療的目標。\n', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13575),
  ('2021', 'Vetech Vetty', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/02/2021-02-24-2.png', 'Vetech致力為毛小孩提供全方位的健康保障，同時協助獸醫產業數位化，建立一個寵物醫療訂閱平台-- Vetty。提供包含健康檢查與建議、常見小病醫療、老年重病醫療等獸醫院的專業醫療服務，給有需求的寵物飼主選擇訂閱。', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13575),
  ('2021', 'PeekurFinance PeekurFinance', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/02/Screen-Shot-2021-02-09-at-10.32.52-PM-Wenyn-Wang.png', '人工智慧技術與Open Data的智能引擎 -- 深入信貸徵信、資產管理場景為金融業量身打造多種解決方案。', 'https://peekurfinance.com/', 13575),
  ('2021', '彼利數位資訊股份有限公司 Wholive 誰住我家', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/02/2021_玉山銀行_彼利數位資訊logo-chuan-yi.png', '「彼利數位資訊」致力於打造房東與租客間的服務平台，2020年推出「Wholive 誰住我家」APP，以「租客/房東評選」作為主要功能，其後陸續推出「帳務管理」、「租屋經驗提報」、「租屋良民證」、「法律諮詢」等租屋相關服務。2021年計畫與金融業合作，透過結合金流，使收繳租金線上自動化，持續深耕打造租屋產業2.0。\n', 'http://wholive.com.tw/', 13575),
  ('2021', '歐姆佳科技（周錫增教授價創計畫） Ohm plus fast 5G毫米波快速校正系統', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/02/螢幕擷取畫面-2021-02-24-143043.png', '5G毫米波快速校正測試系統', NULL, 13575),
  ('2021', 'Astron Medtech (TendMIN) Maxtend', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/02/2021-02-24-6.png', '肌腱斷裂傳統手術的大傷口造成高併發率以及漫長術後復原時間，其併發症(感染及再斷裂)會增加150%-200%的額外醫療支出，艾斯創生醫致力提供創新肌腱微創解決方案，團隊開發之微創手器械組可將手術傷口縮小10倍，並將術後復原時間由6個月縮短至4個月，於每次手術幫助病患節省1280美金。', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13575),
  ('2021', 'Meshub', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/02/台灣網格技術有限公司Meshub-Ka-Kin-Kevin-Wong.png', '目前傳統的網絡服務商和大型公有雲服務商都沒有直接去解決網絡架構問題，因為要改變或增設網絡架構需要非常大的成本和非常多的時間，他們過去10年都是用比較高成本的中心化邊緣計算去嘗試解決問題，但這方法只解決了國家與國家之間的網路塞車問題，沒有解決到本地傳輸數據增長迅速遇到的問題。\n因為互聯網從1.0到2.0都是以中心化的架構去構建，要到3.0的去中心化和萬物聯網還會需要一段時間和革命性的改變。\n\nMeshub開發的軟硬件整合方案，透過分散式的邊緣計算網絡去提供解決方案。我們使用分佈式邊緣計算CDN網絡進一步降低了高達90％的數據傳輸成本。 為了避免直接與雲服務競爭，我們的系統還可以部署在任何雲服務上，因此我們可以相對更低成本輕鬆擴展網絡到全世界。', 'https://www.meshub.io/', 13575),
  ('2021', 'ZIMA Inc.', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/02/談談科技股份有限公司_台大創創LOGO-Wang-Jennifer.png', '連結Right here, Right now, 在酒吧/咖啡廳裡閒著、可以聊天的人。同時用自己的社交數據養成社交分身(Social Sidekick) 幫你去除社交隔閡，滿足你的社交需求。', 'http://zima-tech.com/', 13575),
  ('2021', '陳宏銘教授科技部價創計畫擴增實境之光場眼鏡 Light Field AR Glasses', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/02/2021-02-24-5.png', '開發輕薄短小的光學模組，直接投射光場於視網膜，產生自然舒適、虛實融合的AR/VR體驗。', 'http://www.petaray.com/', 13575),
  ('2021', 'UpperMed PD Care', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/02/2021-02-24-4.png', 'UpperMed是一間新加坡設立的數位醫療新創，旨在透過科技協助改善腹膜透析患者的生活。透過我們開發的家用洗腎管理系統，能有效增加腹膜透析普及的可行性，改善患者的生活同時也能降低醫病溝通成本。\n', 'http://www.uppermed.com.sg/', 13575),
  ('2021', 'LaVida Tec. WaCare遠距健康', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/02/WaCare-logo-5加7是Cheryl.png', 'WaCare是串聯健康專家與親友的關懷網路，透過AI推論引擎、機器學習演算法與自然語言分析，整合個人病歷、政府開放資料、穿戴式裝置，實現個人行為塑模與健康風險預測，並透過主動式風險警示誘發線上諮詢與關懷行動，及早抑制風險發生。\nWaCare同時亦是健康專家的行銷工具，提供專家品牌曝光、健康服務推廣，實現導流集客、個案管理的目標。\n我們發展資料工程與數據科學核心，以實際行動實現預防醫學(Prevention Medicine)與個人健康促進（Health Promotion），將全球醫療健康專家透過WaCare串聯到世界各個角落，透過精準掌握個案健康脈絡與風險預測，自動依據專家專長媒合最適諮詢對象進行線上健康諮詢，以全球化尺度實現全人照護(Holistic Health Care)目標。\n', 'https://www.home.wacare.live/', 13575),
  ('2021', 'hunger夯客', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/02/2021_加速器_hunger夯客logo-王嘉宏.png', 'hunger 夯客專注於美髮美甲、瑜伽健身等美學產業，提供預約管理、會員系統、數據分析與再行銷工具，協助美業產業數位升級，進而提升商家營運效率創造顧客忠誠。\n', 'https://hunger.ai/', 13575),
  ('2021', 'MOM&DAD 媽爹講故事', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/02/2021_台大創創加速器_媽爹講故事logo-Avery-Hua.png', '"媽爹講故事"是由網紅MOM&DAD創立，專門給孩子講睡前故事的品牌，我們針對2--12歲的孩子，致力打造”快樂，成長，互動” 的優質兒童內容，2020拿下Apple Podcast 兒童與家庭類排行榜第一名，網友譽為 ”上萬家庭都愛用的育兒神器”。\n', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13575),
  ('2021', '澔心科技 胎兒暨嬰幼兒智能照護服務 Fetal & Infant Care System', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/02/SiriuXense_Logo-01-Ruby-Hung.png', '澔心科技致力打造「全年齡智能照護生態系」，透過融合感測技術及演算法服務，搭配物聯網穿戴裝置，將前沿感測技術微型化搬入家中；以結合臨床意義的服務模式，以安全非侵入、連續、客觀、高精準且符合人體工學的裝置與服務，讓無微不至照護融入生活之中。產品服務涵蓋了孕期胎兒暨嬰幼兒感測、青少年哮喘連續趨勢、銀髮長期照護等。\n', 'https://www.siriuxense.com/', 13575),
  ('2021', 'Giftpack', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/02/EnterpriseLogo-Corner-Archer-Chiang.png', 'Giftpack 是一個以人工智慧為基底的企業送禮平台，我們將難以大量客製化每個禮物的痛點透過技術轉換成彈指之間的事，在極短的時間可以透過資料分析在全球超過上百萬件的商品中替您數以萬計的收禮者都找到最適合的禮物並且寄送到全世界各地。\n', 'https://giftpack.ai/', 13575),
  ('2021', 'Applato 智慧健康餐點推薦及飲食管理系統', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/02/2021_台大創創加速器_ApplatoLogo-Yen-Chen.png', 'Applato專注於提供餐飲業者智慧化健康餐點推薦系統，並打造個人專屬的健康管理平台，由營養師根據各種需求，提出客製化的餐點建議與陪伴，讓每個人都可以生活得更健康。', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13575),
  ('2021', '綠冠農業有限公司 鳳梨葉衍伸產品', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/02/pinacell01-b-Max-Chang.png', '鳳梨葉屬於農業副產品，且衍伸的用途十分廣泛。一般鳳梨在收成之後，往往任由農民堆砌田間或是清運燒毀而產生額外的經濟成本和環境成本。國際上關於鳳梨葉應用的研究隨著環保意識的抬頭，也越來越普及，但大多仍停留在早期產品概念測試的階段。\n我們整合了台灣製造與研發產業相關的資源，讓鳳梨葉的相關應用從論文實現到了商業化的領域。除了克服鳳梨葉取纖量化的問題，也與紡織研究所共同合作，讓鳳梨紗相關的產品從精煉、開纖到織布一貫化的進行了整合。完成了東南亞國家過去十年一直無法突破的量產問題。此外，鳳梨葉渣的衍伸應用，我們也逐步與國內塑膠產業合作，在減塑與可分解兩個方向上持續開發能夠帶給社會附加價值的產品。同時，更與國內尖端的紙廠進行渣料纖維素奈米纖維的相關實驗，讓草本植物萃取的質量逐步追上，甚至領先國際上的木漿奈米纖維素萃取。\n\n＂Taiwan can help ＂是我們的信念。台灣的知識經濟與產業整合能夠為這個世代所面臨的溫室效應、碳排放與減塑目標等帶來實質且持續性的貢獻。我們來自於田間，但我們站在台灣厚實的產業實力基礎上，選擇以鳳梨葉原料為切入點，期能為這個地球帶來更好的明天。', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13575),
  ('2021', 'ZERO BOTTLE 純淨洗髮露', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/02/2021-02-24.png', 'ZERO BOTTLE是一項循環瓶器服務，透過容器用畢歸還、再填充販售，減少一次性塑膠垃圾。目前推出ZERO BOTTLE純淨洗髮用品，採用動物友善、植物性清潔因子，已於十多家據點販售與歸還。未來將擴及沐浴露、個人清潔保養品等更多產品，希望透過循環容器，提供注重環境友善、奉行減塑生活的消費者一個新選項，創造時尚環保的生活風格。', 'https://www.zerobottletw.com/', 13575),
  ('2021', '凡立橙股份有限公司 ECOCO循環經濟', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/02/2021-02-22-6.png', '"因為想為這片土地做點事，盼望孩子成長的城市更美好，我們從家鄉台南出發，以輕鬆、有趣的方式推動民眾的環保行動。\n2018年開始，ECOCO推出整合環保、點數折抵消費或愛心捐款、資收物再生技術與設計等多面向的平台，結合ECO與COin之概念，實踐資源再生、永續發展的理念。"\n', 'http://ecoco.xyz/', 13575),
  ('2021', '茶茶團隊', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/02/2021_台商資源國際垂直加速器_茶茶團隊logo-茶茶.png', '茶茶是業界唯一在 GMP 食品工廠製造、以 100% 食品級材料製成的清潔用品，能夠取代化學清潔劑，分解油污的效果極強，讓人們輕鬆擺脫化學毒素與致癌物質的侵害。可用於洗碗機 (dishwasher) 或用於手洗洗碗，適合歐美及亞洲市場。跳脫傳統清潔劑的零售思維，以「訂閱全家人的健康」為商業模式，將茶茶定位成「健康生活風格品牌」。', 'https://www.chachawash.com/', 13575),
  ('2021', '捷思博科技, JetSparq Aimpfly，AI智造影像辨識平台', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/02/2021-02-22-3.png', '捷思博科技 JetSparq，專注於打造 AI 智慧製造的應用服務- Aimpfly（AI智造影像辨識平台），透過核心技術智能影像辨識，結合雲端運算服務、將製造業所需資料連網，並導入自動化數據分析，解決製造業缺工、缺技術的困境。我們的服務，能夠提升客戶產品良率，並能夠大幅降低人力負擔，提升台灣製造業的競爭力。\n', 'https://www.denseinsight.com/', 13575),
  ('2021', 'Energy-Craft 異質訊號AIoT Gateway', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/02/2021-02-22-2.png', '為企業或個人客戶提供客製化太陽能設備機電整合系統或產品設計開發的服務，專精於PC Base控制介面的自動化系統與各式感測器整合性開發。企以「異質訊號AIoT Gateway」協助傳統製造業進行設備轉型，達到工業3.5~4.0的狀態。', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13575),
  ('2021', '汎思數據 AI 實務所: 數據工程服務', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/02/2021-02-22.png', '汎思數據的智慧製造雲端管理平台，提供產線即時異常監控與AI影像分析、產線大數據分析與異常偵測通報等服務。服務流程包含：諮詢、POC可行性驗證(包含資料採集與AI建模)、AI模型佈署、AI模型維護，解決當前AI落地的實務面問題。現有產品包含：1. 智能讀表, 以AI影像讀取類比指針表取代人工抄表. 2: AI影像瑕疵檢測, 減少自動光學檢測(AOI/AVI)後需要的目檢人力。', 'http://www.ficusdata.com/', 13575),
  ('2021', '超現實科技 Surreal Education', 'https://tec.ntu.edu.tw/wp-content/uploads/2020/02/surreal-edu-logo-徐凡Joanna.png', '超現實科技致力於透過AR/VR來改革教育，我們走在VR創新內容研發的浪尖上，始終秉持著"Learn better in VR"的信念持續在教育界經營推廣，我們期望能藉由VR科技突破現實的框架，以身歷其境的互動體驗詮釋學科知識內容，再透過整合式的線上平台，提供即時性雙向學習，建構出老師與學生對未來學習的想像藍圖，達到翻轉教育的目的。', 'http://www.surreal.com.tw/', 13575),
  ('2021', 'MangaChat', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/02/2021_親子天下_MangaChat_logo-Joe-Huang.png', '我們的產品：MangaChat，是一個專為學校兒童所設計、以插畫為基礎的數位日記系統。透過我們的AI技術，MangaChat可以解析文字中的情緒特性並自動產生對應的漫畫圖格。使用MangaChat可以幫助學童學習辨識情緒，透過角色扮演的情境，以藝術的思維來抒發內在的心情，與表達自我的想法。', 'https://mangax.co/', 13575),
  ('2021', '猿創力程式設計學校 猿創力K12程式素養數位學習系統／Discovery Education Coding數位教材', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/02/2021_親子天下_猿創力程式設計學校Logo-Kennan-Chen-1-1.png', 'K12數位科技素養學習系統\n* 科技教育內容\n* 內容合作：數位科技素養\n* 內容企劃：符合新世代影片風格\n* OMO學習模式\n* OMO學習：線上影片+測驗+線上／線下陪伴作業課輔\n* 使用者資料分析與推薦\n* 收集學習過程的資料：進度、測驗、作業等', 'https://www.codingapeschool.com/', 13575),
  ('2021', 'super方 inspot IG熱搜', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/02/INSPOT-LOGO_工作區域-1-複本-2-Nick-Lee.png', '"去哪玩還在慢慢爬文?Inspot整理Instagram當下最熱門的景點、餐廳等玩樂資訊，有即時分區、分類、排行榜提供當紅景點、打卡熱榜，圖像化直覺操作，用顏值讓你一眼找到今天要去哪裡玩！配上最好用的地圖模式，五分鐘排好兩天一夜行程OK!\nInspot不只是玩樂推薦資訊平台，更是資料分析平台，Instagram甚麼元素最讓人想打卡?從食物設計到主題佈景，開店想要自然流量的秘密讓inspot來告訴你!"', 'https://inspot.fun/', 13575),
  ('2021', '維爾歐德 AR虛擬世界平台', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/02/2021_台商資源國際_維爾歐德logo-werold-studio.png', 'AR世界是一個基於真實世界地理座標及空間位置與現實融合的虛擬世界，我們期望透過「AR虛擬世界平台」使民眾日常使用網路通訊與科技的習慣如社群和商業行為能夠無縫地轉移至AR世界中，達到虛實融合及展示互動的生活共享體驗。它是一個世界、也是個終極的平台，包含不同的風格、區域，有故事的體驗、也有遊戲性的享受。\n', 'http://www.weroldgames.com/', 13575),
  ('2021', '穀米機工 科技藝術與跨領域創意整合', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/02/2021_台商垂直_穀米機工logo-郭人綺-1-1.png', '榖米機工是一個科技藝術跨領域團隊，我們實現藝術家的想像、協助品牌創作有趣的科技藝術作品。我們特別擅長機械動力相關的類別，能夠從軟體、硬體與設計上做出高度整合。榖米機工提供的是基於技術的創意服務，我們會協助客戶爬梳自己的想像、並且針對體驗、藝術性與美學進行深度的優化。', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13575),
  ('2021', 'Amago Trip Amago B2B One-Stop Travel Platform', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/02/2021-02-24-1.png', 'Amago Trip是一個涵蓋了P2P、O2O、B2B、B2B2C和大資料分析整合的一站式、搜尋比價預訂、訂房管理的線上旅遊平台與ERP系統。\n旅遊已逐漸成為現代人的剛需，但旅遊產業存在高度不透明價格和不穩定供應庫存。Amago Trip透過一站式、多元價格方案、動態價格和API串接資源，解決了傳統旅遊售賣者和消費者中間的資訊差異化，為旅行社及企業用戶提供碎片化旅遊產品的即時市場最佳價格，整合資源並分銷至全世界。', 'http://www.amagotrip.com/', 13575),
  ('2021', '酷嗑博士 Cooktor 酷嗑食驗室 Cooktor Lab', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/01/2020_酷嗑博士_台大創創logo-庭瑜-e1611913131292.png', '「酷嗑食驗室」為每一位重視小孩健康的家長，創造更輕鬆的家庭飲食教育模式。我們提供親子料理手作包，以一道料理為主題，透過「繪本、動畫的知識」，使小朋友認識食物的原型、食用後會對人體帶來什麼樣的影響，並結合好吃好玩的「手作體驗」，讓小朋友從採買到烹飪，參與完整料理過程，在家中輕鬆實踐飲食教育。', 'https://www.facebook.com/cook.and.doctor/', 13575),
  ('2021', 'Rosy Face 春色', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/01/2020_車庫_RosyFace春色-shao-en-Huang.png', 'Rosy Face 春色提供新型態調酒服務，致力於將調酒日常化變為可能，讓每一位調酒師與享受調酒的人們之間產生更緊密的連結。享受高品質調酒從此不用再被酒吧所侷限，隨時隨地享受微醺。\n我們將專業調酒師設計的多款高品質精緻調酒，轉化為可外帶的罐裝調酒產品，滿足所有享受調酒的人們。', 'https://www.facebook.com/rosyfaceofficial', 13575),
  ('2021', 'Vitacies Novotech Protein metabolites and enzyme feed supplement', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/02/2021_Vitacies-Novotech_台大創創logo-Aniket-Limaye.png', 'Vitacies Novotech動物營養公司，致力於透過益生菌發酵的方式，客製化的生產高純度的蛋白質和酶，透過這樣創新的方法，不僅可行性高且可打造出多功能性的產品來滿足動物營養市場的持續不段的新需求。憑藉在印度已有認證配方部門和良好的營銷渠道支持，我們的第一個利基市場將會鎖定印度的家禽業市場。我們的第一個即將出口到印度的產品，是由我們其中一位聯合創始人開發的-台灣著名的蝦紅素產品，透過專利益生菌酵母Kluveyromyces菌株生產，可提高免疫力和產蛋量。而我們接下來的工作會專注於取得所有必要的試驗數據、完成產品註冊並開始在印度販售益生菌蝦紅素。除此之外，我們也在開發解毒蛋白（去降解動物飼料中的毒素及有害的真菌毒素）。並會複製蝦紅素的商業模式，將解毒蛋白推廣到台灣及印度市場，將其快速商業化。我們希望透過發展Vitacies Novotech公司，打造蛋白質和其他來源的新型營養產品，並成為從台灣到印度的動物產業中重要通路及媒介。', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13575),
  ('2021', 'INPERSON 年輕人的聚會社交平台', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/02/2021_車庫_INPERSONlogo-蔡侑軒.jpg', '「INPERSON 年輕人的聚會社交平台」以「實體聚會」、「用戶相似性」作為核心出發點，透過遊戲化機制替用戶找到社交理由，進而將相同興趣、相近族群的用戶，以實體聚會作為媒介，從線上串連至線下。\n', 'https://wordpressmu-651819-3104022.cloudwaysapps.com/startups/', 13575),
  ('2021', 'Foodeast 越食煮憶美食互動料理盒', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/02/2020_車庫孵化器_Foodeastlogo-李如寶.png', '台灣目前有超過54萬新住民人口，其中新住民二代的就學人數已高達30萬人。而唯有讓孩子對「自身文化」或「異國文化」有所認識，才有機會消弭因不理解所產生的誤會與社會歧視。Foodeast 就是一顆啟蒙的種子，期盼透過有趣的越食煮憶互動料理盒，讓所有人能夠更加深入了解並尊重東南亞文化，讓台灣國際村變得更美好。\n', 'https://foodeast.jimdofree.com/', 13575)
INSERT INTO historical_startups (year, name, logo_url, description, external_link, source_post_id) VALUES
  ('2021', 'LIMeat', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/02/2020_車庫_LIMeat_logo-Dan-Zheng.png', '透過訂閱制之市面外送平台上平價餐點整理與AI點餐推薦及預算服務滿足外送服務族之深度需求，並使外送平台之行銷預算效益極大化，並回饋部分金額給使用者作為後續點餐費用，進而創造使用者、外送平台、LIMeat三方的共享價值。\n', 'https://www.facebook.com/LIMeatTaiwan', 13575),
  ('2021', '直覺職掘 給國中生的職業體驗營', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/02/2021_台大車庫孵化器_直覺職掘logo-林潤千-1-1.png', '直覺職掘相信「國中」是最適合開始進行生涯探索的階段，因為孩子將在國中畢業前面對第一個生涯選擇。於是，我們為國中生推出以「職業」為中心的生涯教育服務，包含寒暑假營隊及平日工作坊。\n活動以「領域的多元性」及「體驗的真實性」為設計核心。不同領域的職人會帶領孩子用實作、來認識自我及職涯方向。最終，形形色色、沒有設限的職業體驗課，能翻轉教室內的學科階級，點亮每個孩子的潛能。\n\n2017年至今，直覺職掘已累計辦理14場職業體驗營隊、50場單日主題工作坊，70種職業的課程教案，直接影響超過1300名國中生。', 'https://vacationworkshop.wordpress.com/', 13575),
  ('2021', 'FCS Ascelleia氣候智慧平台', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/02/2021_台大車庫_FCS-Jung-Hsuan-Tsao-scaled-e1612158972147.jpg', '聯合國2015年提出17項永續發展目標（Sustainable Development Goals, SDGs），希望透過環境、社會、與治理（Environmental, Social and Governance，ESG）為推動手段，並以2030年為達成目標年。然氣候變遷帶來極端天氣，導致更強與更頻繁的危害，衝擊自然環境與人類經濟社會。為因應氣候變遷必須透過減緩措施減少溫室氣體排放，但為滿足國際與國內溫室氣體管制規範或倡議，會對公司帶來轉型風險；另一方面，極端化的天氣會導致危害變強或產生新危害，暴露在危害下將面臨實體風險。本公司致力於轉譯專業知識與協助客戶將ESG融入客戶公司治理，協助發展減緩與調適措施來降低轉型風險與實體風險，提高客戶競爭力，並以協助客戶追求同業領先為服務宗旨。', 'https://climsmart.com.tw/', 13575),
  ('2021', '好學.問 Q engine', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/01/2020_車庫_好學問logo-Kevin-Liao.png', '我們提供的解決方案是做搜尋題目解答的 Google，讓學生問問題過程簡單、花費少、能在很短時間就得到解答，且解答內容也是學生能吸收的。\n', 'https://howsolve.github.io/', 13575),
  ('2021', '窩聚．共好日常 女性線上療癒助理與線下服務', 'https://tec.ntu.edu.tw/wp-content/uploads/2021/01/2020_女性線上療癒助理與線下服務_窩聚．共好日常-Ansel-Yu-e1611929666676.png', '窩聚 ‧ 共好日常致力於成為最懂女性心理健康的療癒助理。透過線上融合線下的服務模式遊戲設計，心理輔導工作方法，讓身兼數職擔負照顧責任的女性，隨時進行自我照顧與覺察。我們讓療癒變成日常，打造共好社群。\n', 'http://www.facebook.com/moodynowhere', 13575),
  ('2021', 'Kaik Teachify 開課快手', 'https://tec.ntu.edu.tw/wp-content/uploads/2022/03/Kaik21-7-1.png', 'Kaik 開課快手相信每個人身上所握有的知識都值得分享出來，同時，我們相信科技能夠加速知識的流動與傳播，我們期望自己能夠透過科技，協助老師將知識傳遞出去。\n作為一個教育產品，我們專為想經營自己的教育品牌，增強品牌識別的老師而生。Kaik 開課快手讓您得以輕鬆架設自己的專屬課程教學網站，提供一系列從行銷、課程體驗優化到數據洞察的解決方案，協助您在教育志業推廣上，和您一起將知識散播出去。', 'https://teachify.tw/', 13575),
  ('2022', 'TechInvest科創投資 軟體架構顧問服務', 'https://tec.ntu.edu.tw/wp-content/uploads/2022/03/TechInvest科創投資.png', '我們發現新創團隊往往有很多創新的想法，但卻苦於沒有科技人才，而無法快速精準地做出 MVP，因而錯失良機。 我們希望藉由自身的背景，以軟體技術的角度協助新創，以顧問的角色提供客製化的服務，代替新創公司向外包團隊溝通，並同時監督其產品品質，給予新創團隊最適切的技術建議，以最小的成本完成當前最急需完成的目標。', 'https://techinvest.dev/#/', 13379),
  ('2022', 'MetaCool散熱專家 超冷卻材料', 'https://tec.ntu.edu.tw/wp-content/uploads/2022/03/MetaCool散熱專家.png', 'MetaCool散熱專家，開發一種超冷卻材料，不需用電力、不用燃料，只要接觸物體就可以讓物體降溫10℃以上，MetaCool打造完全不需要電力的冷卻系統，\n「節能減碳，智慧材料，我們一起讓世界更涼爽」。', NULL, 13379),
  ('2022', '綠活賦能 通用療癒花園', 'https://tec.ntu.edu.tw/wp-content/uploads/2022/03/綠活賦能.png', '我們發現新創團隊往往有很多創新的想法，但卻苦於沒有科技人才，而無法快速精準地做出 MVP，因而錯失良機。 我們希望藉由自身的背景，以軟體技術的角度協助新創，以顧問的角色提供客製化的服務，代替新創公司向外包團隊溝通，並同時監督其產品品質，給予新創團隊最適切的技術建議，以最小的成本完成當前最急需完成的目標。', NULL, 13379),
  ('2022', 'Creanity Topo', 'https://tec.ntu.edu.tw/wp-content/uploads/2022/03/Topo-Logo-Square-翁肇陽.png', 'Topo是一個能讓用戶自行打造適地性遊戲的平台，我們連結地方的創意能量將日常生活遊戲化，讓人們以遊戲的視角去體驗日常。\n我們的第一步是媒合實體商家的行銷需求及學生的社交需求，透過Topo輔助商家打造實境遊戲的行銷體驗，吸引學生組隊遊玩，創造到店人流。\n\n我們的使命是透過科技將遠在雲端的數位資訊拉回現實環境，激發人們對探索真實世界的好奇心，把生活看待成一場遊戲。', NULL, 13379),
  ('2022', '企桃囡仔 跨域銀髮協作遊戲工作坊', 'https://tec.ntu.edu.tw/wp-content/uploads/2022/03/企桃囡仔.png', '我們藉由在社區、基金會帶領課程，內容包含銀髮族遊玩桌遊、設計地方特色桌遊......等樂齡活動，促進長者認知、社交、運動功能，並且發揮地方耆老文化價值。期望透過讓銀髮族快樂遊戲，達到正向老化的目的。', NULL, 13379),
  ('2022', 'STOPWET 新型態離子電泳導入止汗裝置', 'https://tec.ntu.edu.tw/wp-content/uploads/2022/03/STOPWET.png', 'STOPWET發明一種新型態離子電泳治療模式，設計出一種低電流參數的乾式人體工學之創新醫材，大幅提升手汗患者的治療意願。透過軟硬體協作建立完整的醫療服務生態體系以增進病患福祉。', NULL, 13379),
  ('2022', '智泉智能 影像識別AI系統與應用', 'https://tec.ntu.edu.tw/wp-content/uploads/2022/03/智泉智能LOGO-Shu-chiang-Chuang.png', '我們提供企業在工業4.0的數位優化與轉型工作上，導入的開發時程長且費用高昂問題的解決方案。主要是以影像識別的人工智慧技術為基礎，在我們所開發的人工智慧影像識別平台上,\n快速產生專屬識別演算法，並串聯不同環境的軟硬體，建構跨系統跨平台的各式落地應用。我們希望不僅滿足客戶預算與時程，更能成為新一代AI應用的成功模式。', 'https://mimiraitec.com/', 13379),
  ('2022', '銅板資本家 給青少年的投資理財課', 'https://tec.ntu.edu.tw/wp-content/uploads/2022/03/銅板資本家.png', '你的夢想是什麼呢？\n有孩子跟我說他想成為電競選手、想當Youtuber，還有一個孩子對越野車深深著迷，他好奇的問我：「有越野車這個職業嗎？」\n有一個好難的問題這樣說道：是要趁年輕時趕緊去追求夢想？還是先找份穩定的工作，再談夢想呢？\n為此，銅板資本家提供第三個解--「何不從小開始？一滴滴累積財富，為將來的夢想做好準備！」\n我們希望帶給青少年「透過投資理財支持自己夢想」的能力。致力於將投資理財最簡化，因為我們深信「投資理財要愈簡單愈好，讓時間留給更多值得去做的事」', NULL, 13379),
  ('2022', '說說實驗室', 'https://tec.ntu.edu.tw/wp-content/uploads/2022/03/說說實驗室.png', '說說實驗室專注於協助不擅於口語表達及在公開場合發言的人，透過三大功能分別是隨口說說-完善的AI口語分析報告、練習說說-客製化的練習方案及模擬情境、社群-互助口說的平台，讓使用者在任何時間、地點精進自己的口語表達能力，解決口語表達能力不足而所帶來的長期困擾。', NULL, 13379),
  ('2022', 'DonaeLabs Netscope', 'https://tec.ntu.edu.tw/wp-content/uploads/2022/03/DonaeLabs-logo_1-Pau-Pernghwa-Kung.jpg', 'DonaeLabs Netscope為製造供應的資料決策戰情室。客戶可透過獨家的no-code流程輕易彙整跨地域的生產資源及供應商關係資料。生產管理可利用AI模型調整決策參數模擬接單、排程、及上下游廠商風險，節省資料工程部門維護成本，並建立細至生產單位的資料透明與實時觀測。', 'http://donaelabs.tech/', 13379),
  ('2022', '溫度寄股份有限公司 POSTORY', 'https://tec.ntu.edu.tw/wp-content/uploads/2022/08/POSTORY-BIS-Log-1024px_2-Hank-Chou.png', '「POSTORY，讓社群與訊息傳遞更具溫度及價值。」\nPOSTORY是傳遞溫度的明信片旅行社群App，我們將手機變成郵筒與藏寶圖，讓喜歡旅行的人在旅途中走訪景點時可以探索富有特色的明信片，透過應用程式輕鬆寄收並與社群分享，讓每個人都能用別具意義的圖文來記錄、分享旅行與生活中的重要時刻與回憶。\n\n對品牌及在地商家來說，POSTORY提供了一個個人化的社群行銷平台，讓它們在傳統社群平台觸及率大幅下降時，能夠透過明信片精準地向顧客一對一傳遞品牌及產品訊息，建立像朋友一般的緊密關係，並在用戶自發性發送明信片時獲得有溫度的口碑宣傳。', 'https://postory.app/', 13379),
  ('2022', 'Tricuss.io 教育與知識交流的 Slack', 'https://tec.ntu.edu.tw/wp-content/uploads/2022/03/Tricuss.io_.png', 'Tricuss.io 現由四位台大畢業生與在學生所組成技術團隊，將打造「教育與知識交流的 Slack」，透過技術 (SaaS, AI, Web3) 與商業模式的緊密結合，解決現有教育場景中， Line 和 FB 僅適合閒聊但「無法深度討論」與「訊息混雜」的問題，並幫助老師「快速上架與銷售、管理課程知識社群」。', 'http://tricuss.io/', 13379),
  ('2022', 'interWellness為你而思 interWellness為你而思飲食友善平臺', 'https://tec.ntu.edu.tw/wp-content/uploads/2022/03/interWellness-Long-Logo-Transparent-林芳如.png', '「和你一起活出亮麗的吃貨人生」是為你而思的願景。為你而思打造一個提供「在乎健康的人、亞健康族群和慢性病友」一個飲食搜尋平臺。透過團隊營養師，協助餐廳計算出餐點的份量與各元素含量。經過餐點資訊揭露，讓使用者可以追蹤飲食攝取。且透過與多間餐廳的合作，使用者的飲食便不受到地緣限制，讓有飲食控制的人都能享有外食的樂趣與便利性。', NULL, 13379),
  ('2022', 'Tera Thinker 人工智慧自適應學習系統', 'https://tec.ntu.edu.tw/wp-content/uploads/2022/03/TeraThinker.png', '「POSTORY，讓社群與訊Tera Thinker 自適應學習系統，透過人工智慧即時追蹤學生的學習狀況，依照學生程度、狀況及弱點，提供最適才適性的客製化學習內容與組合。增強學習效率、降低挫折感，節省學生練習及教師出題時間，花最少的心力達成真正的因材施教。息傳遞更具溫度及價值。」\nPOSTORY是傳遞溫度的明信片旅行社群App，我們將手機變成郵筒與藏寶圖，讓喜歡旅行的人在旅途中走訪景點時可以探索富有特色的明信片，透過應用程式輕鬆寄收並與社群分享，讓每個人都能用別具意義的圖文來記錄、分享旅行與生活中的重要時刻與回憶。\n\n對品牌及在地商家來說，POSTORY提供了一個個人化的社群行銷平台，讓它們在傳統社群平台觸及率大幅下降時，能夠透過明信片精準地向顧客一對一傳遞品牌及產品訊息，建立像朋友一般的緊密關係，並在用戶自發性發送明信片時獲得有溫度的口碑宣傳。', 'https://terathinker.com/', 13379),
  ('2022', 'VoiceTube Name', 'https://tec.ntu.edu.tw/wp-content/uploads/2022/03/VoiceTube.png', 'VoiceTube致力於讓學英文這件事變得更有趣且有效！讓使用者拋開枯燥的教科書，透過觀看自己有興趣的影片的方式，學習到更道地、生活化的英文。藉由 AI 輔助的英文學習系統，與超過10萬部影片的內容，依據用戶的需求與程度，量身定做安排課程，幫助用戶學好道地英文。', NULL, 13379),
  ('2022', 'Qbi塊樂方程式 Name', 'https://tec.ntu.edu.tw/wp-content/uploads/2022/03/Qbi塊樂方程式.png', '我們是台灣新玩具品牌Qbi，專注於開發可以高度互動共玩的益智玩具產品。\n我們希望所提供的每一款設計，不僅可以培養小朋友的多元智能，也要能增進他們的生活能力與學習能力。', NULL, 13379),
  ('2022', '旅攝數位股份有限公司 JOYSHOT', 'https://tec.ntu.edu.tw/wp-content/uploads/2022/03/JOYSHOT.png', 'JOYSHOT拍你玩，致力解決如何獲得優質的旅遊拍攝紀錄的問題，提供平價、彈性，專業攝影普及化的服務，同時提升攝影師多元獲客、收入、形象，以成為攝影師界的UBER為目標。JOYSHOT的線上預約流程只要簡單4步驟，讓全台灣超過200位的在地攝影師，為您與旅伴提供拍攝服務，您專注享受旅行的美好，攝影就交給我們。', 'https://www.joyshot.app/', 13379),
  ('2022', '樂易創 樂點APP-最簡單的歌曲創作工具', 'https://tec.ntu.edu.tw/wp-content/uploads/2022/03/樂易創.png', '樂點APP就像抖音，包含了創作工具及社群，但更著重在流行歌曲的創作及發表。 用戶不需要會樂器或樂理，只要輸入歌詞就能與AI人機共創一首完整的歌曲作品，並錄音、合成原創MV最後一鍵發表至社群，而所有的歌曲都利用區塊鏈智能合約紀錄創作歷程及使用權歸屬，並由我們公司負責營運、管理版稅分潤。', 'https://www.letronmusic.tw/', 13379),
  ('2022', '杯特 uCup永續杯平台', 'https://tec.ntu.edu.tw/wp-content/uploads/2022/03/杯特.png', '我們希望針對消費者的兩大痛點，提供uCup永續杯的服務，讓消費者不用帶杯子出門，只需一張「悠遊卡」能隨地租借環保杯；喝完飲料也不用清洗，隨時歸還環保杯！\n我們相信，如果做環保是件不麻煩的事情，世界會更好！', 'https://ucup.com.tw/', 13379),
  ('2022', 'REcarbon 企業碳中和平台', 'https://tec.ntu.edu.tw/wp-content/uploads/2022/03/REcarbon-e1647412167890.jpeg', 'REcarbon提供SaaS碳盤查平台，協助企業完成碳中和，並將服務普及至大企、中型企業、中小企業。我們協助企業達成：\n1. 碳盤查 - 協助企業碳盤查，了解自身碳排情況\n2. 碳中和 - 介接國際碳權市場，完成企業碳中和', NULL, 13379),
  ('2022', 'Encore 安可日子', 'https://tec.ntu.edu.tw/wp-content/uploads/2022/03/螢幕快照-2022-03-16-下午3.41.59.png', 'Encore App 專注為熟年打造的興趣社群平台，\n邀請對未來充滿期待與追求自我價值的你，\n下載 Encore App 加入我們的平台，\n與更多專家、達人、創作者成為同好，\n共同學習、共享生活、參與活動共創美好回憶，\n找到人生新價值， 再次擁抱精彩生活！', 'http://www.encoredays.com/', 13379),
  ('2022', '超現實科技 SURREALM遠距共學平台', 'https://tec.ntu.edu.tw/wp-content/uploads/2022/03/超現實科技.png', 'SURREALM是一套為了各式教學情境而打造的多人異地虛擬實境VR教學平台，其多人連線、同步互動的特性，讓身處異地的人們打破距離的限制，實現共聚一堂的教學與討論情境。使用者可設定自己的專屬角色外觀，透過虛擬角色模擬真實的教學與社交互動。平台基本配置為個人空間、授課空間與分組討論空間，亦可能根據不同的商業方案，打造主題式與模組化的實作學習場域。', 'https://www.web.surreal.com.tw/', 13379),
  ('2022', 'InventAI DeepFlow & DeepVoice', 'https://tec.ntu.edu.tw/wp-content/uploads/2022/03/INVENTAILOGO_工作區域-1-.png', '1.DeepFlow：高效易用的AI開發分析平台，提供AI模型開發之統一管理機制(MLOps)，具備AI模型開發、管理部署與監控等功能，並提供超參數調優與自動化建模之功能，可有效縮短50%以上作業時間，大幅提升開發效率。\n2.DeepVoice：客戶心聲分析平台，透過AI文本分析技術，提供對話重點摘錄、意圖擷取、情緒分析、主題分群等功能以協助客服中心進行對話資料分析、問題挖掘及趨勢預測，預期可提升10%以上的客服滿意度。', 'https://www.linkedin.com/company/InventAI', 13379),
  ('2022', 'RealT4 Talentrue', 'https://tec.ntu.edu.tw/wp-content/uploads/2022/03/RealT4.png', 'Talentrue, 可視化 SaaS 應用平台，提供使用者簡易 3D 展現可視化界面。應用於智慧工廠/建築，可以以單棟或多棟建築組成的場景進行可視化呈現；平台可鏈結 IoT 裝置數據，便可提供即時性、數據性數位雙生管理平台。除智慧工廠/建築外，廣泛應用於數據中心、倉儲、學校、醫院、安防、觀光、城市等多種空間領域。', 'https://realt4.com/', 13379),
  ('2022', 'Slash studio 循環設計服務Slash studio', 'https://tec.ntu.edu.tw/wp-content/uploads/2022/03/Logo_1024-studio-slash.png', 'Slash studio致力於透過循環設計打造永續生活，以行動實踐循環經濟，進而對社會與環境產生正向影響力。我們專注於「產品永續設計」、「場域永續再造」與「環境議題溝通」，並藉由著聰明又敏捷的協作模式，聯合不同產業的力量，共同解決複雜的系統性問題，為客戶賦予ESG及永續的創新價值。', NULL, 13379),
  ('2022', '傑精靈 FaCare', 'https://tec.ntu.edu.tw/wp-content/uploads/2022/03/傑精靈.png', '傑精靈資訊科技是個熟悉醫療影像或訊號偵測與電腦視覺跨領域整合的公司，致力於智慧醫療等AI相關技術的研發，輔助醫院守護民眾的健康。多年來持續為客戶提供最完善的技術服務與體驗。目前正在發展以人臉辨識的方式偵測心跳與呼吸率，並推算其他生理參數，以最便利的方式促進每個人的健康。期許能夠跨領域結合醫療與電腦視覺領域，持續發展先端技術與應用服務人群社會，照護每個人的健康與安全。', 'http://www.sg-aitek.com/', 13379),
  ('2022', '醫淬思股份有限公司 值得信賴的O2O醫療健康嚴選平台', 'https://tec.ntu.edu.tw/wp-content/uploads/2022/03/醫淬思股份有限公司.png', '醫淬思是目前台灣最大的醫療社群聯盟，超過60位醫療社群意見領袖加入，包含醫師、牙醫、中醫、藥師、營養師、護理師、治療師和諮商師等。醫淬思的願景是「促進醫療資訊流通，實踐醫療普惠無遠弗屆」。藉由社群衛教、期刊科普促進民眾健康識能，與值得信賴的品牌和醫療機構合作，注重安全與健康效能，提供民眾值得信賴的O2O醫療健康嚴選平台。', 'https://mediterest.com/', 13379),
  ('2022', '吉樂健康資訊科技股份有限公司 WaCare遠距健康', 'https://tec.ntu.edu.tw/wp-content/uploads/2022/03/WaCare-村銘陳.png', '吉樂健康 (La Vida Tec.)的企業使命是讓『任何人、任何時間、任何地方，都能實現健康促進』。發展出創新遠距數位健康應用服務【WaCare遠距健康】與【WaPro專家遠距工具平台】，建構由使用者、健康專家與親友組成的關懷社群網路，透過數據的引導連結平台上大量醫療健康專家線上服務，打破距離與時間的限制，及時解決健康問題。WaCare團隊為國內少數具備巨量資料處理與疾病健康風險預測模型設計能力的資料科學與工程團隊，自2016.12成立至今，並且為第一個獲得健保署核可為民眾管理個人病歷數據並提供數位健康促進服務的新創團隊。', 'https://www.wacare.co/', 13379),
  ('2022', '愛米菜 愛米菜餐廳', 'https://tec.ntu.edu.tw/wp-content/uploads/2022/03/愛米菜去背logo-彭禹庭.png', '愛米菜新蔬食實驗所 / 愛米菜是一家致力於翻轉素食印象的餐飲品牌，隨著科技植物肉的發展全球掀起素食新浪潮。台灣有10%素食人口且每年都在成長中，我們希望透過創新和美味的素食產品讓更多葷食者願意嘗試素食，除了口味外，我們也希望將服務、環境、品牌概念用更現代與科技的方式呈現。', 'https://www.facebook.com/amytsai.food', 13379),
  ('2022', '樂邁喬國際股份有限公司 楽坡bonbox', 'https://tec.ntu.edu.tw/wp-content/uploads/2022/03/楽坡bonbox.png', '我們致力透過舒肥、均衡、原型與低調味的烹調手法，讓「健康生活變得簡單」。', 'https://bonbox.tw/', 13379),
  ('2022', 'The Compass Comfytube', 'https://tec.ntu.edu.tw/wp-content/uploads/2022/03/The-Compass.png', '鼻胃管為吞嚥障礙的患者提供營養與藥物，放置過程相當痛苦，增加放置的失敗率，產生併發症及增加醫療支出。ComfytubeTM是能夠降低置入不適感的兩截式鼻胃管，使用SMPU作為鼻胃管的主要材料。在室溫下管子較小且柔軟。置入體腔後，SMPU膨脹至灌食大小。並以磁吸方式固定使其能夠快速穩定的接合，且以伸縮夾取代傳統黏貼減少過敏的發生。', NULL, 13379),
  ('2022', 'New Biodesign Eternal tube', 'https://tec.ntu.edu.tw/wp-content/uploads/2022/03/New-Biodesign.png', '預防阻塞之可收縮性餵食管/透過氣體收縮達到模仿腸道蠕動之管路裝置，藉此維持管路的暢通，希望能延長餵食管的使用壽命，減少病患額外的就醫需求，提高病人的營養狀況與照護者的生活品質。', NULL, 13379),
  ('2022', 'Medevice 磁力防導絲滯留裝置', 'https://tec.ntu.edu.tw/wp-content/uploads/2022/03/Medevice.png', '依據臨床經驗與文獻分析，當臨床專業人員在操作血管導管置入術時，如中央靜脈導管，可能因疏忽將輔助置入的金屬導絲留滯於體內忘記取出，早成嚴重併發症如靜脈栓塞、心律不整等。國際上現有解決方案僅有醫院品管流程更新與臨床再教育，尚無使用機構再設計作為防呆裝置。我們設計了磁力輔助裝置，幫助操作者防止金屬導絲在操作時不慎留滯。', NULL, 13379),
  ('2022', 'MeTCare Home-based IOP measuring device', 'https://tec.ntu.edu.tw/wp-content/uploads/2022/03/MeTCare.jpg', '青光眼是世界上排名第二名造成失明的原因。然而早期診斷，早期介入治療可讓患者免於走向失明的風險。目前篩檢(screening)及追蹤(follow up)方式仍以眼壓追蹤為主，但是眼壓有日夜變化差異(diurnal change)的特性，並非固定數值，如同血壓一班，故造成在門診追蹤眼壓時不一定能檢測出有意義的數據。另一方面，市面上雖有不少眼壓量測產品，然而大部分因操作困難，須由醫師執行操作外，且其單價較高。本產品開發之目標為提供患者本身在居家即可簡單安全的操作，提供患者更即時的眼壓清況，也提供醫師更加精確的數據協助青光眼的控制與治療，達到最佳個人化醫療的情況。', NULL, 13379),
  ('2022', '電子藥瓶', 'https://tec.ntu.edu.tw/wp-content/uploads/2022/03/電子藥瓶.png', '希望能提高憂鬱症患者的用藥順從性，由此改善生活品質、疾病預後，並建立有力的病友支持網，深入病患的生活。', NULL, 13379),
  ('2022', '南瓜虛擬科技 Name', 'https://tec.ntu.edu.tw/wp-content/uploads/2022/03/南瓜虛擬科技.png', NULL, NULL, 13379),
  ('2022', 'Speed 3D Inc. Picbot－AR智慧拍照機器人 / FunkAR－WebAR送禮平台', 'https://tec.ntu.edu.tw/wp-content/uploads/2022/03/Speed-3D-Inc..png', '擁有堅強行動應用開發能力及可程式化3D內容技術而名揚國際的啟雲科技，為AR技術應用領導先驅，2017年起應美國Meta (Facebook) 官方邀請成為AR技術合作夥伴，迄今仍為台灣唯一官方認證技術合作夥伴。啟雲科技提供一站式AR內容相關的客製化服務，如社群應用AR廣告、或是系統軟硬體的整合客製化服務。\n2019年團隊接續開發自有品牌「PICBOT - AR智慧拍照機器人」、「FunkAR - WebAR送禮平台」，已開發軟硬體產品皆獲得多國發明專利，全球已合作服務超過200餘知名品牌，成績斐然。啟雲科技以「元宇宙建築師」之姿，提供品牌及中小企業完整的AR技術支援，積極投入開發新一代AR擴增實境送禮平台，並受邀與各大企業結盟，成為第一批建構新世界的開拓者。', 'https://www.spe3d.co/', 13379),
  ('2022', '方兔互動娛樂工作室 台北大空襲', 'https://tec.ntu.edu.tw/wp-content/uploads/2022/03/Fun2_Logo_300dpi_1024x1024px_A-Sophia-Huang.png', '《台北大空襲》是一款以二戰台灣為背景的動作冒險遊戲，你將扮演一位失憶的少女，和一隻台灣犬，在戰火摧殘的城市中求生。在喚醒記憶的過程中，伴隨真相而來的，卻是致命的危機⋯⋯。遊戲關卡將有許多機關、道具、裝備，考驗你的操作與協調能力。「躲避空襲」將是遊戲精髓，你將擬真感受二戰期間台灣人「走空襲」的難忘往事。', 'https://fun2studio.com/', 13379),
  ('2022', 'MIFLY MAKAR', 'https://tec.ntu.edu.tw/wp-content/uploads/2022/03/米菲多媒體logo-04-Aileen-MIFLY.png', '「MAKAR XR編輯平台」提供創作者不需學習程式編譯，可自由創建、分享並瀏覽XR專案的數位內容平台。其功能包含：圖像辨識(AR擴增實境)、空間辨識(MR混合實境)、360環景導覽(VR虛擬實境)及陀螺儀互動功能為XR主要應用模式。', 'https://www.makerar.com/', 13379),
  ('2022', 'MAI BodyMap', 'https://tec.ntu.edu.tw/wp-content/uploads/2022/03/MAI_Logo-01-Sam-Jang.png', 'MAI的產品包括 (1) BodyMap : VR人體解剖與模擬訓練軟體 (2)AcuMap : 身臨其境的虛擬針灸培訓軟體，以及 (3) DigiTwin : 醫學影像融合與數位分身重建軟體。透過與美國名校的合作，例如哥倫比亞大學和紐約大學，MAI提供優秀的師資在醫學教育的元宇宙中與來自世界各地的用戶進行互動式學習，我們的目標是透過沈浸式互動，藉以增強用戶的醫學智慧，以及共同協作出更有價值的數位內容。在今年12月8號，MAI首次在線上啟動收費式的元宇宙活動，由紐約大學醫學院的Dr. Gregory Katz 主講，並提供參加用戶線上教育學分，MAI的元宇宙，在疫情期間的遠距教學，已經成為必備的教學工具，我們期待在2022年積極衝刺會員人數，創告在醫學教育上的創造者經濟規模。', 'http://www.mai.ai/', 13379),
  ('2022', '科碼新媒體 AR遠距商務系統', 'https://tec.ntu.edu.tw/wp-content/uploads/2022/03/104_corma-Ray-Lee.png', '此系統開發目的在增加遠距業務洽談成交機會。賣方透過網頁編輯器完成3D模型編輯，運用APP，即可將業務人員去背以AR之形式傳送至買方場域，結合產品之3D資訊演示商品。', NULL, 13379),
  ('2022', '全球動力科技股份有限公司 元宇宙警察訓練、元宇宙軍事訓練、元宇宙智慧交通、元宇宙智慧安全', 'https://tec.ntu.edu.tw/wp-content/uploads/2022/03/全球動力科技股份有限公司.png', 'take! 以智販機為基礎，將派樣行銷的實體場域人潮與實體商品體驗，與網路平台各種數位行銷工具結合，打造出「數據化、可追蹤、可二次行銷」的 OMO (Offline Merges Online) 融合行銷服務，為各種零售品牌建立品牌與受眾資產，也為場域經營者創造嶄新的用戶體驗與營收模式。', 'http://www.bigxreality.com/tw/', 13379),
  ('2022', 'take!智慧體驗行銷 拿拿科技行銷', 'https://tec.ntu.edu.tw/wp-content/uploads/2022/08/拿拿科技行銷logo去背-Jimmy-Yiu-1.png', 'take! 以智販機為基礎，將派樣行銷的實體場域人潮與實體商品體驗，與網路平台各種數位行銷工具結合，打造出「數據化、可追蹤、可二次行銷」的 OMO (Offline Merges Online) 融合行銷服務，為各種零售品牌建立品牌與受眾資產，也為場域經營者創造嶄新的用戶體驗與營收模式。', 'http://www.bigxreality.com/tw/', 13379),
  ('2022', '心偵環 悠揚團隊', 'https://tec.ntu.edu.tw/wp-content/uploads/2022/08/悠揚團隊LOGO.jpg', '•平臺優勢與產品特徵\n•非侵入式血流監測技術，即時觀察到健康指標的變化\n•完整連續記錄，觀察過程而非單點，為長期健康服務\n•以循證為基礎的健康管理服務，做到隨時隨地隨心\n•心血管風險篩檢指標滿足重點人群重點關注\n•心血管嚴重不良事件風險分層，達到分而治之的效果\n•心血管疾病預防管理，真正做到 “未病先防"', 'http://www.bigxreality.com/tw/', 13379)
INSERT INTO historical_startups (year, name, logo_url, description, external_link, source_post_id) VALUES
  ('2022', '大話中文內容平台與華人文化線上課程 大話中文', 'https://tec.ntu.edu.tw/wp-content/uploads/2022/08/大話中文LOGO.png', '全球學習華語的人數高達2億人，以文化興趣為出發點學習華語的比例高達八成，然而，目前我們發現現有的傳統文化、華語教學產品，有老舊、互動性低的問題。另外，市面上其他語言的中華文化內容多僅止於入門或非專業的分享，而希望學習傳統文化技藝的學習者則多不得其門而入。\n大話中文線上雙週刊提供海內外語言學校和華語中心線上雙週刊補充教材，就像中文版本的空中英語教室；現在，我們正準備要到美國的kickstarter平台上進行群眾募資，讓大家預購華人歷史文化課。結合語言學習和活潑的歷史故事，用程度分級的方式一步一步的帶領成人學生，並且媒合語言學校和想要把中文學得更好的學生。\n未來，我們更會藉由平台上學習者的偏好和大數據資料分析，推出更多不同主題的線上課和傳統技藝的學習材料包等等文創商品。\n大話中文會成為最自由、有趣又有深度內涵的的線上傳統技藝和華語學習的元宇宙社群，讓海外學習者喜歡台灣，瞭解台灣，宣傳台灣。', 'https://dahuachinese.com/', 13379),
  ('2022', 'SMARTAX 365 Ecosystem 酷堤康科技', 'https://tec.ntu.edu.tw/wp-content/uploads/2022/08/酷堤康科技logo去背-Tiffany-Hsiao.png', 'QTCOMM Inc. 透過台灣統一發票經驗，協助印尼地方政府進行稅務改革及系統數位化，並透過稅務系統切入對當地商家與終端消費者的服務市場。\n目前已與286個地方政府完成SMARTAX Ecosystem的獨家簽約，預計在三到五年內，將 2G 的 Tax BI 系統與 2B 的 Smart Printer 佈向印尼 514 個城市及 120 萬間商家，而消費者也可以透過IndoChat APP來掃描發票參加抽獎，由此打造出全方位的 SMARTAX Ecosystem。', 'https://indochat.co.id/en/', 13379),
  ('2022', '超解析微型光達系統 Visioner幻視科技', 'https://tec.ntu.edu.tw/wp-content/uploads/2022/08/VISIONER-梁妙華.png', '幻視科技為解決傳統光達因結構複雜、體積龐大與成本高的應用限制，致力發展高規格與性能、軟硬整合的LiDAR系統解決方案，過去的兩年我們成功開發出低成本、體積小以及高解析度，更是唯一可突破天氣限制的固態微型光達設計，並持續進行性能上的優化以及國內外專利佈局。\nVisioner開發之光達產品主要打入自駕車與軍用光達市場，商業模式在自駕車市場中，取得Velodyne合作開發關鍵零組件，並透過Velodyne既有的自駕車供應鏈進行販售；今年我們嘗試建置人工智慧輔助光達系統，應用於工廠自動搬運場域，營收我們會以相關零組件銷售為主，我們現在也正在接受光達相關的開發案，未來也將持續整合光達各項感測器，期望能研發出貼切市場需求之光達技術，為世界科技產業貢獻一份心力。', NULL, 13379),
  ('2022', 'X-CITY XPACE', 'https://tec.ntu.edu.tw/wp-content/uploads/2022/08/XPACE-logo去背-Astrid-CH.png', 'XPACE 致力於為用戶提升數位足跡與資料的價值， 透過 AI 與分散式帳本技術，讓人人皆能享有資料經濟的紅利。\nX-CITY 是一個 3D 多元應用高互動性的線上社群平台/元宇宙，用戶並有機會享有額外的收入來源，是舉辦各種線上活動、創建個人風格社群、體驗不同社群風格與話題討論、與朋友聚會聊天的最佳吸睛場域。\n\nXPACE 也協助企業打造虛擬空間、社群徽章制度與客製化場景，讓用戶體驗更加深刻的內容與豐富有趣的社群生活，提升品牌認同與忠誠度。', NULL, 13379),
  ('2022', 'ARCHE Studio META ARCHE Technology', 'https://tec.ntu.edu.tw/wp-content/uploads/2022/08/Meta-Arte-D-1-3-white-Headquarters-MetaArche.png', 'ARCHE Studio是鎂碁科技旗下結合科技與設計的實驗性工作室，透過虛擬體驗技術的模組化，應用於商業創新開發。尤以大眾面向的體驗為關注重點，期望透過媒體內容、知識教育打造新型態的互動體驗與虛實連結，再結合線上線下應用裝置整合，持續建構劃世代web3的數位孿生與元宇宙普及化。', 'https://metaarche.cargo.site/', 13379),
  ('2022', 'Oh!Bot Line SCRM Oh!Bot', 'https://tec.ntu.edu.tw/wp-content/uploads/2022/08/OhBot-LOGO.png', 'Oh!Bot 提供中小企業做Social CRM管理工具，透過在Line官方帳號上的軟體串接完成整體一站式服務包含，線上預約系統，會員經營系統，社群電商系統', 'https://ohbottech.com/', 13379),
  ('2022', 'LuminX Tracking Kit 路明思生技', 'https://tec.ntu.edu.tw/wp-content/uploads/2022/08/LuminX-LOGO-Vincent-Fan.png', 'LuminX Tracking Kit 具良好生物相容性及長效螢光訊號穩定輸出特性，能輕鬆\n完成細胞標定（單顆細胞級）、癌症轉移追蹤和最新開發的免疫細胞標定。佐以\n專業影像及定量技術，有效地提供目標細胞群位於大小動物模式裡的外觀影\n像、型態、數量和分佈位置。', 'http://www.luminxbiotech.com/', 13379),
  ('2022', '聲音內容(Podcast、有聲書) 聲鮮時采科技', 'https://tec.ntu.edu.tw/wp-content/uploads/2022/08/聲鮮時采Logo去背-王薇瑄.jpg', '聲鮮時采科技以經營聲音IP為核心，擅長將原文字內容轉化為聲音內容產品，除了為企業量身打造專屬聲音內容、為企業品牌行銷之外，也與多家出版社採利潤共享方式合作製作及銷售有聲書，為傳統出版社提供數位轉型之解決方案。目前旗下已有12檔自有IP的Podcast節目，亦有4位聲優已開始參與製作出版社的有聲書內容。', 'https://www.nextvoicetech.com/', 13379),
  ('2022', '飛天奶茶', 'https://tec.ntu.edu.tw/wp-content/uploads/2022/08/飛天奶茶logo去背-飛天奶茶Flying-Milk-Tea.jpg', '飛天奶茶是一個凝聚了來自世界各地的華人創作者的商業平台，網站主要由作品分享、社交媒體與電子商務三個部分組成，為創作者提供了跨國販售商品、經營個人品牌的渠道。\n網站內名為「創作者事務所」的媒合服務，成功串聯起數千位創作者與各界企業，為企業提供客製化、優質且價格合理的素材，可用於網絡宣傳、創意行銷、產品包裝、遊戲製作甚至教育產業等多個領域。', 'https://market.flyingmilktea.com/', 13379),
  ('2022', 'Uni-Trip 樂多科技', 'https://tec.ntu.edu.tw/wp-content/uploads/2022/08/樂多科技LOGO去背-Tonton-Yang.jpg', '客製行程、數位應用是正在發生的趨勢同時也是產業界最大的痛點，當業界跟不上市場需求，很有機會被淘汰。現今旅行社使用的系統皆不能完整讓旅行社應用，更不能面對接下來的客製化、特色遊程趨勢。過往市場多以標準套裝團為主，所使用的ERP系統工具多以大團操作為主，在支援客製化、深度旅遊等小團功能皆非常缺乏，功能大多著重在協助旅行社與服務供應商的金流串連為主，對於行程客製化安排等內容尚不具備完整功能。第二是傳統旅行社的作業習性上，從安排司機、餐廳到旅館多以人工聯繫，中間過程缺乏數位化，導致操作團務的靈活性受到限制，難以針對特殊旅遊族群或額外需求進行客製化團務安排。\n樂多科技在疫情間出發，以客製化排程為核心打造完整應用數位平台，包括團控系統、B2B平台、前台官網、旅客行為數據可視化資料、套裝團應用、DM產生器、CRM管理，金流串接等功能。跟著旅遊業，在最壞的時代，一起打造下一個世代。', 'https://www.unitrip.asia/', 13379),
  ('2022', 'RENEAL', 'https://tec.ntu.edu.tw/wp-content/uploads/2022/08/RENEAL-logo去背-Neal-tseng.png', 'Pesto Green 旨在讓可持續生活方式更容易在香港獲得和採用。 我們的產品作為一個平台，將當地綠色服務提供商/商家與可持續發展從業者聯繫起來，從可持續發展的倡導者到初學者——他們是可持續生活方式世界的新手。 我們將與這些合格的商家合作，為我們的平台用戶提供獨家折扣，作為回報，我們將增加他們的業務流量並增強他們對可持續發展承諾的善意。 我們的平台用戶可以通過各種綠色行為（例如拒絕在餐廳使用塑料；自帶飯盒）來賺取我們稱為 P 幣的貨幣，並兌換我們合作商家的所需優惠券（例如當地生態旅遊）。 我們渴望涵蓋人們每天需要的產品和服務。', NULL, 13379),
  ('2022', 'Pesto Green Super App Pesto Green', 'https://tec.ntu.edu.tw/wp-content/uploads/2022/08/logo-Peter-Yeh.png', 'Pesto Green 旨在讓可持續生活方式更容易在香港獲得和採用。 我們的產品作為一個平台，將當地綠色服務提供商/商家與可持續發展從業者聯繫起來，從可持續發展的倡導者到初學者——他們是可持續生活方式世界的新手。 我們將與這些合格的商家合作，為我們的平台用戶提供獨家折扣，作為回報，我們將增加他們的業務流量並增強他們對可持續發展承諾的善意。 我們的平台用戶可以通過各種綠色行為（例如拒絕在餐廳使用塑料；自帶飯盒）來賺取我們稱為 P 幣的貨幣，並兌換我們合作商家的所需優惠券（例如當地生態旅遊）。 我們渴望涵蓋人們每天需要的產品和服務。Pesto Green 旨在讓可持續生活方式更容易在香港獲得和採用。 我們的產品作為一個平台，將當地綠色服務提供商/商家與可持續發展從業者聯繫起來，從可持續發展的倡導者到初學者——他們是可持續生活方式世界的新手。 我們將與這些合格的商家合作，為我們的平台用戶提供獨家折扣，作為回報，我們將增加他們的業務流量並增強他們對可持續發展承諾的善意。 我們的平台用戶可以通過各種綠色行為（例如拒絕在餐廳使用塑料；自帶飯盒）來賺取我們稱為 P 幣的貨幣，並兌換我們合作商家的所需優惠券（例如當地生態旅遊）。 我們渴望涵蓋人們每天需要的產品和服務。', NULL, 13379),
  ('2022', 'Duet OTP Jmem tek', 'https://tec.ntu.edu.tw/wp-content/uploads/2022/08/Jmem-tek.jpg', '由於網路的發達與萬物聯網的時代來臨， IoT 設備每年出產的數量以億來計算，但傳統的軟體已不足夠，我們提供了一種新型態的硬體防護，歷經四年研究，利用多晶矽與 High-k 材料等不同元件結構之優勢，也藉由 Fuse 與 anti-Fuse 編成法來完成多組態及多位元，得以改善目前現有 OTP 在安全性、耗電以及容易被 逆向工程的缺點。', 'https://www.jmemtek.com/', 13379),
  ('2022', 'LPG物聯網雲端平台 Artifact智器科技', 'https://tec.ntu.edu.tw/wp-content/uploads/2022/08/Artifact智器科技.png', '與伸波通訊有限公司共同研發「LPG桶裝瓦斯物聯網雲端平台」，由他們開發硬體，也就是物聯網智慧瓦斯表，而我們為硬體設計相對應的平台系統，相輔相成，提高平台的使用便利性以及實用性。透過數據分析、雲端整合等技術，以整合瓦斯行物流為基礎，提高瓦斯行的人力使用效率，同時讓瓦斯行能夠提升對於一般民眾的服務品質。', 'https://artifactdev.tw/', 13379),
  ('2023', '撩慾', 'https://tec.ntu.edu.tw/wp-content/uploads/2023/03/撩慾logo_new.png', '重新定義女性對於情慾的探索和求知的需求，以華燈初上的媽媽桑及專業人士為IP，推出心法與技法的線上教學課程、訂閱制的情慾短片課程、達人嚴選與教學的訂閱制情趣產品箱。', NULL, 13751),
  ('2023', 'NFTicketing', 'https://tec.ntu.edu.tw/wp-content/uploads/2023/03/NFTicketing_logo去背-Tseng-Wilson.png', 'NFTicketing 是一個致力於「零黃牛」的票務平台，提供安全、透明且可信賴的空間，讓每位購票的朋友回歸最純粹的購票體驗，並且透過最貼近生活的方式讓普通民眾輕易地探索 "Web3.0" 的世界。', NULL, 13751),
  ('2023', '人木有限公司', 'https://tec.ntu.edu.tw/wp-content/uploads/2023/03/人木有限公司logo去背-Evelyn-Chou.png', '一間離您家最近、最好抵達、最好上手的健身房！人木有限公司擁有精實的健身教練培訓系統，配合社區公設(健身房)大小，提供住戶適合的運動課程，如：壺鈴、專業拳擊、初階重量訓練…等。外派健身教練與器材直達社區，也能大幅改善長者出門運動的距離痛點；針對物管業者也提供了系統化的公設健身房管理計劃。\n\n', 'https://myrenmu.wordpress.com/', 13751),
  ('2023', '台大俞松良老師團隊', 'https://tec.ntu.edu.tw/wp-content/uploads/2023/03/俞松良.jpg', '人類幾乎所有的疾病都與免疫有關，不管是免疫系統出問題造成疾病(如自體免疫失調)或是疾病造成免疫失調(如癌症)。透過自體抗體的剖析對於不同疾病可以及時提供診斷依據，達成精準治療。我們團隊提供高通量的自體抗體檢測晶片，可針對不同疾病，找出相關的自體抗體生物標記，協助疾病的偵測及診斷。', NULL, 13751),
  ('2023', '厝邊MyNeighbor', 'https://tec.ntu.edu.tw/wp-content/uploads/2023/03/厝邊MyNeighbor-logo去背-Chinchin-Yang.png', '厝邊MyNeighbor 致力打造一個有溫度的二手交易平台，鼓勵買賣家透過面交，創造出二手物品新價值。厝邊專注在地經營、鼓勵真鄰面交、沒有手續費、也不用處理繁瑣的包裝寄件、除了省下時間與運費，又能和住在同個生活圈裡的鄰居當面確認物品狀態，不僅安心地完成交易，也增添了社區互動的溫度。', 'https://www.myneighbor.com.tw/', 13751),
  ('2023', '恩食', 'https://tec.ntu.edu.tw/wp-content/uploads/2023/03/恩食logo去背-chen小琪.jpg', '恩食使用本土在地農友用心、真心培育出含有高花青素的秈糯糙米，是專精食品科學的郭孟怡教授親自研發的健康食品品牌。團隊秉持感恩及照顧長輩的心情，以全方位的打造安全吞嚥及均衡營養的進食照顧為初衷，研發高品質的優良銀髮族軟食產品，重視適口性、機能性、保存攜帶性。', 'https://www.gracefood.com.tw/', 13751),
  ('2023', '起起夫夫', 'https://tec.ntu.edu.tw/wp-content/uploads/2023/03/起起夫夫logo去背-許博超.png', '追築app為一建築探索平台，致力於統整媒合一切建築相關事物。我們協助各大建築相關行業來推廣自己，並減少其徵才、徵人的時間管理成本。', NULL, 13751),
  ('2023', '賦語科技 Answer Corp.', 'https://tec.ntu.edu.tw/wp-content/uploads/2023/03/賦語科技logo去背-Answer-Corp.png', '賦語科技開發高度客製化的翻譯軟體以回應專業譯者及企業需求：對於專業譯者而言，機器翻譯品質沒有保證，尚不能滿足商業上的高要求標準，譯者期待有「更大參與度」及「更強大學習功能」的 AI 翻譯平台，助其事半功倍；企業則有大量「專有名詞」、「內部翻譯習慣」需處理，現有市面上產品皆未關注。\n賦語科技利用其特殊「句法解構」及「偏好記憶」技術，改善工作流程，積極創造翻譯軟體新標竿。', NULL, 13751),
  ('2023', '繁晶科技 Ranictek', 'https://tec.ntu.edu.tw/wp-content/uploads/2023/03/繁晶科技logo去背-Wang-Mike.png', '繁晶科技是一間IC設計公司，主要研發的產品包含5G與未來6G的基地台晶片以及衛星通訊晶片，尤其針對開放式(O-RAN)基地台以及大型陣列天線(Massive MIMO)基地台之晶片。創辦人王易凡博士於台大電信所取得博士學位，發表了數篇關於大型陣列天線基地台技術之IEEE國際期刊與會議論文，並具有在IC設計公司、電信商、以及系統廠商服務之工作經驗。', NULL, 13751),
  ('2023', 'FozirTex 賦喆運動科技', 'https://tec.ntu.edu.tw/wp-content/uploads/2023/03/BadX-logo去背-YU-HAO-FAN.png', '本產品結合虛擬實境(VR)、智慧紡織、人工智慧與運動科技創造出新型態的虛擬運動系統，能不受時間、場地以及人數的限制進行羽球、撞球等運動。玩家能透過視覺化的運動科學指標在單人訓練模式中精進自己的球技，也能在多人連線模式中進行高度臨場感的球賽，並搭配手機app紀錄運動狀況、認識球友，打造運動元宇宙！', '#', 13751),
  ('2023', 'Combogic Tech. 櫛構科技', 'https://tec.ntu.edu.tw/wp-content/uploads/2023/03/Combogic-Tech-櫛構科技logo去背-Wei-Ming-Li.png', '隨著全球暖化與氣候變遷加劇，全球企業正面對前所未有的 ESG 轉型壓力，挑戰公司治理文化與數據洞察的軟硬實力。\n\n櫛構科技從聯合國永續發展目標(SDGs) 「7.永續能源」、「9. 工業創新」、「13. 氣候對策」 等三大方向出發，致力於開發運具碳排放數據分析系統，提供精準、自動化的 AI 碳管理解決方案，做到真實洞察、真實減碳、真實轉型等「三真」，讓減碳不再是公關口號，而是提升企業韌性的共同願景。\n團隊成員具有近十年 AI 與 GIS 實務整合經驗，包含協助多間公司數位轉型、機器學習、資料探勘、軟硬體整合系統等產官學整合實務經驗，能為客戶提供全方位價值。\n\n除了隨手關燈，我們可以做更多。', 'https://combogic.com/', 13751),
  ('2023', '點點善cooseii', 'https://tec.ntu.edu.tw/wp-content/uploads/2023/03/cooseii-15-Mark-Yeh.png', '點點善cooseii圖像共創平台相信每個人都擁有天賦，\n團隊帶領弱勢進行藝術課程創作手稿，\n再經由專業設計師保留手稿線條筆觸下；\n共同創作為可商業應用之設計圖稿。\n我們希望透過共創價值帶給弱勢第二份收入，\ncooseii不僅給釣竿、陪釣魚、更創造魚市；\n邀請大眾參與cooseii平台遇見被隱藏的天賦。', 'https://www.cooseii.com/', 13751),
  ('2023', '哈彼科技股份有限公司', 'https://tec.ntu.edu.tw/wp-content/uploads/2023/03/havppen_logo_正方形黑-2-ALLISON-CHIU.png', 'HAVPPEN為一站式線上教育開課平台，讓專業知識變現可以更簡單、輕鬆、容易！提供內容企劃與影音製作、課程網站架設以及15種以上模組，包含文章模組、課程模組、預約模組、活動模組、直播模組、電商模組等整合線上線下OMO模式，一條龍解決數位轉型方案等SaaS服務。', NULL, 13751),
  ('2023', '科學毛怪 PetSci', 'https://tec.ntu.edu.tw/wp-content/uploads/2023/03/Logo_Final-胡兆棨.png', '科學毛怪 PetSci 提供寵物腸道菌檢測分析，期望透過科學檢驗與 AI 預測的方式給予寵物最適合的飲食建議，並與台灣小農合作販售純天然寵物食品,寵物吃得安心又健康。', NULL, 13751),
  ('2023', 'pergolas', 'https://tec.ntu.edu.tw/wp-content/uploads/2023/03/0418-logo外框.jpg', '結合美國智能化演算法先進概念，及台灣高素質AI開發人力，開發台灣自有的智能化演算化整合服務方案。主要目的是在提昇台灣整體智能交易技術水平，提昇國際化市場交易競爭力', 'https://sites.google.com/pergolastech.com/2pgl?pli=1', 13751),
  ('2023', 'Social Monster社社發抖', 'https://tec.ntu.edu.tw/wp-content/uploads/2023/03/Social-Monster社社發抖logo去背-孟芹.png', 'Social Monster 想解決有強烈社交需求者，在社交場合「無法有效率結識目標人物」及「事後難以維持關係」兩大痛點。\n軟體主要功能：\n一、聚會前提供參與者相關資訊\n二、聚會後利用管理工具，依個人喜好將結識好友分群、製作備忘綠（記憶點、好惡等資訊）以便針對不同類型友人延續關係\n我們相信絕對有方法讓社交過程更容易！', NULL, 13751),
  ('2023', 'UFO Pay 優付', 'https://tec.ntu.edu.tw/wp-content/uploads/2023/03/UFO_Pay_logo去背-Arctic-Yen.png', 'UFO Pay協助消費者處理信用卡優惠比較、帳務整合的支付平台，透過大數據分析讓消費變成一件既聰明又簡單的事情。不僅如此，UFO Pay的 AI 會針對不同使用者推薦合適的金融產品，幫助消費者在眾多信用卡中找到屬於自己最划算的那一張，實現 Pay Smart & Pay Easy 的目標。', NULL, 13751),
  ('2023', 'Gocochain', 'https://tec.ntu.edu.tw/wp-content/uploads/2023/03/Gocochain-logo去背-簡宜信.png', '「Cotect」方案鎖定生鮮食品供應商在物流運送過程中對於溫控之不確定性的痛點，提供操作便利、測量精準、低成本的便攜式感測器，隨時監控貨品在運送過程中的溫度變化；並透過雲端資料庫及數據儀表板，協助業者即時檢視數據變化，降低營運成本、提昇決策效率，成為出貨後供應商與消費者之間最可靠的第三雙眼。', 'https://www.facebook.com/gocochain', 13751),
  ('2023', 'Y&E', 'https://tec.ntu.edu.tw/wp-content/uploads/2023/03/YE_LOGO去背-周庭宇.png', '我們希望打造一個讓青年世代與樂齡族群共同使用的平台。在平台中雙方可以透過尋找符合自己期望、或是能自己有興趣的人或活動，進一步的與不同世代的人建立關係，青年世代能從樂齡族群身上獲取人生經歷與建議，樂齡族群也能藉此開拓新的旅遊體驗，達到青銀共融的願景。', NULL, 13751),
  ('2023', '奉茶行動 My Hong-Te', 'https://tec.ntu.edu.tw/wp-content/uploads/2023/03/奉茶行動logo去背-黃暐程_奉茶行動.png', '我們需要「喝水，不要製造丟棄塑膠瓶」\n2020年推出「奉茶行動：解你的渴，為地球減塑減碳」\n\n串連政府、企業、民間超過1萬2千站免費飲水據點，提供大眾源頭減廢，實踐SDGs12.5，攜手實踐ESG。\n至2022年，已有22萬人次下載APP，一同在源頭減少91萬瓶裝水使用及減少85公噸的二氧化碳排放。', 'https://www.circuplus.org/tw/water-refill-map/', 13751),
  ('2023', 'DMKTZ Inc.', 'https://tec.ntu.edu.tw/wp-content/uploads/2023/03/DMKTZ-logo-Jac-Hsieh.jpg', '人體元宇宙傳送門： 利用Scanatic 360 body scanner與方略電子顯示器打造人體元宇宙傳送門，3秒鐘將真人人體掃描後傳送到元宇宙空間，搭配虛擬服裝和不同的元宇宙情境，讓消費者或品牌在零售空間提供web3的新零售體驗', 'https://www.tg3ds.com/', 13751),
  ('2023', 'Goldfinch', 'https://tec.ntu.edu.tw/wp-content/uploads/2023/03/goldfinch_logo-Po-Han-Chung.png', 'LingoTV: 看影片學日文。使用者能夠透過音樂，旅遊，文化，美食介紹等影片學習日文。口說方面，我們與日本人老師合作開發會話課程，使用者能夠學習到最地道的會話。透過我們開發的語音辨識AI，能夠精準矯正使用者的發音並給予分析指導。', NULL, 13751),
  ('2023', 'Linggle', 'https://tec.ntu.edu.tw/wp-content/uploads/2023/03/Linggle-邹丞勛.png', 'Linggle 學習引擎，最新 AI 技術，包括 T5 和 BERT 等，為全球「英力虛弱」（中級 B1/B2）的非母語中學生、大學生，快速提升聽說讀寫能力（到中高級 B2/C1）。', 'https://sites.google.com/nlplab.cc/linggle-officialwebsite/%E9%A6%96%E9%A0%81?authuser=0', 13751),
  ('2023', '翱翔智慧股份有限公司 Owlsome Tech', 'https://tec.ntu.edu.tw/wp-content/uploads/2023/03/Logo-Dark-Blue-1-PeiYing-Wu.png', '「LiFTMiND 昇智達」是第一個以乘客為核心設計的電梯智慧化方案，我們致力讓數據幫助電梯安全提升，打造人性的搭乘工具，建構更有效率的未來都市。以永續為指標，為電梯升級帶來新的助力。', 'https://www.owlsome.tech/', 13751),
  ('2023', 'Tricuss', 'https://tec.ntu.edu.tw/wp-content/uploads/2023/03/Logo_Name-NH-Wang-Came1us.png', 'Tricuss 是個工作資訊的整合平台 (訊息版的 Notion/Zapier)，透過 API 自動化與標籤化訊息 (HyperMessage) ，幫助知識工作者在個人或團隊，能更有方便收集與管理各類工作資訊、更有效地溝通與協作，大幅降低每日高達 60% 的事務型工作。', 'https://www.tricuss.io/zh-TW', 13751),
  ('2023', 'SaltLab', 'https://tec.ntu.edu.tw/wp-content/uploads/2023/03/saltlab-logo去背-SaltLab.png', 'SaltLab致力於研發消費者友善的區塊鏈應用服務，透過各類型的產品讓越來越多的企業加入加密貨幣金融、NFT領域及WEB3商城，協助企業在數位轉型的世代中打好基礎搶得先機。\n推出加密貨幣第三方支付通道「貝殼支付」，嚴格遵守法規且支援廠商新台幣出金，提供廠商多元支付通道並解決加密貨幣持有者的應用需求。', 'https://www.backerpay.com/', 13751),
  ('2023', 'Trainge', 'https://tec.ntu.edu.tw/wp-content/uploads/2023/03/Trainge-logo去背-紀維綱Karl-Chi.png', 'Trainge運動平台提供消費者運動課程、場地租借、專業教練的預約，並提供企業完整健康解決方案，協助完成員工健康數據分析、AI個人客製運動計畫、線上運動學習平台、實體與線上並行的健康講座及課程等服務。', 'https://www.trainge.com/', 13751),
  ('2023', '愛吠的狗娛樂股份有限公司', 'https://tec.ntu.edu.tw/wp-content/uploads/2023/03/愛吠的狗娛樂股份有限公司LOGO去背-CHE.png', 'METASPACE提供企業創新客製化模組服務。使用者可自定義數位分身，在世界中逛遊商鋪、體驗虛擬穿戴、參與互動遊戲，並獲得商家兌換優惠；離開實體商鋪現場後，其數位分身仍可在元宇宙世界逛遊，不定時獲商家好康消息推播。', 'https://www.thebarkingdog-games.com/', 13751),
  ('2023', 'Virsody', 'https://tec.ntu.edu.tw/wp-content/uploads/2023/03/logo_1024-Assign-Arch.png', '以 Web3D 互動引擎為核心，提供無程式碼的遊戲化及虛擬場景編輯器，幫助創作者打造主題館，以沉浸式體驗提高合作品牌的轉換率。UGC 為 Metaverse 的核心驅動力，讓KOL能提供粉絲更多優質的數位內容與遊戲化體驗，翻轉品牌商業匹配的單向搜索，選擇已搭建好契合主題的空間進行更精準的受眾投放。', 'https://virsody.io/', 13751),
  ('2023', 'Tracle 垃可', 'https://tec.ntu.edu.tw/wp-content/uploads/2023/03/解放生活-logo-去背-Ben-Chen.png', 'Tracle 垃可 要解決民眾不方便出門追垃圾車的問題。透過訂閱制到府收垃圾服務，只要上官網訂購，就會有專人定期到府收取垃圾，為你解決困擾、提升生活品質。另外，Tracle 垃可也提供多戶方案，協助房東、社區和包租代管業者進行垃圾空間的規劃、收取', 'https://tracle-tw.com/', 13751),
  ('2023', 'ZEMO', 'https://tec.ntu.edu.tw/wp-content/uploads/2023/03/ZEMO-Logo-白底-呂學儒.png', 'ZEMO將純電動車及軟體平台整合為零碳移動服務，服務企業各類型商務旅行需求、導入模組化的雲端軟體系統，簡化使用者操作、營運行政財會流程。同時，雲端系統亦進行移動服務控管，精準的即時數位化管理，將企業用戶體驗放至於首位，並致力於淨零碳排、員工價值提升，將ESG價值於企業營運中完整落實。', NULL, 13751),
  ('2023', '錨點影音', 'https://tec.ntu.edu.tw/wp-content/uploads/2023/03/5CBE3EA5-3B1E-46EA-9210-2F7EC008CBA4-alis507501.gif', '下對錨點，攻克萬變數位浪潮！錨點影音是整合多元影音製程（實拍、動畫、直播）、提供各產業組織商務環節影音需求的公司（包含廣告、公關、人資、展示..）。我們致力導入新科技促進片場效率化、研發新製程加速後製產效，並持續開發影音企劃模組。尤其後疫情及5G時代來臨，影音早已是新語言，未來將持續將影音產品化、電商化。', 'https://www.facebook.com/AnchorfilmTW?mibextid=LQQJ4d', 13751),
  ('2023', '維爾歐德', 'https://tec.ntu.edu.tw/wp-content/uploads/2023/03/維爾歐德logo去背-werold-studio.png', '藉由多種無線傳輸機制（藍芽、WIFI、4G/5G），將各自不同的手機畫面及操作資訊進行整合後投放至主螢幕，此時手機再與投放出來的畫面進行互動。\n運用此項技術，可以輕易實現在較大的空間、同一情境下，進行多人互動、甚至共同競技/互助的應用內容，提供給各式場域業者全新的大型投影/投放應用方案。', 'http://www.weroldgames.com/', 13751),
  ('2023', '科碼新媒體', 'https://tec.ntu.edu.tw/wp-content/uploads/2023/03/104_corma-Ray-Lee.png', '此系統開發目的在增加遠距業務洽談成交機會。賣方透過網頁編輯器完成3D模型編輯，運用APP，即可將業務人員去背以AR之形式傳送至買方場域，結合產品之3D資訊演示商品', 'http://www.weroldgames.com/', 13751),
  ('2023', '超現實科技', 'https://tec.ntu.edu.tw/wp-content/uploads/2023/03/超現實科技logo-Lee-Ting.png', 'SURREALM是一套為了各式教學情境而打造的多人異地虛擬實境VR教學平台，其多人連線、同步互動的特性，讓身處異地的人們打破距離的限制，實現共聚一堂的教學與討論情境。使用者可設定自己的專屬角色外觀，透過虛擬角色模擬真實的教學與社交互動。平台基本配置為個人空間、授課空間與分組討論空間，亦可能根據不同的商業方案，打造主題式與模組化的實作學習場域。', 'https://www.surreal.com.tw/Home', 13751),
  ('2024', 'DATAYOO', NULL, 'DataYoo 悠由數據致力成為支持綠色經濟與氣候科技專業數據解決方案的 TOP1 企業，透過資料科學打造全科學化的數據產地管理機制，以達資源運用最佳化，除運用科技協助農業建立穩定品質與調節供貨的能力，解決生產過剩、剩食等問題外，透過農、漁電共生以及種植科學化分析服務、碳規劃與計算服務，達到綠色循環的環境生態，而悠由數據更是在 2021 年入選為星展基金會全亞洲 19 間社會企業代表，我們希望能作為客觀的第三方數據公司，一起為永續環境盡一份心力。', NULL, 18891)
INSERT INTO historical_startups (year, name, logo_url, description, external_link, source_post_id) VALUES
  ('2024', 'Calyx', NULL, 'Calyx 的產品主要分為三大部分。首先是我們非消耗性的氣體感測器。可檢測特定空氣中化學物質。全球首款支援有線和無線通信的感測器。第二個是我們的 A.I. Eye，運用我們專有的演算法，預測雞的重量和均勻性。最後是我們的 Calyx Cloud，一個友善的操作平台供客戶在手機、平板以及電腦上線上監測數據。', NULL, 18891),
  ('2024', 'GUGU', NULL, 'GUGU 是一家跨國數位證券商，創立於 2020 年 6 月。以低門檻「零碎股」投資服務，即使「一美元」也能開始進行投資，主打「六分鐘」快速開戶交易體驗，並強化「股票導航」與「社群投資」互動投資體驗，提供國際人士更便利、友善的美股投資環境。', NULL, 18891),
  ('2024', '寶貝友股份有限公司', NULL, 'baby baby cool 是用 100% 有機棉加上時尚設計同時採用符合身形的立體剪裁成人時尚工法製作而成的 100% 有機棉精品童裝。', NULL, 18891),
  ('2024', '臺灣醫用電子股份有限公司', NULL, '我們推出了一款名為 STOPWET 的智慧止汗醫材，其創新性表現於簡單易用、安全便捷。接下來，我們計劃推出 HOMED 平台，由專業皮膚科醫師參與開發。STOPWET 已完成 FDA 的 Q-sub，獲得委員正面回應，預計 2024 年上半年將提交 FDA 510k。', NULL, 18891),
  ('2024', 'LiFUNd', NULL, 'LiFUNd 透過雲端募資平台為企業提供多元社會回饋方案，協助企業以更精簡的人力落實 CSR。我們與大專院校生合作，激發出嶄新且有趣的社會回饋提案，並依據企業的需求，挑選出最適合的團隊進行合作，以高影響力方式履行社會責任，促使企業與學生攜手解決社會問題，實現多贏的共融永續社會。', NULL, 18891),
  ('2024', 'RE:LAB', NULL, '「 2 小時創造互動遊戲，讓品牌溝通變好玩！」不需要程式能力，也不用耗費大量預算與人力，使用 OOOPEN Lab 遊戲模組，就能簡單將遊戲化的互動體驗融入品牌的內容行銷策略中，提高擴散、互動與轉換率！\n從心理測驗到扭蛋抽獎，多款互動模組，操作簡單好上手，視覺編輯超自由，讓你輕鬆展現品牌個性與企劃主題。', NULL, 18891),
  ('2024', '賦語科技股份有限公司', NULL, '賦語科技 ByteLingo 利用生成式 AI 技術結合客戶資料，打造出企業專屬的多語言知識管理平台。獨家演算法有效調用與任務相關的資訊，使 AI 產出精確可用的結果，同時節省使用成本與提升產出品質。我們已為超過 30 間上市櫃公司翻譯財報、年報、永續報告書，客戶遍佈金融、生醫、半導體等各大產業。', NULL, 18891),
  ('2024', '康統 Kenkone', NULL, '康統醫學科技提供數位醫療解決方案，以先進的人工智能技術提升醫療品質，效率與資料價值。產品 EVAS 智能醫師助理，結合了醫療語言模型、生成式 AI、語音識別等科技，協助醫護在零打字完成手術報告，已證明可提昇病歷完整度，減輕醫護人員的病歷負擔。台灣已有數家付費醫院客戶，也進入日本國立癌症研究中心醫院使用。', NULL, 18891),
  ('2024', '幻控科技', NULL, '想像您走在街頭，一個仿佛漂浮在空中的廣告吸引了您的目光。這正是我們革命性的懸浮顯示技術。我作為這項技術的推動者，深信它將改變廣告的未來。這不僅是展示產品，更是為品牌故事增添無與倫比的魅力。從商業展覽到城市廣場，我們的技術為觀眾創造難忘的視覺體驗，一起開創廣告的新紀元。', NULL, 18891),
  ('2024', '群青集科技', NULL, 'Just ART: 演出評價、資訊的社群平台-打造如同 Dcard、巴哈姆特一樣的藝文社群討論平台，透過平台獨特的電子徽章認證機制，讓真正體驗過演出的觀眾能夠發表看法，其他觀眾能夠做參考，提升作品的知名度。', NULL, 18891),
  ('2024', 'LaplaceAI 拉普拉斯智能', NULL, 'LaplaceAI 拉普拉斯智能科技是一家專注於人工智慧（AI）與環境、社會與治理（ESG）永續發展的創新團隊。我們的核心產品 Eco Smart Guide 永續淨零平台，主要協助用戶撰寫永續報告書。此外，平台還提供永續淨零查詢區與永續淨零助手功能，讓用戶能輕鬆獲取永續發展資訊，分析碳盤查數據，並幫助他們做出明智的決策。', NULL, 18891),
  ('2024', 'Tancestor (始祖T)', NULL, '結合AI大腦和遊戲引擎的高仿真渲染，本產品能夠應對大多數的點餐需求，更可靈活擴展至展場指引、與顧客即時互動等多元功能。除了提升服務的效率，更可以打造一個獨特的品牌標籤。我們的虛擬客戶服務人員能夠緊密配合多樣化的需求，包括對菜單內容、行銷文案、應答方式的客製化，為您的客戶打造獨一無二的智能互動體驗。', NULL, 18891),
  ('2024', '禾新生醫股份有限公司', NULL, '考量人口老化的問題，需要為無法運動的老人提供解決方案，預防慢性疾病。\n傳統 EECP 價格高、體積大、噪音大、時間長，為此團隊研發了【螺旋型 HECP 】解決傳統EECP 長期問題。HECP 體積更小（收納時僅單人沙發大小）且性能更為安靜和減少身體震動，使病人的舒適度顯著提升，準備好滿足更廣泛的醫療社群需求。', NULL, 18891),
  ('2024', '數位氣候科技有限公司', NULL, 'GetEmission 可提供客戶「為排放源開設線上問卷」並「設計客製化資料」欄位，提供企業碳管理單位依據不同階段之碳管理目標，進行高度彈性的資料利用。', NULL, 18891),
  ('2024', '像素立方有限公司', NULL, '透過最新型的裸視 3D 技術，在一般的螢幕上呈現出如同 VR 一樣的 3D 立體視覺效果，觀看者無須穿戴任何額外裝置，且大幅改善了傳統裸視 3D 在可視角及畫質上的限制。', NULL, 18891),
  ('2024', 'OfferLand.cc 訊洲科技', NULL, 'OfferLand.cc 是專為留學生和職場新鮮人打造的一站式平台，集結社群、論壇和工具，供青年獲得經驗和資訊以實現職業和教育目標！\n現推出功能有：留學申請落點查詢系統、職涯＆留學論壇\nLand your Offers, OfferLand!', NULL, 18891),
  ('2024', 'Yataiga', NULL, '我們提供雲端 AI 服務幫助量子科技研究團隊與新創公司處理最佳化問題。項目包含量子控制最佳化、量子線路最佳化以及量子糾錯優化等等，提供資源包含機器學習模型、計算資源、實驗設備串接等等，協助客戶無痛、低成本地使用人工智慧來做最佳化。', NULL, 18891),
  ('2024', '臺大腸躁症新藥團隊', NULL, 'DC105 是一個 first-in-class 的新藥，用於治療腸躁症的慢性腹痛。DC105 展現了卓越的鎮痛效果，以及具有副作用低（ 500 倍以上的選擇性對 5-HT7R以外 的受體，transporter 跟ion channel ）且毒性小（低 herg 與 cytochrome P450 的抑制性）的優點。', NULL, 18891),
  ('2024', '穎領 / 林怡成教授團隊', NULL, '因應AI物聯網(AIoT)時代下各式應用產品之連線需求\n聚焦於毫米波晶片與模組產業鏈\n透過 專利授權 與 設計服務\n提供 兼具 高效能 高度微型化 高整合度的天線設計\n突破 毫米波天線與系統晶片整合至 各式應用產品的瓶頸\n加速 毫米波產業 創新技術應用之蓬勃發展', NULL, 18891),
  ('2024', '真金火焰 / 李佳翰教授團隊', NULL, '我們可提供晶片設計所需的輻射測試服務和裝置：本團隊晶片抗輻射核心技術能提供晶片暴露於輻射環境下的安全及穩定度之測試服務和裝置。評估輻射影響晶片效能造成的損失，可應用產業包含低軌道衛星通訊、電動車/自駕車、癌症腫瘤輻射醫療設備所需的抗輻射晶片和具輻射容忍度晶片之測試服務和裝置。', NULL, 18891),
  ('2024', '樂福台灣', NULL, '提供店家一張感應卡，讓客人透過手機靠近感應，開啟Line 官方帳號中的特定店家欄位，待店家手機驗證給點後，便可獲得集點點數，安全方便快速進行集點，以建立顧客忠誠。\n.\n同時，也有邀請碼制度，可以分享資訊給朋友，讓對方有機會去新的店家。成功後，邀請者跟受邀者皆可取得折價券、優惠券，以轉介紹擴大影響力。', NULL, 18891),
  ('2024', '貓談社', NULL, '貓談社的業務主軸為「改善貓咪問題行為、提升人貓生活品質」，並提倡「人道、科學、有效」的原則。服務形式包含一對一的諮詢服務、實體與線上課程、貓行為相關商品的販售。我們擁有業界最紮實的進修經歷與高標準的服務品質，不但是目前全台最大的貓行為諮詢團隊，也曾獲台北市全額創業補助與台北市潛力企業獎。', NULL, 18891),
  ('2024', '思輔科技', NULL, '有鑑於電腦輔助手術、運動科學等領域蓬勃發展，思輔科技旨在發展定位技術以創造更適宜的解決方案並與應用情境接軌。思輔科技成立至今完成了耗材式、光學式、機械式三種不同形式的定位技術之可行性評估，以及專利佈局。經與各領域專家討論後，優先以機械式定位技術為主，展開產品化的開發設計。', NULL, 18891),
  ('2024', '凱歐斯科技有限公司', NULL, '身在少子化的時代，凱歐斯調酒機可以為餐飲業缺工困境提供一個實際可行的解決方式。藉由無人化的調酒機器，提供全新的飲品體驗和降低店家的人力成本，成為商家應對變化、滿足顧客需求的得力助手，同時也成為人們轉變生活型態中，不可或缺的必需品。', NULL, 18891),
  ('2024', 'Rehaco', NULL, '一套陪伴民眾做居家運動和復健的系統，包含了感測器與APP。藉由感測器精準地偵測使用者動作，避免運動傷害以及達到更有效的復健成果。APP的設計則會鼓勵使用者持之以恆的運動和復健，經由使用者授權後，健身教練或醫療人員可以觀看數據，進一步調整健身菜單或運動處方。', NULL, 18891),
  ('2024', '脈動創新', NULL, '這款手持式即時點對點診斷(iPOCT)設備能在15分鐘內評估胸痛患者的急性心肌梗塞風險。適用於救護車緊急醫療，無需專業人員與實驗設備，價格親民。能提早識別心肌梗塞風險，及時治療。這是一種革新的診斷工具，尤其適用於病患抵達醫院前的評估。', NULL, 18891),
  ('2024', 'GYMer 健盟', NULL, '經常旅行、出差的朋友們，是否常常覺得到了外地就沒有地方運動了呢？是否想上的課程成分散在不同的健身房呢？在健身業日益茁壯的市場上，我們健盟團隊正在開發一個健身房平台，將旅遊平台、外送平台、機場貴賓室(ex: 龍騰、longueKey)的概念套用到健身領域，串連不同的健身房，讓想健身的你隨時都能動起來。', NULL, 18891),
  ('2024', 'Dila', NULL, '透過結合音樂發掘和品味的對現今的交友軟體進行創新。\n我們會每日將用戶進行匹配，用戶的個人檔案上會有 1~3張的 Mixtape（歌單）\n用戶喜歡彼此的歌單便可進行更深入的互動。', NULL, 18891),
  ('2024', '初布', NULL, '初布，致力於解決台灣紡織業庫存布氾濫的問題。透過升級再造庫存布，轉化為高品質的團體服飾，並秉持「Local for Local」和「MIT」的製作流程，以減少交通汙染並支持在地正面臨轉型的中小紡織業者。透過這種方式，我們不僅舒緩庫存布問題，更幫助布廠提升ESG，實現多贏局面。', NULL, 18891),
  ('2024', 'Enlighten', NULL, 'Enlighten是一站式獎學金資訊整合平台，串聯需求者（學生）、提供者（企業、基金會），及潛在利害關係人，使獎學金資訊交流與申請流程更加順暢，將對的人帶到對的機會前，追求更多的可能。\n本平台期待達到：1. 充滿資源的、2. 易觸及的、3. 可信賴的、4. 永續的。\n期許能裨益所有獎學金利害關係人，並槓桿優秀人才與資源的合作潛力。', NULL, 18891),
  ('2024', 'CxFi', NULL, 'CxFi是一家金融科技初創公司，提供區塊鏈技術的碳信用眾籌平台，專注於連接開發中國家的減碳項目和全球投資者。我們的平台使碳信用交易更透明、高效，支持全球對抗氣候變化的努力，同時為中小企業提供達成碳中和目標的渠道。', NULL, 18891),
  ('2024', '機能性咖啡', NULL, '將消費者對補給品的需求，和喝咖啡的習慣結合，而且採用精品級咖啡豆，專業的萃取方式，保留最佳口感，讓咖啡愛好者，每天早上享受一杯好咖啡，就能達到美容、健康、保養的需求！', NULL, 18891),
  ('2024', '序場', NULL, '序場， 是劇本的孵化器，是人才的培育所，是探索新秩序、新敘事的實驗場，也是讓劇作家靠岸的藝術之家，以培植臺灣劇作、孵育戲劇人才、推廣臺灣文化為核 心，以孵化、翻譯、教育、構作、交流為五大執行方向，以成為國際劇作交匯的樞紐為願景。', NULL, 18891),
  ('2024', 'Precise Big Data', NULL, 'With Our solution, a cardiologist can get ECG from a cardiac monitoring device. Users can receive a pre-screening and treatment suggestion.', NULL, 18891),
  ('2024', '揪你健康 Jolly Health', NULL, '揪你健康是比民俗療法更好的選擇！\n我們給客戶全員物理治療背景的專業品質、雙邊評價機制與專長劃分，幫助客戶找到適合自己的物理治療師並可選擇到府或實體門市服務。不論是緊繃、僵硬還是酸痛，只要手機一點，就能自由選擇時間與地點，享受專業的評估、運動按摩與訓練服務，客製化打擊緊繃酸痛，預防再發生！', NULL, 18891),
  ('2024', 'Builders Studio', NULL, 'Builders 建立每一個孩子的學習建立鷹架，為「期待看見孩子在學科上，能夠有效學習」的「特殊生家長」提供「身心輔導融入學科教學」給他們的孩子，讓學習不再只為了競爭，而是真正建造孩子的人生。', NULL, 18891),
  ('2024', '黴感走 / 林晉玄老師團隊', NULL, '全新抗香港腳黴菌製劑，提供更有效、更安全的治療方式，降低患者的復發。', NULL, 18891),
  ('2025', '矽晶定序高速科技股份有限公司', NULL, 'NGSAAP 是一種超快速的 NGS 資料分析解決方案。完全本地運算確保資料安全和隱私。該系統可以直接、即時地存取基因型，從而節省最終用戶和雲端伺服器之間的資料傳輸的大量時間。GeneASIC NGSAAP 都可以幫助任何人隨時隨地釋放基因組學的力量。', NULL, 20158),
  ('2025', '見臻科技股份有限公司', NULL, '見臻科技專注於提供整合性視線追蹤解決方案 ,視線追蹤技術分析眼睛來瞭解使用者相關資訊,包含視線位置、眼球位置、瞳孔大小等。在元宇宙的時代中被視為是 VR/AR/智慧眼鏡的重要關鍵技術之一,其重要性在於能夠輔助元宇宙終端裝置—AR/VR 眼鏡—之近眼顯示器讓使用者能有更舒適的感受,也同時能讓「眼神控制」進入元宇宙之中,讓使用者能夠更沈浸、更直覺地和數位世界互動。', NULL, 20158),
  ('2025', '昊偉環境科技股份有限公司', NULL, '極端氣候下，化石燃料的減量使用是人類的解決方案之一。ECO-fuelsaver環保節能系統是為了高耗能、高污染且仍須使用石化燃料的各產業提供合適的ESG節能減排解決方案。適用對象包含重卡、鍋爐、大型工程機具、柴油發電機及內河船舶。本產品除了增加燃燒效率5-15%外，更可降低汙染排放20-40%。', NULL, 20158),
  ('2025', '智慧家禽守護者', NULL, '結合 AI 影像辨識技術與 AIOT 物聯網技術，透過非侵入式拍攝實時檢測家禽健康狀況，實現高效健康監控與疾病早期預警，減少疾病帶來的經濟損失，提升生產效益，並推動畜牧產業邁向數位化轉型與智慧化管理的美好未來。', NULL, 20158),
  ('2025', '拚願科技股份有限公司', NULL, '以一個相控陣列雷達模組為基本單位，根據使用場景和需求，可組合成不同數量大小的相控陣列雷達模組集合為以下產品應用：主動式多功能雷達用於無人載具，地面型便攜式高解析度監控雷達，大型相控陣列雷達模組集成。', NULL, 20158),
  ('2025', '加加減減股份有限公司', NULL, '加加減減發展太陽能自潔增亮奈米塗層，不僅能夠提升玻璃穿透率並吸收紫外光，同時具備超親水自潔效應與光催化分解有機汙染物等特性。將此材料應用於太陽能板表面玻璃塗佈，能提高太陽能板發電效率5%，降低清洗頻率與人力需求50%，同時延長太陽能板壽命，固碳省水，實現加電、加錢。減人、減碳、加加減減的優勢。', NULL, 20158),
  ('2025', '初曦智護（AuroraCare）', NULL, '我們的產品「牙科治療計畫圖」是一款基於網頁的工具，透過簡單的操作，醫師可選擇牙位和治療項目，自動生成可視化的治療計畫圖。圖示以色彩和標註清楚呈現治療，並同步顯示預估費用。此產品具備隨時隨地使用的便利性，不僅提升患者理解力與診療效率，也增強醫師的專業形象與信任感，是現代牙科溝通與診療的理想輔助工具。', NULL, 20158),
  ('2025', '新千歲科技有限公司', NULL, 'Peqaboo 是亞洲首個結合 AI 技術與全面寵物護理的平臺，提供日常服務與健康監測的全方位解決方案。我們的 CRM 系統助診所簡化管理、提升效率，並支持品牌透過數據導向的推薦與廣告精準觸及用戶，推動業務成長。Peqaboo 還以強大的生態圈構建能力，成為產業價值共創的合作夥伴。', NULL, 20158),
  ('2025', '本一科技股份有限公司', NULL, '我們深信AI的力量能為醫療環境帶來革新。\n我們致力於打造一個以人為本的AI醫療生態系，\n以AI將人工智能與醫療人員的結合\n為醫護人員和病患創造共好的醫療體驗。\n期許成為智能醫療領域的領航者，透過AI賦能，實現醫療平權，\n讓每個醫護都能享有品質的就業環境。\n\n以人為本 始終如一。\n本一科技', NULL, 20158),
  ('2025', 'HomeFit', NULL, '我們希望使用科學的手段，讓大家擁有更永續、健康的居住生活環境。', NULL, 20158),
  ('2025', 'Kardomo', NULL, 'Kardomo 是專為 K-pop 粉絲打造的二手周邊交易平台，提供競標與中介服務，確保安全交易。透過 AI 小卡鑑價技術分析市場數據，提升定價透明度。相比臉書社團與一般電商，Kardomo 更專業、安全、高效，致力成為台灣領先的 K-pop 周邊交易平台。', NULL, 20158),
  ('2025', '智續股份有限公司', NULL, '成為人力資源管理界的麥肯錫，透過專業知識、數據分析與AI技術工具，結合客製化的服務，提供即時、專業且可負擔的人資解決方案。幫助中小企業突破資源限制，使其也能擁有專業人資管理能量，降低勞資風險，提升營運效益，讓資方的善意被感受、讓勞方的心聲被聽見，推動企業在和諧中實現永續成長，打造更健康的職場生態。', NULL, 20158),
  ('2025', '欸愛智能有限公司', NULL, 'StoryCraft運用生成式AI技術，打造專為親子互動設計的個性化說故事平台。我們結合兒童教育理論，創作能根據孩子需求生成的專屬故事，並以家長的聲音和容貌作為數位替身，增強親密感與互動效果。未來，我們將推出更多童趣化的數位角色，協助家庭和教育機構更好地運用故事時間，促進孩子的語言、情感與認知發展。', NULL, 20158)
INSERT INTO historical_startups (year, name, logo_url, description, external_link, source_post_id) VALUES
  ('2025', '瑛孚鈉團隊', NULL, '傳統口服藥品對於許多灰指甲患者，不僅治療耗時且易傷肝，副作用造成的不適及療程過長，使服藥順從性低，總體治療不佳無法完全根治易復發。現有外用藥品劑型使用方式，亦讓患者感到不便，服藥順從性亦是低下。\n我們團隊規劃開發全球第一支，因應高齡化，以人為本及環境友善，專為灰指甲治療的噴霧劑，徹底根治告別反覆感染', NULL, 20158),
  ('2025', '永續未來影響力有限公司', NULL, '我們以AI技術為核心，結合軟體即服務（Software as a Service, SaaS）平台與專業顧問，將傳統顧問勞力密集服務轉型為知識密集的數位ESG AI智能顧問解決方案，幫助企業實現ESG永續專業知識快速導入，提升營運效率同時滿足永續發展需求並增強市場競爭力。', NULL, 20158),
  ('2025', 'KAUUI', NULL, 'KAUUI 針對平常以手機作為旅行資訊搜索媒介且經常出遊的使用者，讓使用者平時滑手機不須跳出正在使用的 APP，一個按鍵就能將看到的貼文內容或是網路文章自動擷取並按照地區、類型分類內容。並且，AI 旅行助理提供的回答皆是以使用者的這份資料庫為主，因此回答相較於其他 AI，在旅行出遊方面更加個人化。', NULL, 20158),
  ('2025', '零域科技有限公司', NULL, 'NETELLUS目標成為永續版的Alibaba，是一個致力於降低永續服務成本、加速企業永續轉型的B2B永續服務媒合平台。我們專注於降低永續交易成本過高的現況，並開發更多元、可信賴的永續解決方案供企業選擇，幫助企業一站式找到最合適且價格合理的永續服務。', NULL, 20158),
  ('2025', '台灣永續力 (TWS)', NULL, 'ESG企業永續資源暨碳盤查管理系統，融合永續報告書的模組化設計、AI與即時數據分析，專為大型場域量身打造碳排管控與減碳治理方案。支持臺灣公、私部門精準掌握碳足跡、制定低碳策略，共同邁向2050淨零藍圖，攜手推動全球永續發展。', NULL, 20158),
  ('2025', '醫拓科技', NULL, '為改善現有醫療訓練資源不足以及稀缺性,醫拓科技運用AR技術結合3D列印器官模型引領醫療教學改革與創新,讓醫學生與專業醫護人員沉浸於高互動性、高精確度的手術訓練環境，大幅提升臨床教學的實踐效果。藉由每次的實作建立應用資料庫，除減輕傳統教學負擔外未來，也規劃未來AI進一步智能分析並提供最佳解決方案.', NULL, 20158),
  ('2025', 'Adastra星指科技', NULL, 'Adastra致力於提供為活動公關產業節省溝通、行政等繁瑣人力的AI軟體解方。我們的ai助理可以在line聊天室協助公司管理專案、建立任務並自動化完成搜尋、聯絡廠商等繁瑣業務，讓活動公關公司能專注在改善活動體驗。請上adastra.tw體驗新時代的工作方式！', NULL, 20158),
  ('2025', '富據智能科技股份有限公司', NULL, '安心泳AI防溺水系統運用AI技術實現泳池安全管理智慧化。系統可即時監控泳客行為，快速偵測潛在溺水風險，並發出精確警報協助救援。採用多攝影機影像拼接及去識別化技術，確保無死角監控與隱私保護，同時生成數據報表支持場館營運優化，為水域安全提供全方位解決方案。', NULL, 20158),
  ('2025', 'Nexretail', NULL, 'NexRetail 是一家專注於智慧零售 AI 解決方案的領先企業，致力於協助零售業者透過先進技術實現數位轉型與精準行銷。我們的主要產品包括：\n• Offline CRM 分析平台 – \n• 智慧互動 Kiosk 與虛擬助理系統 –\n• AI 影像辨識與語音技術 –', NULL, 20158),
  ('2025', '市民永續股份有限公司', NULL, '全民碳集提供消費者於日常生活中能蒐集永續行為和消費數據, 精算減碳量並自動銷售給予企業賺取獎金, 更與金融業者合作, 每100元獎金還能透過證券商進行定期定額投資, 增加被動收入; 能用於企業ESG解決方案, 移轉既有的ESG活動預算, 像是淨灘, 鼓勵員工日常永續轉獎金和投資, 幫員工綠色加薪', NULL, 20158),
  ('2025', '金隼行銷股份有限公司', NULL, '掌握下一世代網路話語霸權的 AI MaaS 平台，透過Fine Tuning技術改變現有廣告生態。將各種優良的資料來源訓練為真正可商業化使用的模型', NULL, 20158),
  ('2025', '傑創通股份有限公司', NULL, 'GVTel專注於5G O-RAN無線專網，推出全球首款內嵌式PCIe DU，具高效能、低功耗、成本優勢的競品。產品涵蓋RU、DU、CU與專屬頻譜，適用於智慧城市、企業專網等應用。技術已獲中華電信實驗室驗證，並參與中、德、英、美國、台灣、瑞典、日本、新加坡等實驗場域，加速5G O-RAN創新落地。', NULL, 20158),
  ('2025', '創生醫電股份有限公司', NULL, '「每一顆視網膜，都是一個家庭，一個希望。」 創生醫電致力於再生醫學領域的突破性變革，逆轉視力受損的過程。我們致力於視網膜類器官量產，並透過這樣的力量，驅動整個視力再生領域的變革。透過製造平台技術與國際夥伴整合，創生要引領可負擔組織工程與再生技術，整合多個領域建構世界上第一個垂直整合的人造組織生態鏈。', NULL, 20158),
  ('2025', '連橫生技股份有限公司', NULL, '此為模組化中型廚餘處理設備，將噸級設備縮小至20呎貨櫃，方便安裝。貨櫃包裝設計隔絕外界影響，減少故障噪音，並避免誤觸風險。採用常溫製程，將生廚餘與乾基混拌後投入，經粉碎與攪拌後40分至1小時即可完成轉化。無需加熱乾燥，耗能僅為傳統設備的1/4，成本較低，且每小時可轉化100公斤廚餘為基底肥料。', NULL, 20158),
  ('2025', 'Cool Innovation', NULL, '我們的技術無需化學藥物或特殊包裝即可延長蔬果的鮮度。如生菜、無花果可保鮮30 天，草莓 45 天，麝香葡萄 3 個月等。即使在 90% 以上的高濕度環境中，也能保持紙箱乾燥。產品包括 20/40 英尺貨櫃、小型冰箱以及倉庫方案。在耗電量方面，與傳統冷藏設備及倉庫相比，我們可節省約 50% 的能耗。', NULL, 20158),
  ('2025', '大門科技顧問有限公司', NULL, 'DamenKYT是一款專注於區塊鏈風險管理的Web3反詐騙平台，提供即時錢包風險評估、跨鏈資金追蹤及報案支援。個人用戶可查詢錢包風險、舉報可疑地址、生成報案文件；企業用戶則能透過黑名單API辨識風險交易。我們致力於提升區塊鏈交易透明度與安全性，打造可信賴的Web3環境。', NULL, 20158),
  ('2025', '艾鉑金科技股份有限公司', NULL, 'AiBuuking-你的專屬Ai會計師。我們用各類AI工具，優化記帳/財務/稅務/審計的重複性工作。無論是會計師或是企業用戶，都能藉由我們的讓財稅營運更智慧、更簡單、更專業、更節省人力。我們不為取代會計師，而為了解決各領域專業財會人員人力不足的挑戰而存在。Ai會計已是世界的主流，我們邀請您一起加入。', NULL, 20158),
  ('2025', '台灣微網科技股份有限公司', NULL, '能源轉型除去碳化，分散化亦為重要趨勢，場域端透過自建微電網，具發電、儲電、電力調度能力來達成能源使用目標。台灣微網科技團隊具十年以上實際微電網開發整合經驗，μGridEMS 微電網邊緣能源管理方案，可快速整合太陽能、儲能、UPS、充電樁，並透過自主開發的演算法協助用戶達成電費最佳化、無縫緊急電力提供', NULL, 20158),
  ('2025', '藝信股份有限公司', NULL, '藝信結合AI光學技術與區塊鏈，為藝術品提供採證與存證服務，打造「智慧證書」，驗證真偽並記錄特徵。透過高精度顯微掃描與數位指紋技術，將數據存於區塊鏈，確保不可篡改且永久保存。「智慧證書」應用於畫廊、拍賣行、收藏家與藝術機構，提升藝術品流通透明度，降低偽造風險，保障藝術品真實性及價值，推動產業數位化。', NULL, 20158),
  ('2025', '先進材股份有限公司Advanced Materials Co., Ltd.', NULL, '"新竹金Bamboo 是先進材股份有限公司的一個環保品牌。\n\n我們專注於100%可生物降解負碳包材的創新與應用，\n目標是減少供應鏈中的塑料使用，並降低全球產品碳足跡。\n\n以竹粉為主，利用竹子循環經濟功能，衍生多元面向應用，產出負碳排產品，\n日後期望以竹代塑，實現產品完全分解和減少廢棄物，友善循環目標。"', NULL, 20158),
  ('2025', '奇思資訊股份有限公司', NULL, '數位化時代企業面臨爆炸性成長數據，花費大量人力及時間在數據處理與分析上，且無法有效將數據轉換成企業所需資訊及洞察。TranX 提供企業專屬 AI 員工，對話交辨任務如真人員工，加速企業工作流程+60倍及決策效率+20倍，解鎖企業數據價值和生產力，驅動企業創新成長。', NULL, 20158),
  ('2025', '十論科技股份有限公司', NULL, 'Tricuss是一個 AI 數據資產與 AI Agent No-Code 平台，協助企業將流程、知識和數據整合到大型語言模型（LLMs），使 AI Agents 透過反覆地分析、預測、文件理解及邏輯推理等能力，為企業管理者或工程師提供執行建議或完整的研究分析報告。', NULL, 20158),
  ('2025', '蘿蔔科技有限公司', NULL, 'Mai.Today 是一款專為服務業者設計的AI協作行事曆，幫助業者輕鬆管理行程與訂單。結合AI技術，能自動生成報表並統整數據，讓業者專注於業務拓展與創新，提升效率。無論是排程、協作還是數據分析，Mai.Today 都能提供全方位支持，簡化日常運營。', NULL, 20158),
  ('2025', '啟夢股份有限公司', NULL, '啟夢系統化科系探索營隊：透過求廣、求深、求透系統化步驟，帶領高中生透過全面探索自然組59種、社會組65種科系類別，讓學生可以一次搞定科系方向。', NULL, 20158),
  ('2025', '聚典資訊股份有限公司', NULL, '聚典資訊專注於AI、資料科學技術核心，打造能解決痛點的產品來服務客戶，產品應用包括LLM智能客服和知識管理的Gen AI Agents、以及智能辨識促銷系統、顧客數據平台等 AI/Data embedded module products，以客戶需求為主軸、以技術為基底，來進行產品的開發與導入', NULL, 20158),
  ('2025', 'Upbeat Technology', NULL, '阿比特電子科技致力於全時感測打造的高效能邊緣AI感測應用晶片，提供超低功耗解決方案，專為邊緣AI應用設計。AI SoC MCU專為全時設計，實現極致節能。晶片擁有PUF硬體層級安全機制，確保邊緣AI運算的資料保護。MEMS振動感測器為全球首款10 kHz全矽設計，能強化AI語音偵測。', NULL, 20158)
